"use client";

import React, { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { ChevronDown, Plus, Trash2 } from "lucide-react";
import {
  Input,
  Label,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
  Checkbox,
  Button,
} from "@/shared/ui";
import { useSettingsMap, useUpdateSetting } from "@/shared/hooks/useSettings";
import { parseJsonSetting, serializeSetting } from "@/shared/utils/settings-json";
import {
  CMS_MENU_SETTINGS_KEY,
  DEFAULT_MENU_SETTINGS,
  getCmsMenuSettingsKey,
  type MenuItem,
  type MenuSettings,
  normalizeMenuSettings,
} from "@/features/cms/types/menu-settings";
import { useThemeSettings } from "./ThemeSettingsContext";
import { ANIMATION_PRESETS, type AnimationPreset } from "@/features/gsap/types/animation";
import { useCmsDomainSelection } from "@/features/cms/hooks/useCmsDomainSelection";
import type { ColorScheme } from "@/features/cms/types/theme-settings";
import type { CmsDomain } from "@/features/cms/types";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

// Types imported from menu-settings.ts

const MENU_SECTIONS = [
  "Visibility & Placement",
  "Menu Layout",
  "Menu Items",
  "Menu Images",
  "Typography",
  "Colors",
  "Spacing",
  "Mobile Menu",
  "Dropdown Style",
  "Sticky Behaviour",
  "Active State",
  "Hover Effects",
  "Animations",
];

const COLOR_SCHEME_FALLBACK = [
  { label: "Custom colors", value: "custom" },
];

const FONT_FAMILY_OPTIONS = [
  { label: "Inter", value: "Inter, sans-serif" },
  { label: "Arial", value: "Arial, sans-serif" },
  { label: "Georgia", value: "Georgia, serif" },
  { label: "Times New Roman", value: "'Times New Roman', serif" },
  { label: "Courier New", value: "'Courier New', monospace" },
  { label: "Verdana", value: "Verdana, sans-serif" },
  { label: "Trebuchet MS", value: "'Trebuchet MS', sans-serif" },
  { label: "Palatino", value: "'Palatino Linotype', serif" },
  { label: "System UI", value: "system-ui, sans-serif" },
];

const FONT_WEIGHT_OPTIONS = [
  { label: "100 – Thin", value: "100" },
  { label: "200 – Extra Light", value: "200" },
  { label: "300 – Light", value: "300" },
  { label: "400 – Normal", value: "400" },
  { label: "500 – Medium", value: "500" },
  { label: "600 – Semi Bold", value: "600" },
  { label: "700 – Bold", value: "700" },
  { label: "800 – Extra Bold", value: "800" },
  { label: "900 – Black", value: "900" },
];

// ---------------------------------------------------------------------------
// Reusable helpers
// ---------------------------------------------------------------------------

function ColorField({
  label,
  value,
  onChange,
}: {
  label: string;
  value: string;
  onChange: (v: string) => void;
}): React.ReactNode {
  return (
    <div className="space-y-1">
      <Label className="text-[10px] uppercase tracking-wider text-gray-500">{label}</Label>
      <div className="flex items-center gap-2">
        <label className="relative flex size-7 shrink-0 cursor-pointer items-center justify-center overflow-hidden rounded border border-border/50">
          <input
            type="color"
            value={value}
            onChange={(e: React.ChangeEvent<HTMLInputElement>) => onChange(e.target.value)}
            className="absolute inset-0 size-full cursor-pointer opacity-0"
          />
          <div className="size-full rounded" style={{ backgroundColor: value }} />
        </label>
        <Input
          value={value}
          onChange={(e: React.ChangeEvent<HTMLInputElement>) => onChange(e.target.value)}
          className="h-7 flex-1 bg-gray-800/40 text-xs"
        />
      </div>
    </div>
  );
}

function NumberField({
  label,
  value,
  onChange,
  suffix,
  min,
  max,
}: {
  label: string;
  value: number;
  onChange: (v: number) => void;
  suffix?: string;
  min?: number;
  max?: number;
}): React.ReactNode {
  return (
    <div className="space-y-1">
      <Label className="text-[10px] uppercase tracking-wider text-gray-500">{label}</Label>
      <div className="flex items-center gap-1.5">
        <Input
          type="number"
          value={value}
          min={min}
          max={max}
          onChange={(e: React.ChangeEvent<HTMLInputElement>) => onChange(Number(e.target.value))}
          className="h-7 flex-1 bg-gray-800/40 text-xs"
        />
        {suffix && <span className="text-[10px] text-gray-500">{suffix}</span>}
      </div>
    </div>
  );
}

function RangeField({
  label,
  value,
  onChange,
  min,
  max,
  suffix,
}: {
  label: string;
  value: number;
  onChange: (v: number) => void;
  min: number;
  max: number;
  suffix?: string;
}): React.ReactNode {
  return (
    <div className="space-y-1">
      <div className="flex items-center justify-between">
        <Label className="text-[10px] uppercase tracking-wider text-gray-500">{label}</Label>
        <span className="text-[11px] text-gray-300">
          {value}
          {suffix}
        </span>
      </div>
      <input
        type="range"
        min={min}
        max={max}
        value={value}
        onChange={(e: React.ChangeEvent<HTMLInputElement>) => onChange(Number(e.target.value))}
        className="w-full accent-blue-500"
      />
    </div>
  );
}

function SelectField({
  label,
  value,
  onChange,
  options,
}: {
  label: string;
  value: string;
  onChange: (v: string) => void;
  options: { label: string; value: string }[];
}): React.ReactNode {
  return (
    <div className="space-y-1">
      <Label className="text-[10px] uppercase tracking-wider text-gray-500">{label}</Label>
      <Select value={value} onValueChange={onChange}>
        <SelectTrigger className="h-7 bg-gray-800/40 text-xs">
          <SelectValue />
        </SelectTrigger>
        <SelectContent>
          {options.map((opt: { label: string; value: string }) => (
            <SelectItem key={opt.value} value={opt.value}>
              {opt.label}
            </SelectItem>
          ))}
        </SelectContent>
      </Select>
    </div>
  );
}

function CheckboxField({
  label,
  checked,
  onChange,
}: {
  label: string;
  checked: boolean;
  onChange: (v: boolean) => void;
}): React.ReactNode {
  return (
    <label className="flex items-center gap-2 cursor-pointer">
      <Checkbox
        checked={checked}
        onCheckedChange={(v: boolean | "indeterminate") => onChange(v === true)}
      />
      <span className="text-xs text-gray-300">{label}</span>
    </label>
  );
}

// ---------------------------------------------------------------------------
// Panel
// ---------------------------------------------------------------------------

export function MenuSettingsPanel({ showHeader = true }: { showHeader?: boolean } = {}): React.ReactNode {
  const [openSections, setOpenSections] = useState<Set<string>>(new Set());
  const { theme } = useThemeSettings();
  const { domains, activeDomainId, zoningEnabled } = useCmsDomainSelection();
  const settingsQuery = useSettingsMap();
  const updateSetting = useUpdateSetting();
  const hasHydratedRef = useRef(false);
  const loadedKeyRef = useRef<string | null>(null);
  const scopeTouchedRef = useRef(false);
  const persistTimerRef = useRef<number | null>(null);

  const initialMenuScopeId = useMemo((): string => {
    if (!zoningEnabled) return "default";
    return activeDomainId || "default";
  }, [zoningEnabled, activeDomainId]);

  const [userMenuScopeId, setUserMenuScopeId] = useState<string | null>(null);
  const menuScopeId = useMemo((): string => {
    if (!zoningEnabled) return "default";
    return userMenuScopeId ?? initialMenuScopeId;
  }, [initialMenuScopeId, userMenuScopeId, zoningEnabled]);

  const menuKey = useMemo((): string => {
    if (!zoningEnabled) return CMS_MENU_SETTINGS_KEY;
    if (!menuScopeId || menuScopeId === "default") return CMS_MENU_SETTINGS_KEY;
    return getCmsMenuSettingsKey(menuScopeId);
  }, [menuScopeId, zoningEnabled]);

  const initialSettings = useMemo((): MenuSettings => {
    if (!settingsQuery.isFetched) return DEFAULT_MENU_SETTINGS;
    const stored = parseJsonSetting<Partial<MenuSettings> | null>(
      settingsQuery.data?.get(menuKey),
      null
    );
    if (!stored && menuKey !== CMS_MENU_SETTINGS_KEY) {
      const fallback = parseJsonSetting<Partial<MenuSettings> | null>(
        settingsQuery.data?.get(CMS_MENU_SETTINGS_KEY),
        null
      );
      return normalizeMenuSettings(fallback);
    }
    return normalizeMenuSettings(stored);
  }, [menuKey, settingsQuery.data, settingsQuery.isFetched]);

  const [userSettings, setUserSettings] = useState<MenuSettings | null>(null);
  const settings = userSettings ?? initialSettings;

  const colorSchemeOptions = useMemo((): { label: string; value: string }[] => {
    const options = [...COLOR_SCHEME_FALLBACK];
    const schemes: ColorScheme[] = theme?.colorSchemes ?? [];
    schemes.forEach((scheme: ColorScheme) => {
      if (!scheme?.id) return;
      options.push({ label: scheme.name || scheme.id, value: scheme.id });
    });
    return options;
  }, [theme?.colorSchemes]);

  const availableColorSchemeIds = useMemo((): Set<string> => {
    return new Set((theme?.colorSchemes ?? []).map((scheme: ColorScheme) => scheme.id));
  }, [theme?.colorSchemes]);

  const menuColorSchemeId = useMemo((): string => {
    if (settings.menuColorSchemeId === "custom") return "custom";
    return availableColorSchemeIds.has(settings.menuColorSchemeId) ? settings.menuColorSchemeId : "custom";
  }, [availableColorSchemeIds, settings.menuColorSchemeId]);

  const hasScopedMenu = useMemo(() => {
    if (!zoningEnabled) return false;
    if (menuKey === CMS_MENU_SETTINGS_KEY) return false;
    return settingsQuery.data?.has(menuKey) ?? false;
  }, [menuKey, settingsQuery.data, zoningEnabled]);

  const update = useCallback(<K extends keyof MenuSettings>(key: K, value: MenuSettings[K]): void => {
    setUserSettings((prev: MenuSettings | null) => ({ ...(prev ?? initialSettings), [key]: value }));
  }, [initialSettings]);

  const addMenuItem = useCallback((): void => {
    setUserSettings((prev: MenuSettings | null) => {
      const current = prev ?? initialSettings;
      return {
        ...current,
        items: [
          ...current.items,
          { id: String(Date.now()), label: "New link", url: "/", imageUrl: "" },
        ],
      };
    });
  }, [initialSettings]);

  const updateMenuItem = useCallback((id: string, field: "label" | "url" | "imageUrl", value: string): void => {
    setUserSettings((prev: MenuSettings | null) => {
      const current = prev ?? initialSettings;
      return {
        ...current,
        items: current.items.map((item: MenuItem) =>
          item.id === id ? { ...item, [field]: value } : item
        ),
      };
    });
  }, [initialSettings]);

  const removeMenuItem = useCallback((id: string): void => {
    setUserSettings((prev: MenuSettings | null) => {
      const current = prev ?? initialSettings;
      return {
        ...current,
        items: current.items.filter((item: MenuItem) => item.id !== id),
      };
    });
  }, [initialSettings]);

  useEffect((): void => {
    if (!settingsQuery.isFetched) return;
    hasHydratedRef.current = true;
    loadedKeyRef.current = menuKey;
  }, [menuKey, settingsQuery.isFetched]);

  useEffect((): void => {
    if (!hasHydratedRef.current) return;
    if (loadedKeyRef.current !== menuKey) return;
    if (!userSettings) return;
    const nextSerialized = serializeSetting(userSettings);
    if (persistTimerRef.current) window.clearTimeout(persistTimerRef.current);
    persistTimerRef.current = window.setTimeout(() => {
      updateSetting.mutate({ key: menuKey, value: nextSerialized });
    }, 500);
  }, [menuKey, userSettings, updateSetting]);

  useEffect((): () => void => {
    return (): void => {
      if (persistTimerRef.current) window.clearTimeout(persistTimerRef.current);
    };
  }, []);

  const toggleSection = useCallback((section: string): void => {
    setOpenSections((prev: Set<string>) => {
      const next = new Set(prev);
      if (next.has(section)) {
        next.delete(section);
      } else {
        next.add(section);
      }
      return next;
    });
  }, []);

  const renderSectionBody = useCallback(
    (section: string): React.ReactNode => {
      switch (section) {
        // ---------------------------------------------------------------
        // Visibility & Placement
        // ---------------------------------------------------------------
        case "Visibility & Placement":
          return (
            <div className="space-y-3">
              <CheckboxField
                label="Show menu"
                checked={settings.showMenu}
                onChange={(v: boolean) => update("showMenu", v)}
              />
              <SelectField
                label="Menu position"
                value={settings.menuPlacement}
                onChange={(v: string) => update("menuPlacement", v as any)}
                options={[
                  { label: "Top", value: "top" },
                  { label: "Left", value: "left" },
                  { label: "Right", value: "right" },
                ]}
              />
              <CheckboxField
                label="Collapsible menu"
                checked={settings.collapsible}
                onChange={(v: boolean) => update("collapsible", v)}
              />
              {settings.collapsible && (
                <CheckboxField
                  label="Collapsed by default"
                  checked={settings.collapsedByDefault}
                  onChange={(v: boolean) => update("collapsedByDefault", v)}
                />
              )}
              {(settings.menuPlacement === "left" || settings.menuPlacement === "right") && (
                <>
                  <RangeField
                    label="Side width"
                    value={settings.sideWidth}
                    onChange={(v: number) => update("sideWidth", v)}
                    min={160}
                    max={420}
                    suffix="px"
                  />
                  {settings.collapsible && (
                    <RangeField
                      label="Collapsed width"
                      value={settings.collapsedWidth}
                      onChange={(v: number) => update("collapsedWidth", v)}
                      min={48}
                      max={120}
                      suffix="px"
                    />
                  )}
                </>
              )}
            </div>
          );

        // ---------------------------------------------------------------
        // Menu Layout
        // ---------------------------------------------------------------
        case "Menu Layout":
          return (
            <div className="space-y-3">
              <SelectField
                label="Layout style"
                value={settings.layoutStyle}
                onChange={(v: string) => update("layoutStyle", v)}
                options={[
                  { label: "Horizontal", value: "horizontal" },
                  { label: "Vertical", value: "vertical" },
                  { label: "Centered", value: "centered" },
                ]}
              />
              <SelectField
                label="Alignment"
                value={settings.alignment}
                onChange={(v: string) => update("alignment", v)}
                options={[
                  { label: "Left", value: "left" },
                  { label: "Center", value: "center" },
                  { label: "Right", value: "right" },
                  { label: "Space between", value: "space-between" },
                ]}
              />
              <RangeField
                label="Max width"
                value={settings.maxWidth}
                onChange={(v: number) => update("maxWidth", v)}
                min={800}
                max={1400}
                suffix="px"
              />
              <CheckboxField
                label="Full width"
                checked={settings.fullWidth}
                onChange={(v: boolean) => update("fullWidth", v)}
              />
            </div>
          );

        // ---------------------------------------------------------------
        // Menu Items
        // ---------------------------------------------------------------
        case "Menu Items":
          return (
            <div className="space-y-2">
              {settings.items.map((item: MenuItem) => (
                <div
                  key={item.id}
                  className="flex items-start gap-1.5 rounded border border-border/40 bg-gray-800/30 p-2"
                >
                  <div className="flex-1 space-y-1.5">
                    <Input
                      value={item.label}
                      onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                        updateMenuItem(item.id, "label", e.target.value)
                      }
                      placeholder="Label"
                      className="h-7 bg-gray-800/40 text-xs"
                    />
                    <Input
                      value={item.url}
                      onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                        updateMenuItem(item.id, "url", e.target.value)
                      }
                      placeholder="URL"
                      className="h-7 bg-gray-800/40 text-xs"
                    />
                    {settings.showItemImages && (
                      <Input
                        value={item.imageUrl ?? ""}
                        onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                          updateMenuItem(item.id, "imageUrl", e.target.value)
                        }
                        placeholder="Image URL"
                        className="h-7 bg-gray-800/40 text-xs"
                      />
                    )}
                  </div>
                  <button
                    type="button"
                    onClick={(): void => removeMenuItem(item.id)}
                    className="mt-1 rounded p-1 text-gray-500 hover:text-red-300 hover:bg-red-500/10"
                    title="Remove item"
                  >
                    <Trash2 className="size-3.5" />
                  </button>
                </div>
              ))}
              <Button
                size="sm"
                variant="outline"
                className="w-full text-xs"
                onClick={addMenuItem}
              >
                <Plus className="mr-1.5 size-3.5" />
                Add menu item
              </Button>
            </div>
          );

        // ---------------------------------------------------------------
        // Menu Images
        // ---------------------------------------------------------------
        case "Menu Images":
          return (
            <div className="space-y-3">
              <CheckboxField
                label="Show item images"
                checked={settings.showItemImages}
                onChange={(v: boolean) => update("showItemImages", v)}
              />
              {settings.showItemImages && (
                <RangeField
                  label="Image size"
                  value={settings.itemImageSize}
                  onChange={(v: number) => update("itemImageSize", v)}
                  min={12}
                  max={48}
                  suffix="px"
                />
              )}
            </div>
          );

        // ---------------------------------------------------------------
        // Typography
        // ---------------------------------------------------------------
        case "Typography":
          return (
            <div className="space-y-3">
              <SelectField
                label="Font family"
                value={settings.fontFamily}
                onChange={(v: string) => update("fontFamily", v)}
                options={FONT_FAMILY_OPTIONS}
              />
              <NumberField
                label="Font size"
                value={settings.fontSize}
                onChange={(v: number) => update("fontSize", v)}
                suffix="px"
                min={10}
                max={32}
              />
              <SelectField
                label="Font weight"
                value={settings.fontWeight}
                onChange={(v: string) => update("fontWeight", v)}
                options={FONT_WEIGHT_OPTIONS}
              />
              <NumberField
                label="Letter spacing"
                value={settings.letterSpacing}
                onChange={(v: number) => update("letterSpacing", v)}
                suffix="px"
                min={-2}
                max={10}
              />
              <SelectField
                label="Text transform"
                value={settings.textTransform}
                onChange={(v: string) => update("textTransform", v)}
                options={[
                  { label: "None", value: "none" },
                  { label: "Uppercase", value: "uppercase" },
                  { label: "Capitalize", value: "capitalize" },
                ]}
              />
            </div>
          );

        // ---------------------------------------------------------------
        // Colors
        // ---------------------------------------------------------------
        case "Colors":
          return (
            <div className="space-y-3">
              <SelectField
                label="Color scheme"
                value={menuColorSchemeId}
                onChange={(v: string) => update("menuColorSchemeId", v)}
                options={colorSchemeOptions}
              />
              {menuColorSchemeId === "custom" && (
                <>
                  <ColorField
                    label="Background"
                    value={settings.backgroundColor}
                    onChange={(v: string) => update("backgroundColor", v)}
                  />
                  <ColorField
                    label="Text color"
                    value={settings.textColor}
                    onChange={(v: string) => update("textColor", v)}
                  />
                  <ColorField
                    label="Active item"
                    value={settings.activeItemColor}
                    onChange={(v: string) => update("activeItemColor", v)}
                  />
                  <ColorField
                    label="Border"
                    value={settings.borderColor}
                    onChange={(v: string) => update("borderColor", v)}
                  />
                </>
              )}
            </div>
          );

        // ---------------------------------------------------------------
        // Spacing
        // ---------------------------------------------------------------
        case "Spacing":
          return (
            <div className="space-y-3">
              <Label className="text-[10px] uppercase tracking-wider text-gray-500">Padding</Label>
              <div className="grid grid-cols-2 gap-2">
                <NumberField label="Top" value={settings.paddingTop} onChange={(v: number) => update("paddingTop", v)} suffix="px" min={0} max={100} />
                <NumberField label="Right" value={settings.paddingRight} onChange={(v: number) => update("paddingRight", v)} suffix="px" min={0} max={100} />
                <NumberField label="Bottom" value={settings.paddingBottom} onChange={(v: number) => update("paddingBottom", v)} suffix="px" min={0} max={100} />
                <NumberField label="Left" value={settings.paddingLeft} onChange={(v: number) => update("paddingLeft", v)} suffix="px" min={0} max={100} />
              </div>
              <RangeField
                label="Item gap"
                value={settings.itemGap}
                onChange={(v: number) => update("itemGap", v)}
                min={0}
                max={40}
                suffix="px"
              />
            </div>
          );

        // ---------------------------------------------------------------
        // Mobile Menu
        // ---------------------------------------------------------------
        case "Mobile Menu":
          return (
            <div className="space-y-3">
              <SelectField
                label="Breakpoint"
                value={settings.mobileBreakpoint}
                onChange={(v: string) => update("mobileBreakpoint", v)}
                options={[
                  { label: "768px (Tablet)", value: "768" },
                  { label: "1024px (Small desktop)", value: "1024" },
                  { label: "1280px (Large desktop)", value: "1280" },
                ]}
              />
              <SelectField
                label="Animation"
                value={settings.mobileAnimation}
                onChange={(v: string) => update("mobileAnimation", v)}
                options={[
                  { label: "Slide left", value: "slide-left" },
                  { label: "Slide right", value: "slide-right" },
                  { label: "Slide down", value: "slide-down" },
                  { label: "Fade", value: "fade" },
                ]}
              />
              <ColorField
                label="Hamburger color"
                value={settings.hamburgerColor}
                onChange={(v: string) => update("hamburgerColor", v)}
              />
              <CheckboxField
                label="Show overlay"
                checked={settings.mobileOverlay}
                onChange={(v: boolean) => update("mobileOverlay", v)}
              />
            </div>
          );

        // ---------------------------------------------------------------
        // Dropdown Style
        // ---------------------------------------------------------------
        case "Dropdown Style":
          return (
            <div className="space-y-3">
              <ColorField
                label="Background"
                value={settings.dropdownBg}
                onChange={(v: string) => update("dropdownBg", v)}
              />
              <ColorField
                label="Text color"
                value={settings.dropdownTextColor}
                onChange={(v: string) => update("dropdownTextColor", v)}
              />
              <NumberField
                label="Border radius"
                value={settings.dropdownRadius}
                onChange={(v: number) => update("dropdownRadius", v)}
                suffix="px"
                min={0}
                max={24}
              />
              <SelectField
                label="Shadow"
                value={settings.dropdownShadow}
                onChange={(v: string) => update("dropdownShadow", v)}
                options={[
                  { label: "None", value: "none" },
                  { label: "Small", value: "small" },
                  { label: "Medium", value: "medium" },
                  { label: "Large", value: "large" },
                ]}
              />
              <NumberField
                label="Min width"
                value={settings.dropdownMinWidth}
                onChange={(v: number) => update("dropdownMinWidth", v)}
                suffix="px"
                min={100}
                max={400}
              />
            </div>
          );

        // ---------------------------------------------------------------
        // Sticky Behaviour
        // ---------------------------------------------------------------
        case "Sticky Behaviour":
          const positionMode =
            settings.positionMode ?? (settings.stickyEnabled ? "sticky" : "static");
          const isSticky = positionMode === "sticky";
          const isSide = settings.menuPlacement === "left" || settings.menuPlacement === "right";
          const canHideOnScroll = isSticky || isSide;
          return (
            <div className="space-y-3">
              <SelectField
                label="Menu position"
                value={positionMode}
                onChange={(v: string) => update("positionMode", v as any)}
                options={[
                  { label: "Glued to top", value: "sticky" },
                  { label: "Top of page", value: "static" },
                ]}
              />
              {isSticky && (
                <>
                  <NumberField
                    label="Sticky offset"
                    value={settings.stickyOffset}
                    onChange={(v: number) => update("stickyOffset", v)}
                    suffix="px"
                    min={0}
                    max={200}
                  />
                  <CheckboxField
                    label="Shrink on scroll"
                    checked={settings.shrinkOnScroll}
                    onChange={(v: boolean) => update("shrinkOnScroll", v)}
                  />
                  <ColorField
                    label="Sticky background"
                    value={settings.stickyBackground}
                    onChange={(v: string) => update("stickyBackground", v)}
                  />
                </>
              )}
              {canHideOnScroll && (
                <>
                  <CheckboxField
                    label="Hide on scroll"
                    checked={settings.hideOnScroll}
                    onChange={(v: boolean) => update("hideOnScroll", v)}
                  />
                  {settings.hideOnScroll && (
                    <NumberField
                      label="Show on scroll up after"
                      value={settings.showOnScrollUpAfterPx}
                      onChange={(v: number) => update("showOnScrollUpAfterPx", v)}
                      suffix="px"
                      min={0}
                      max={600}
                    />
                  )}
                </>
              )}
            </div>
          );

        // ---------------------------------------------------------------
        // Active State
        // ---------------------------------------------------------------
        case "Active State":
          return (
            <div className="space-y-3">
              <SelectField
                label="Style"
                value={settings.activeStyle}
                onChange={(v: string) => update("activeStyle", v)}
                options={[
                  { label: "Underline", value: "underline" },
                  { label: "Bold", value: "bold" },
                  { label: "Background", value: "background" },
                  { label: "Border bottom", value: "border-bottom" },
                  { label: "None", value: "none" },
                ]}
              />
              <ColorField
                label="Active color"
                value={settings.activeColor}
                onChange={(v: string) => update("activeColor", v)}
              />
            </div>
          );

        // ---------------------------------------------------------------
        // Hover Effects
        // ---------------------------------------------------------------
        case "Hover Effects":
          return (
            <div className="space-y-3">
              <SelectField
                label="Style"
                value={settings.hoverStyle}
                onChange={(v: string) => update("hoverStyle", v)}
                options={[
                  { label: "Underline", value: "underline" },
                  { label: "Color shift", value: "color-shift" },
                  { label: "Background", value: "background" },
                  { label: "Scale", value: "scale" },
                  { label: "None", value: "none" },
                ]}
              />
              <ColorField
                label="Hover color"
                value={settings.hoverColor}
                onChange={(v: string) => update("hoverColor", v)}
              />
              <RangeField
                label="Transition speed"
                value={settings.transitionSpeed}
                onChange={(v: number) => update("transitionSpeed", v)}
                min={100}
                max={500}
                suffix="ms"
              />
            </div>
          );

        // ---------------------------------------------------------------
        // Animations
        // ---------------------------------------------------------------
        case "Animations":
          return (
            <div className="space-y-3">
              <SelectField
                label="Entry animation"
                value={settings.menuEntryAnimation}
                onChange={(v: string) => update("menuEntryAnimation", v as any)}
                options={ANIMATION_PRESETS}
              />
              <SelectField
                label="Hover animation"
                value={settings.menuHoverAnimation}
                onChange={(v: string) => update("menuHoverAnimation", v as any)}
                options={ANIMATION_PRESETS}
              />
            </div>
          );

        default:
          return <div className="text-xs text-gray-500">Settings coming soon.</div>;
      }
    },
    [settings, update, addMenuItem, updateMenuItem, removeMenuItem, colorSchemeOptions, menuColorSchemeId]
  );

  return (
    <div className="flex min-h-0 flex-1 flex-col">
      {showHeader && (
        <div className="border-b border-border px-4 py-3">
          <div className="text-xs font-semibold uppercase tracking-wide text-gray-400">
            Menu settings
          </div>
          <p className="mt-1 text-[11px] text-gray-500">
            Configure the look and behaviour of your page navigation.
          </p>
        </div>
      )}
      <div className="flex-1 overflow-y-auto p-3">
        <div className="space-y-3">
          <div className="rounded border border-border/40 bg-gray-900/50 p-3">
            <Label className="text-[10px] uppercase tracking-wider text-gray-500">
              Menu scope
            </Label>
            {zoningEnabled ? (
              <div className="mt-2 space-y-2">
                <Select
                  value={menuScopeId}
                  onValueChange={(value: string) => {
                    scopeTouchedRef.current = true;
                    setUserMenuScopeId(value);
                  }}
                >
                  <SelectTrigger className="h-8 text-xs">
                    <SelectValue placeholder="Select zone" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="default">Default (fallback)</SelectItem>
                    {domains.map((domain: CmsDomain) => (
                      <SelectItem key={domain.id} value={domain.id}>
                        {domain.domain}
                        {domain.id === activeDomainId ? " (active)" : ""}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                {menuScopeId !== "default" && !hasScopedMenu ? (
                  <p className="text-[10px] text-gray-500">
                    Using default menu until you customize this zone.
                  </p>
                ) : null}
              </div>
            ) : (
              <p className="mt-2 text-[11px] text-gray-500">
                Simple routing enabled. This menu applies globally.
              </p>
            )}
          </div>
          <div className="space-y-2">
          {MENU_SECTIONS.map((section: string) => {
            const isOpen = openSections.has(section);
            return (
              <div
                key={section}
                className="rounded border border-border/40 bg-gray-900/60"
              >
                <button
                  type="button"
                  onClick={(): void => toggleSection(section)}
                  className="flex w-full items-center justify-between gap-2 px-3 py-2 text-left text-sm text-gray-200 hover:bg-muted/40"
                  aria-expanded={isOpen}
                >
                  <span>{section}</span>
                  <ChevronDown className={`size-4 text-gray-500 transition ${isOpen ? "rotate-180" : ""}`} />
                </button>
                {isOpen && (
                  <div className="px-3 pb-3">{renderSectionBody(section)}</div>
                )}
              </div>
            );
          })}
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import React, { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { Undo2, Redo2, Eye, Maximize2, Minimize2 } from "lucide-react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import {
  Button,
  Checkbox,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
  useToast,
} from "@/shared/ui";
import { CmsDomainSelector } from "@/features/cms";
import type { PageZone, SectionInstance } from "../../types/page-builder";
import type { PageSlugLink, Slug } from "../../types";
import { usePageBuilder } from "../../hooks/usePageBuilderContext";
import { useCmsSlugs, useUpdatePage } from "../../hooks/useCmsQueries";
import { useCmsDomainSelection } from "../../hooks/useCmsDomainSelection";
import { PreviewSection, type MediaReplaceTarget } from "./PreviewBlock";
import { MediaLibraryPanel } from "./MediaLibraryPanel";
import { PageSelectorBar } from "./PageSelectorBar";
import { useThemeSettings } from "./ThemeSettingsContext";
import { buildColorSchemeMap } from "@/features/cms/types/theme-settings";
import { getHoverEffectVars, getMediaInlineStyles, getMediaStyleVars } from "../frontend/theme-styles";

const ZONE_ORDER: PageZone[] = ["header", "template", "footer"];
const EDIT_BUTTON_HIDE_DELAY = 1200;

type UserPreferencesResponse = {
  cmsPreviewEnabled?: boolean | null;
};

const userPreferencesQueryKey = ["user-preferences"] as const;

export function PagePreviewPanel(): React.ReactNode {
  const { state, dispatch } = usePageBuilder();
  const { theme } = useThemeSettings();
  const { activeDomainId, activeDomain } = useCmsDomainSelection();
  const slugsQuery = useCmsSlugs(activeDomainId);
  const updatePage = useUpdatePage();
  const [mediaTarget, setMediaTarget] = useState<MediaReplaceTarget | null>(null);
  const [mediaOpen, setMediaOpen] = useState(false);
  const { toast } = useToast();
  const previousPanelsRef = useRef<{ left: boolean; right: boolean } | null>(null);
  const isViewing = state.leftPanelCollapsed && state.rightPanelCollapsed;
  const [showEditButton, setShowEditButton] = useState<boolean>(isViewing);
  const showEditButtonRef = useRef<boolean>(isViewing);
  const lastPointerMoveRef = useRef(0);
  const [hoveredNodeId, setHoveredNodeId] = useState<string | null>(null);
  const queryClient = useQueryClient();
  const preferencesQuery = useQuery({
    queryKey: userPreferencesQueryKey,
    queryFn: async (): Promise<UserPreferencesResponse> => {
      const res = await fetch("/api/user/preferences");
      if (!res.ok) {
        throw new Error("Failed to load user preferences");
      }
      return (await res.json()) as UserPreferencesResponse;
    },
    staleTime: 1000 * 60 * 5,
  });
  const updatePreferencesMutation = useMutation({
    mutationFn: async (payload: UserPreferencesResponse): Promise<void> => {
      const res = await fetch("/api/user/preferences", {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });
      if (!res.ok) {
        throw new Error("Failed to update user preferences");
      }
    },
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: userPreferencesQueryKey });
    },
    onError: (error: Error) => {
      console.warn("[CMS] Failed to persist preview toggle.", error);
    },
  });
  const domainSlugSet = useMemo(
    (): Set<string> | null =>
      (slugsQuery.data ?? []).length
        ? new Set((slugsQuery.data ?? []).map((slug: Slug) => slug.slug))
        : null,
    [slugsQuery.data]
  );
  const colorSchemes = useMemo(() => (
    theme.colorSchemes.length ? buildColorSchemeMap(theme) : undefined
  ), [theme]);
  const hoverVars = useMemo(
    () => getHoverEffectVars(theme.enableAnimations ? theme.hoverEffect : undefined, theme.enableAnimations ? theme.hoverScale : undefined),
    [theme.enableAnimations, theme.hoverEffect, theme.hoverScale]
  );
  const mediaVars = useMemo(() => getMediaStyleVars(theme), [theme]);
  const mediaStyles = useMemo(() => getMediaInlineStyles(theme), [theme]);
  const outOfZoneSlugs = useMemo(() => {
    if (!domainSlugSet) return [];
    const slugs = state.currentPage?.slugs ?? [];
    const values = slugs.map((link: PageSlugLink) => link.slug.slug);
    return values.filter((value: string) => !domainSlugSet.has(value));
  }, [state.currentPage?.slugs, domainSlugSet]);

  const zoneSlugValues = useMemo((): string[] => {
    const page = state.currentPage;
    const domainSlugs = slugsQuery.data ?? [];
    if (!page || domainSlugs.length === 0) return [];
    if (page.slugIds?.length) {
      const slugById = new Map(domainSlugs.map((slug: Slug) => [slug.id, slug.slug]));
      const ordered = page.slugIds
        .map((id: string) => slugById.get(id))
        .filter((value: string | undefined): value is string => Boolean(value));
      if (ordered.length) return ordered;
    }
    if (!domainSlugSet) return [];
    const values = (page.slugs ?? []).map((link: PageSlugLink) => link.slug.slug);
    return values.filter((value: string) => domainSlugSet.has(value));
  }, [state.currentPage, slugsQuery.data, domainSlugSet]);

  const initialPreviewSlug = useMemo((): string | null => {
    if (!state.currentPage || zoneSlugValues.length === 0) return null;
    return zoneSlugValues[0] || null;
  }, [state.currentPage, zoneSlugValues]);

  const [userPreviewSlug, setUserPreviewSlug] = useState<string | null>(null);
  const selectedPreviewSlug = userPreviewSlug ?? initialPreviewSlug;

  const previewUrl = useMemo((): string | null => {
    if (!selectedPreviewSlug) return null;
    if (typeof window === "undefined") return `/${selectedPreviewSlug}`;

    const protocol = window.location.protocol;
    const currentHost = window.location.host;
    const currentHostname = window.location.hostname;
    const targetHost = activeDomain?.domain ?? currentHostname;
    const resolvedHost = targetHost === currentHostname ? currentHost : targetHost;
    const path = selectedPreviewSlug.startsWith("/") ? selectedPreviewSlug : `/${selectedPreviewSlug}`;
    return `${protocol}//${resolvedHost}${path}`;
  }, [selectedPreviewSlug, activeDomain]);

  const previewHostMatches = useMemo((): boolean => {
    if (typeof window === "undefined") return true;
    if (!previewUrl) return true;
    try {
      const url = new URL(previewUrl);
      return url.host === window.location.host;
    } catch {
      return true;
    }
  }, [previewUrl]);

  const previewFallbackUrl = useMemo((): string | null => {
    if (!state.currentPage) return null;
    if (typeof window === "undefined") return `/preview/${state.currentPage.id}`;
    return `${window.location.origin}/preview/${state.currentPage.id}`;
  }, [state.currentPage]);

  const initialPreviewDraftsEnabled = useMemo((): boolean => {
    return Boolean(preferencesQuery.data?.cmsPreviewEnabled);
  }, [preferencesQuery.data?.cmsPreviewEnabled]);

  const [userPreviewDraftsEnabled, setUserPreviewDraftsEnabled] = useState<boolean | null>(null);
  const previewDraftsEnabled = userPreviewDraftsEnabled ?? initialPreviewDraftsEnabled;

  const previewTargetLabel = useMemo((): string => {
    if (!selectedPreviewSlug) return "";
    const path = selectedPreviewSlug.startsWith("/") ? selectedPreviewSlug : `/${selectedPreviewSlug}`;
    const host = activeDomain?.domain ?? "current";
    return `${host}${path}`;
  }, [selectedPreviewSlug, activeDomain]);

  const handleSelectNode = useCallback(
    (nodeId: string): void => {
      dispatch({ type: "SELECT_NODE", nodeId });
    },
    [dispatch]
  );

  const handleHoverNode = useCallback(
    (nodeId: string | null): void => {
      if (!state.inspectorEnabled) return;
      setHoveredNodeId((prev: string | null) => (prev === nodeId ? prev : nodeId));
    },
    [state.inspectorEnabled]
  );

  const effectiveHoveredNodeId = state.inspectorEnabled ? hoveredNodeId : null;

  const handleSave = useCallback(async (): Promise<void> => {
    if (!state.currentPage) return;

    const page = state.currentPage;
    const updatedPage = {
      ...page,
      showMenu: page.showMenu ?? true,
      status: page.status,
      publishedAt: page.publishedAt,
      seoTitle: page.seoTitle,
      seoDescription: page.seoDescription,
      seoOgImage: page.seoOgImage,
      seoCanonical: page.seoCanonical,
      robotsMeta: page.robotsMeta,
      components: state.sections.map((s: SectionInstance) => ({
        type: s.type,
        content: { zone: s.zone, settings: s.settings, blocks: s.blocks },
      })),
      slugIds: page.slugIds,
    };

    await updatePage.mutateAsync({
      id: page.id,
      input: updatedPage,
    });
  }, [state.currentPage, state.sections, updatePage]);

  const handlePreview = useCallback(async (): Promise<void> => {
    if (!state.currentPage) return;
    const initialTarget = previewFallbackUrl ?? "about:blank";
    const previewWindow = window.open(initialTarget, "_blank");
    if (!previewWindow) {
      toast("Popup blocked. Allow popups to open the preview.", { variant: "error" });
      return;
    }
    try {
      previewWindow.opener = null;
    } catch {
      // ignore cross-origin or browser restrictions
    }
    try {
      await handleSave();
      if (slugsQuery.isLoading) {
        toast("Loading zone slugs. Try again in a moment.", { variant: "error" });
        return;
      }
      const isPublished = state.currentPage.status === "published";
      const shouldUseSlug = Boolean(previewUrl) && (isPublished || previewDraftsEnabled) && previewHostMatches;
      const targetUrl = shouldUseSlug ? previewUrl : previewFallbackUrl;
      if (!targetUrl) {
        toast("This page has no slug in the current zone.", { variant: "error" });
        return;
      }
      if (!previewHostMatches && previewUrl) {
        toast("Previewing on current host (domain mismatch).", { variant: "info" });
      }
      previewWindow.location.href = targetUrl;
    } catch (error) {
      console.error("Failed to save before preview:", error);
      toast("Save before preview failed. Try again.", { variant: "error" });
    }
  }, [handleSave, state.currentPage, toast, previewUrl, previewFallbackUrl, slugsQuery.isLoading, previewDraftsEnabled, previewHostMatches]);


  const handleOpenMedia = useCallback((target: MediaReplaceTarget): void => {
    setMediaTarget(target);
    setMediaOpen(true);
  }, []);

  const handleMediaOpenChange = useCallback((open: boolean): void => {
    setMediaOpen(open);
    if (!open) {
      setMediaTarget(null);
    }
  }, []);

  const handleMediaSelect = useCallback(
    (filepaths: string[]): void => {
      if (!mediaTarget) return;
      const image = filepaths[0];
      if (!image) return;

      if (mediaTarget.kind === "section") {
        dispatch({
          type: "UPDATE_SECTION_SETTINGS",
          sectionId: mediaTarget.sectionId,
          settings: { [mediaTarget.key]: image },
        });
      } else {
        if (!mediaTarget.blockId) return;
        if (mediaTarget.columnId && mediaTarget.parentBlockId) {
          dispatch({
            type: "UPDATE_NESTED_BLOCK_SETTINGS",
            sectionId: mediaTarget.sectionId,
            columnId: mediaTarget.columnId,
            parentBlockId: mediaTarget.parentBlockId,
            blockId: mediaTarget.blockId,
            settings: { [mediaTarget.key]: image },
          });
        } else if (mediaTarget.columnId) {
          dispatch({
            type: "UPDATE_BLOCK_IN_COLUMN",
            sectionId: mediaTarget.sectionId,
            columnId: mediaTarget.columnId,
            blockId: mediaTarget.blockId,
            settings: { [mediaTarget.key]: image },
          });
        } else {
          dispatch({
            type: "UPDATE_BLOCK_SETTINGS",
            sectionId: mediaTarget.sectionId,
            blockId: mediaTarget.blockId,
            settings: { [mediaTarget.key]: image },
          });
        }
      }

      setMediaOpen(false);
      setMediaTarget(null);
    },
    [dispatch, mediaTarget]
  );

  const showEdit = useCallback((): void => {
    if (showEditButtonRef.current) return;
    showEditButtonRef.current = true;
    setShowEditButton(true);
  }, []);

  const hideEdit = useCallback((): void => {
    if (!showEditButtonRef.current) return;
    showEditButtonRef.current = false;
    setShowEditButton(false);
  }, []);

  const setPanelsCollapsed = useCallback(
    (leftCollapsed: boolean, rightCollapsed: boolean): void => {
      if (state.leftPanelCollapsed !== leftCollapsed) {
        dispatch({ type: "TOGGLE_LEFT_PANEL" });
      }
      if (state.rightPanelCollapsed !== rightCollapsed) {
        dispatch({ type: "TOGGLE_RIGHT_PANEL" });
      }
    },
    [dispatch, state.leftPanelCollapsed, state.rightPanelCollapsed]
  );

  const handleToggleViewing = useCallback((): void => {
    if (!isViewing) {
      previousPanelsRef.current = {
        left: state.leftPanelCollapsed,
        right: state.rightPanelCollapsed,
      };
      setPanelsCollapsed(true, true);
      lastPointerMoveRef.current = Date.now();
      showEdit();
      return;
    }
    const previous = previousPanelsRef.current;
    if (previous) {
      setPanelsCollapsed(previous.left, previous.right);
    } else {
      setPanelsCollapsed(false, false);
    }
    previousPanelsRef.current = null;
    hideEdit();
  }, [hideEdit, isViewing, setPanelsCollapsed, showEdit, state.leftPanelCollapsed, state.rightPanelCollapsed]);

  useEffect((): (() => void) => {
    if (!isViewing) return (): void => {};

    lastPointerMoveRef.current = Date.now();
    const handlePointerMove = (): void => {
      lastPointerMoveRef.current = Date.now();
      showEdit();
    };
    window.addEventListener("pointermove", handlePointerMove);
    const idleCheck = window.setInterval(() => {
      if (Date.now() - lastPointerMoveRef.current > EDIT_BUTTON_HIDE_DELAY) {
        hideEdit();
      }
    }, 200);

    return (): void => {
      window.removeEventListener("pointermove", handlePointerMove);
      window.clearInterval(idleCheck);
    };
  }, [hideEdit, isViewing, showEdit]);

  // Group sections by zone
  const sectionsByZone = ZONE_ORDER.reduce<Record<PageZone, SectionInstance[]>>(
    (acc: Record<PageZone, SectionInstance[]>, zone: PageZone) => {
      acc[zone] = state.sections.filter((s: SectionInstance) => s.zone === zone);
      return acc;
    },
    { header: [], template: [], footer: [] }
  );

  const hasSections = state.sections.length > 0;
  const previewWidthClass =
    state.previewMode === "mobile"
      ? "max-w-[420px]"
      : "w-full";
  const previewFrameClass =
    state.previewMode === "mobile"
      ? "rounded-2xl border border-white/10 bg-gray-950/40 shadow-[0_0_0_1px_rgba(59,130,246,0.15)]"
      : "";

  const basePadding = typeof theme.pagePadding === "number" ? theme.pagePadding : 0;
  const baseMargin = typeof theme.pageMargin === "number" ? theme.pageMargin : 0;
  const paddingTop = typeof theme.pagePaddingTop === "number" ? theme.pagePaddingTop : basePadding;
  const paddingRight = typeof theme.pagePaddingRight === "number" ? theme.pagePaddingRight : basePadding;
  const paddingBottom = typeof theme.pagePaddingBottom === "number" ? theme.pagePaddingBottom : basePadding;
  const paddingLeft = typeof theme.pagePaddingLeft === "number" ? theme.pagePaddingLeft : basePadding;
  const marginTop = typeof theme.pageMarginTop === "number" ? theme.pageMarginTop : baseMargin;
  const marginRight = typeof theme.pageMarginRight === "number" ? theme.pageMarginRight : baseMargin;
  const marginBottom = typeof theme.pageMarginBottom === "number" ? theme.pageMarginBottom : baseMargin;
  const marginLeft = typeof theme.pageMarginLeft === "number" ? theme.pageMarginLeft : baseMargin;
  const pageRadius = typeof theme.borderRadius === "number" ? theme.borderRadius : 0;
  const pageStyle: React.CSSProperties = {
    backgroundColor: theme.backgroundColor,
    borderRadius: pageRadius > 0 ? pageRadius : undefined,
    overflow: pageRadius > 0 ? "hidden" : undefined,
  };
  const contentStyle: React.CSSProperties = {
    paddingTop,
    paddingRight,
    paddingBottom,
    paddingLeft,
    marginTop,
    marginRight,
    marginBottom,
    marginLeft,
  };

  return (
    <div className="relative flex flex-1 flex-col bg-gray-950">
      {/* Toolbar */}
      <div
        className={`overflow-hidden transition-all duration-300 ease-in-out ${
          isViewing
            ? "max-h-0 opacity-0 -translate-y-4 pointer-events-none border-transparent"
            : "max-h-20 opacity-100 translate-y-0 border-b border-border"
        }`}
      >
        <div className="flex items-center justify-end gap-2 px-6 py-3">
          {!isViewing && (
            <>
              <CmsDomainSelector label="" triggerClassName="h-8 w-[200px]" />
              <PageSelectorBar variant="toolbar" />
              {slugsQuery.isLoading ? (
                <div className="rounded-full border border-slate-500/40 bg-slate-500/10 px-3 py-1 text-[10px] text-slate-300">
                  Loading zone slugs…
                </div>
              ) : zoneSlugValues.length > 1 ? (
                <Select
                  value={selectedPreviewSlug ?? ""}
                  onValueChange={(value: string): void =>
                    setUserPreviewSlug((prev: string | null) => (prev === value ? prev : value))
                  }
                >
                  <SelectTrigger className="h-8 w-[200px] text-xs">
                    <SelectValue placeholder="Preview slug" />
                  </SelectTrigger>
                  <SelectContent>
                    {zoneSlugValues.map((slug: string) => (
                      <SelectItem key={slug} value={slug}>
                        /{slug}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              ) : zoneSlugValues.length === 1 ? (
                <div
                  className="rounded-full border border-blue-500/30 bg-blue-500/10 px-3 py-1 text-[10px] text-blue-200"
                  title={previewTargetLabel}
                >
                  Preview: /{zoneSlugValues[0]}
                </div>
              ) : (
                <div className="rounded-full border border-red-500/40 bg-red-500/10 px-3 py-1 text-[10px] text-red-200">
                  No slug in zone
                </div>
              )}
              {outOfZoneSlugs.length > 0 && (
                <div className="rounded-full border border-amber-500/40 bg-amber-500/10 px-3 py-1 text-[10px] text-amber-200">
                  Cross-zone: {outOfZoneSlugs.map((slug: string) => `/${slug}`).join(", ")}
                </div>
              )}
              <label className="flex items-center gap-2 rounded-full border border-slate-500/40 bg-slate-500/10 px-3 py-1 text-[10px] text-slate-200">
                <Checkbox
                  checked={previewDraftsEnabled}
                  onCheckedChange={(value: boolean | "indeterminate"): void => {
                    const next = value === true;
                    setUserPreviewDraftsEnabled(next);
                    updatePreferencesMutation.mutate({ cmsPreviewEnabled: next });
                  }}
                />
                Draft preview
              </label>
              <Button
                onClick={(): void => { void handlePreview(); }}
                size="sm"
                variant="outline"
                className="text-gray-300 hover:text-white"
                disabled={!state.currentPage || updatePage.isPending}
              >
                <Eye className="mr-2 size-4" />
                {updatePage.isPending ? "Saving..." : "Preview"}
              </Button>
              <Button
                onClick={(): void => dispatch({ type: "UNDO" })}
                size="icon"
                variant="ghost"
                className="text-gray-400 hover:text-white"
                disabled={state.history.past.length === 0}
              >
                <Undo2 className="size-4" />
              </Button>
              <Button
                onClick={(): void => dispatch({ type: "REDO" })}
                size="icon"
                variant="ghost"
                className="text-gray-400 hover:text-white"
                disabled={state.history.future.length === 0}
              >
                <Redo2 className="size-4" />
              </Button>
              <Button
                onClick={(): void => { void handleSave(); }}
                size="sm"
                className="bg-blue-600 hover:bg-blue-700"
                disabled={!state.currentPage || updatePage.isPending}
              >
                {updatePage.isPending ? "Saving..." : "Save"}
              </Button>
            </>
          )}
          {!isViewing && (
            <Button
              onClick={handleToggleViewing}
              size="sm"
              variant="outline"
              className="text-gray-300 hover:text-white"
              disabled={!state.currentPage}
            >
              <Maximize2 className="mr-2 size-4" />
              Show
            </Button>
          )}
        </div>
      </div>

      {isViewing && (
        <div className="pointer-events-none absolute right-6 top-4 z-20 flex justify-end">
          <div
            className={`pointer-events-auto transition-all duration-300 ease-in-out ${
              showEditButton ? "opacity-100 translate-y-0" : "opacity-0 -translate-y-2"
            }`}
          >
            <Button
              onClick={handleToggleViewing}
              size="sm"
              variant="outline"
              className="text-gray-300 hover:text-white opacity-60 hover:opacity-100"
              disabled={!state.currentPage}
            >
              <Minimize2 className="mr-2 size-4" />
              Edit
            </Button>
          </div>
        </div>
      )}

      {/* Preview area */}
      <div className="flex-1 overflow-y-auto" data-cms-canvas-viewport="true">
        {!state.currentPage ? (
          <div className="flex h-full items-center justify-center p-6 text-gray-500">
            Select a page from the left panel to preview it
          </div>
        ) : !hasSections ? (
          <div className="flex h-full items-center justify-center p-6 text-gray-500">
            No sections yet. Use the left panel to add sections.
          </div>
        ) : (
          <>
            <div className="p-0">
              <div
                data-cms-canvas="true"
                className={`cms-hover-scope mx-auto ${previewWidthClass} ${previewFrameClass} ${previewFrameClass ? "p-3" : ""} ${
                  state.inspectorEnabled ? "cursor-crosshair" : ""
                }`}
                style={{
                  ...hoverVars,
                  ...mediaVars,
                  ...pageStyle,
                }}
              >
                <div style={contentStyle}>
                  {ZONE_ORDER.map((zone: PageZone) => {
                    const zoneSections = sectionsByZone[zone];
                    if (zoneSections.length === 0) return null;

                    return (
                      <div key={zone}>
                        {/* Zone sections */}
                        <div>
                          {zoneSections.map((section: SectionInstance) => (
                            <PreviewSection
                              key={section.id}
                              section={section}
                              layout={{ fullWidth: theme.fullWidth }}
                              selectedNodeId={state.selectedNodeId}
                              isInspecting={state.inspectorEnabled}
                              inspectorSettings={state.inspectorSettings}
                              hoveredNodeId={effectiveHoveredNodeId}
                              colorSchemes={colorSchemes}
                              mediaStyles={mediaStyles}
                              onSelect={handleSelectNode}
                              onHoverNode={handleHoverNode}
                              onOpenMedia={handleOpenMedia}
                              onRemoveSection={(sectionId: string) => dispatch({ type: "REMOVE_SECTION", sectionId })}
                              onToggleSectionVisibility={(sectionId: string, isHidden: boolean) =>
                                dispatch({ type: "UPDATE_SECTION_SETTINGS", sectionId, settings: { isHidden } })
                              }
                              onRemoveRow={(sectionId: string, rowId: string) =>
                                dispatch({ type: "REMOVE_GRID_ROW", sectionId, rowId })
                              }
                            />
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          </>
        )}
      </div>
      <MediaLibraryPanel
        open={mediaOpen}
        onOpenChange={handleMediaOpenChange}
        onSelect={handleMediaSelect}
        selectionMode="single"
      />
    </div>
  );
}

"use client";
import React, { useMemo } from "react";
import { Button, Input, Tabs, TabsContent, TabsList, TabsTrigger, useToast, AppModal, ModalShell, SectionHeader, SectionPanel } from "@/shared/ui";
import { Suspense, useCallback, useEffect, useState } from "react";
import Link from "next/link";
import { useSearchParams } from "next/navigation";
import { Loader2, RefreshCcw, Trash2, XCircle, Eye, ImageIcon, MoreVertical, Star, ChevronRight, Pin } from "lucide-react";
import type { ProductAiJob } from "@/shared/types/jobs";
import type { ProductAiJobsPanelProps } from "@/features/jobs/types/jobs-ui";
import ProductListingJobsPanel from "@/features/jobs/components/ProductListingJobsPanel";

// Types for PreviewBlock (assumed based on context)
type PageZone = "header" | "content" | "footer";
type AppEmbedId = "chatbot" | "search" | "products";
type AppEmbedOption = { id: AppEmbedId; label: string };
const APP_EMBED_OPTIONS: AppEmbedOption[] = [
  { id: "chatbot", label: "Chatbot" },
  { id: "search", label: "Product Search" },
  { id: "products", label: "Product Grid" },
];

interface BlockInstance {
  id: string;
  type: string;
  settings: Record<string, any>;
}

interface InspectorSettings {
  showEditorChrome?: boolean;
}

interface MediaReplaceTarget {
  kind: "block";
  sectionId: string;
  blockId: string;
  columnId?: string;
  parentBlockId?: string;
  key: string;
}

interface PreviewBlockProps {
  block: BlockInstance;
  isSelected?: boolean;
  onSelect?: (id: string) => void;
  sectionId: string;
  columnId?: string;
  parentBlockId?: string;
  stretch?: boolean;
  contained?: boolean;
  showEditorChrome?: boolean;
  mediaStyles?: React.CSSProperties;
  onOpenMedia?: (target: MediaReplaceTarget) => void;
}

// Mock functions assumed based on context
const buildContainerClass = (base: string, extra: string): string => `${base} ${extra}`;
const buildImageElementPresentation = (settings: any, media: any): any => ({
  wrapperStyles: {},
  imageStyles: {},
  useFill: false,
  hasOverlay: false,
  overlayStyles: {},
});

export function PreviewBlock({
  block,
  isSelected,
  onSelect,
  sectionId,
  columnId,
  parentBlockId,
  stretch,
  contained,
  showEditorChrome,
  mediaStyles,
  onOpenMedia,
}: PreviewBlockProps): React.JSX.Element | null {
  const handleSelect = (e: React.MouseEvent | React.KeyboardEvent): void => {
    e.stopPropagation();
    onSelect?.(block.id);
  };

  const handleKeyDown = (e: React.KeyboardEvent): void => {
    if (e.key === "Enter" || e.key === " ") {
      handleSelect(e);
    }
  };

  const wrapBlock = (content: React.ReactNode): React.JSX.Element => (
    <div className="preview-block-wrapper h-full">{content}</div>
  );

  const selectedBorderClass = "border-blue-500 ring-2 ring-blue-500/20";
  const selectedSoftBg = "bg-blue-500/5";

  // Text block
  if (block.type === "Text") {
    const text = (block.settings["text"] as string) || "Enter text here...";
    const tag = (block.settings["tag"] as string) || "p";
    const alignment = (block.settings["alignment"] as string) || "left";
    const fontSize = (block.settings["fontSize"] as number) || 16;
    const fontWeight = (block.settings["fontWeight"] as string) || "normal";
    const color = (block.settings["color"] as string) || "inherit";

    const Tag = tag as any;

    return wrapBlock(
      <div
        role="button"
        tabIndex={0}
        onClick={handleSelect}
        onKeyDown={handleKeyDown}
        className={buildContainerClass(
          `w-full transition ${contained ? "max-w-full" : ""}`,
          `rounded border p-3 ${
            isSelected
              ? `${selectedBorderClass} ${selectedSoftBg}`
              : "border-border/30 bg-gray-800/20 hover:border-border/50"
          }`
        )}
      >
        <Tag
          style={{
            textAlign: alignment,
            fontSize: `${fontSize}px`,
            fontWeight,
            color,
          }}
          className="m-0"
        >
          {text}
        </Tag>
      </div>
    );
  }

  // Image element block
  if (block.type === "ImageElement") {
    const src = (block.settings["src"] as string) || "";
    const alt = (block.settings["alt"] as string) || "Image";
    const presentation = buildImageElementPresentation(block.settings, mediaStyles);
    const hasSrc = Boolean(src);
    const baseClasses = `w-full text-left transition ${contained ? "max-w-full" : ""}`;
    const wrapperStyles = stretch
      ? { ...presentation.wrapperStyles, height: "100%" }
      : presentation.wrapperStyles;
    const useFill = stretch ? true : presentation.useFill;

    return (
      wrapBlock(
        <div
          role="button"
          tabIndex={0}
          onClick={handleSelect}
          onKeyDown={handleKeyDown}
          className={buildContainerClass(
            baseClasses,
            `rounded border p-1 ${
              isSelected
                ? `${selectedBorderClass} ${selectedSoftBg}`
                : "border-border/30 bg-gray-800/20 hover:border-border/50"
            }`
          )}
        >
          {hasSrc ? (
            <div className="relative" style={wrapperStyles}>
              {/* eslint-disable-next-line @next/next/no-img-element */}
              <img
                src={src}
                alt={alt}
                style={{
                  ...presentation.imageStyles,
                  display: "block",
                  height: useFill ? "100%" : "auto",
                }}
              />
              {presentation.hasOverlay && (
                <div className="pointer-events-none absolute inset-0" style={presentation.overlayStyles} />
              )}
            </div>
          ) : (
            <div
              className="cms-media flex items-center justify-center bg-gray-800/50 py-8 text-gray-500 text-sm"
              style={presentation.wrapperStyles}
            >
              No image selected
            </div>
          )}
        </div>
      )
    );
  }

  // Button block
  if (block.type === "Button") {
    const label = (block.settings["buttonLabel"] as string) || "Button";
    const link = (block.settings["buttonLink"] as string) || "#";
    const style = (block.settings["buttonStyle"] as string) || "solid";

    const baseButtonClasses = "cms-hover-button inline-block rounded-md px-6 py-2.5 text-sm font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2";
    const customStyles: React.CSSProperties = {};
    const fontFamily = block.settings["fontFamily"] as string | undefined;
    const fontSize = block.settings["fontSize"] as number | undefined;
    const fontWeight = block.settings["fontWeight"] as string | undefined;
    const textColor = block.settings["textColor"] as string | undefined;
    const bgColor = block.settings["bgColor"] as string | undefined;
    const borderColor = block.settings["borderColor"] as string | undefined;
    const borderRadius = block.settings["borderRadius"] as number | undefined;
    const borderWidth = block.settings["borderWidth"] as number | undefined;

    if (fontFamily) customStyles.fontFamily = fontFamily;
    if (fontSize && fontSize > 0) customStyles.fontSize = `${fontSize}px`;
    if (fontWeight) customStyles.fontWeight = fontWeight;
    if (textColor) customStyles.color = textColor;
    if (bgColor) customStyles.backgroundColor = bgColor;
    if (borderColor) customStyles.borderColor = borderColor;
    if (borderRadius && borderRadius > 0) customStyles.borderRadius = `${borderRadius}px`;
    if (borderWidth && borderWidth > 0) customStyles.borderWidth = `${borderWidth}px`;

    const buttonContent =
      style === "outline" ? (
        <a
          href={link}
          className={`${baseButtonClasses} border-2 border-white text-white hover:bg-white hover:text-gray-900 focus:ring-white`}
          style={customStyles}
        >
          {label}
        </a>
      ) : (
        <a
          href={link}
          className={`${baseButtonClasses} bg-white text-gray-900 hover:bg-gray-200 focus:ring-white`}
          style={customStyles}
        >
          {label}
        </a>
      );

    return (
      wrapBlock(
        <div
          role="button"
          tabIndex={0}
          onClick={handleSelect}
          onKeyDown={handleKeyDown}
          className={buildContainerClass(
            `inline-block ${contained ? "max-w-full" : ""}`,
            `cms-hover-button rounded border p-3 ${
              isSelected
                ? `${selectedBorderClass} ${selectedSoftBg}`
                : "border-border/30 bg-gray-800/20 hover:border-border/50"
            }`
          )}
        >
          {buttonContent}
        </div>
      )
    );
  }

  // RichText block
  if (block.type === "RichText") {
    const colorScheme = block.settings["colorScheme"] as string | undefined;

    return (
      wrapBlock(
        <div
          role="button"
          tabIndex={0}
          onClick={handleSelect}
          onKeyDown={handleKeyDown}
          className={buildContainerClass(
            `w-full text-left transition overflow-hidden ${contained ? "max-w-full" : ""}`,
            `rounded border p-3 ${
              isSelected
                ? `${selectedBorderClass} ${selectedSoftBg}`
                : "border-border/30 bg-gray-800/20 hover:border-border/50"
            }`
          )}
        >
          <div className="rounded-lg p-4 text-gray-400" data-color-scheme={colorScheme}>
            <p className="text-sm italic">Rich text content area</p>
          </div>
        </div>
      )
    );
  }

  // Image block
  if (block.type === "Image") {
    const src = (block.settings["src"] as string) || "";
    const alt = (block.settings["alt"] as string) || "Image";
    const width = (block.settings["width"] as number) || 100;
    const borderRadius = (block.settings["borderRadius"] as number) || 0;
    const baseClasses = `w-full text-left transition ${contained ? "max-w-full" : ""}`;
    const resolvedStyles: React.CSSProperties = {
      ...(mediaStyles ?? {}),
      ...(borderRadius > 0 ? { borderRadius: `${borderRadius}px` } : {}),
    };
    const wrapperStyles: React.CSSProperties = stretch
      ? { width: `${width}%`, height: "100%", ...resolvedStyles }
      : { width: `${width}%`, ...resolvedStyles };
    const imageClassName = stretch ? "block h-full w-full object-cover" : "block h-auto w-full object-cover";

    return (
      wrapBlock(
        <div className="relative group">
          <div
            role="button"
            tabIndex={0}
            onClick={handleSelect}
            onKeyDown={handleKeyDown}
            className={buildContainerClass(
              baseClasses,
              `rounded border p-1 ${
                isSelected
                  ? `${selectedBorderClass} ${selectedSoftBg}`
                  : "border-transparent hover:border-border/30"
              }`
            )}
          >
            {src ? (
              <div className="cms-media relative" style={wrapperStyles}>
                {/* eslint-disable-next-line @next/next/no-img-element */}
                <img src={src} alt={alt} className={imageClassName} />
              </div>
            ) : (
              <div
                className="cms-media flex items-center justify-center bg-gray-700/30 min-h-[60px]"
                style={wrapperStyles}
              >
                <div className="flex flex-col items-center gap-1">
                  <ImageIcon className="size-6 text-gray-500" />
                  <span className="text-xs text-gray-500 truncate max-w-[120px]">{alt}</span>
                </div>
              </div>
            )}
          </div>
          {showEditorChrome && onOpenMedia && (
            <button
              type="button"
              onClick={(e: React.MouseEvent): void => {
                e.stopPropagation();
                onOpenMedia?.({
                  kind: "block",
                  sectionId,
                  blockId: block.id,
                  columnId,
                  parentBlockId,
                  key: "src",
                });
              }}
              className="absolute right-2 top-2 rounded-full border border-border/40 bg-gray-900/70 px-2 py-1 text-[10px] text-gray-300 opacity-0 transition group-hover:opacity-100"
            >
              Replace image
            </button>
          )}
        </div>
      )
    );
  }

  // VideoEmbed block
  if (block.type === "VideoEmbed") {
    const url = (block.settings["url"] as string) || "";
    const ratio = (block.settings["aspectRatio"] as string) || "16:9";
    const autoplay = (block.settings["autoplay"] as string) === "yes";

    let embedUrl: string | null = null;
    if (url) {
      const ytMatch = url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/|youtube\.com\/embed\/)([^&?#]+)/);
      if (ytMatch) embedUrl = `https://www.youtube.com/embed/${ytMatch[1]}`;
      else {
        const vimeoMatch = url.match(/vimeo\.com\/(?:video\/)?(\d+)/);
        if (vimeoMatch) embedUrl = `https://player.vimeo.com/video/${vimeoMatch[1]}`;
        else if (url.includes("embed") || url.includes("player")) embedUrl = url;
      }
    }

    const paddingBottom = ratio === "4:3" ? "75%" : ratio === "1:1" ? "100%" : "56.25%";
    const resolvedStyles: React.CSSProperties = {
      ...(mediaStyles ?? {}),
      paddingBottom,
    };

    return (
      wrapBlock(
        <div
          role="button"
          tabIndex={0}
          onClick={handleSelect}
          onKeyDown={handleKeyDown}
          className={buildContainerClass(
            `w-full text-left transition overflow-hidden ${contained ? "max-w-full" : ""}`,
            `rounded border p-3 ${
              isSelected
                ? `${selectedBorderClass} ${selectedSoftBg}`
                : "border-border/30 bg-gray-800/20 hover:border-border/50"
            }`
          )}
        >
          {embedUrl ? (
            <div className="cms-media relative w-full" style={resolvedStyles}>
              <iframe
                className="absolute inset-0 h-full w-full"
                src={`${embedUrl}${autoplay ? "?autoplay=1&mute=1" : ""}`}
                title="Embedded video"
                allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                allowFullScreen
              />
            </div>
          ) : (
            <div
              className="cms-media flex items-center justify-center bg-gray-800/50 py-8 text-gray-500 text-sm"
              style={resolvedStyles}
            >
              Enter a video URL
            </div>
          )}
        </div>
      )
    );
  }

  // AppEmbed block
  if (block.type === "AppEmbed") {
    const appId = (block.settings["appId"] as AppEmbedId) || "chatbot";
    const title = (block.settings["title"] as string) || "";
    const embedUrl = (block.settings["embedUrl"] as string) || "";
    const height = (block.settings["height"] as number) || 420;
    const appLabel = APP_EMBED_OPTIONS.find((option: AppEmbedOption) => option.id === appId)?.label ?? "App";

    return (
      wrapBlock(
        <div
          role="button"
          tabIndex={0}
          onClick={handleSelect}
          onKeyDown={handleKeyDown}
          className={buildContainerClass(
            `w-full text-left transition overflow-hidden ${contained ? "max-w-full" : ""}`,
            `rounded border p-3 ${
              isSelected
                ? `${selectedBorderClass} ${selectedSoftBg}`
                : "border-border/30 bg-gray-800/20 hover:border-border/50"
            }`
          )}
        >
          <div className="cms-hover-card w-full rounded-lg border border-border/40 bg-gray-900/40 p-4">
            <div className="mb-3">
              <div className="text-sm font-semibold text-white">{title || appLabel}</div>
              <div className="text-[10px] uppercase tracking-wide text-gray-500">App embed</div>
            </div>
            {embedUrl ? (
              <iframe
                src={embedUrl}
                title={title || appLabel}
                className="w-full rounded-md border border-border/40 bg-black"
                style={{ height }}
              />
            ) : (
              <div
                className="flex items-center justify-center rounded-md border border-dashed border-border/40 bg-gray-800/40 text-xs text-gray-400"
                style={{ height }}
              >
                Provide an embed URL to render the {appLabel} app here.
              </div>
            )}
          </div>
        </div>
      )
    );
  }

  // Divider block
  if (block.type === "Divider") {
    const dividerStyle = (block.settings["dividerStyle"] as string) || "solid";
    const thickness = (block.settings["thickness"] as number) || 1;
    const color = (block.settings["dividerColor"] as string) || "#4b5563";

    return (
      wrapBlock(
        <div
          role="button"
          tabIndex={0}
          onClick={handleSelect}
          onKeyDown={handleKeyDown}
          className={buildContainerClass(
            `w-full text-left transition overflow-hidden ${contained ? "max-w-full" : ""}`,
            `rounded border p-3 ${
              isSelected
                ? `${selectedBorderClass} ${selectedSoftBg}`
                : "border-border/30 bg-gray-800/20 hover:border-border/50"
            }`
          )}
        >
          <hr
            className="my-2 border-0"
            style={{ borderTopStyle: dividerStyle as any, borderTopWidth: `${thickness}px`, borderTopColor: color }}
          />
        </div>
      )
    );
  }

  // SocialLinks block
  if (block.type === "SocialLinks") {
    const platforms = (block.settings["platforms"] as string) || "";
    const links = platforms.split(",").map((l: string) => l.trim()).filter(Boolean);

    return (
      wrapBlock(
        <div
          role="button"
          tabIndex={0}
          onClick={handleSelect}
          onKeyDown={handleKeyDown}
          className={buildContainerClass(
            `text-left transition ${contained ? "max-w-full" : ""}`,
            `rounded border p-3 ${
              isSelected
                ? `${selectedBorderClass} ${selectedSoftBg}`
                : "border-border/30 bg-gray-800/20 hover:border-border/50"
            }`
          )}
        >
          {links.length === 0 ? (
            <p className="text-sm text-gray-500">Add social media URLs in settings</p>
          ) : (
            <div className="flex items-center gap-4">
              {links.map((link: string, idx: number) => {
                let label = "Link";
                try {
                  label = new URL(link).hostname.replace("www.", "").split(".")[0] ?? "Link";
                } catch {
                  // keep default
                }
                return (
                  <a
                    key={`${link}-${idx}`}
                    href={link}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="rounded-full border border-gray-600 p-2 text-gray-400 transition hover:text-white hover:border-white"
                  >
                    <span className="text-xs font-medium uppercase">{label.slice(0, 2)}</span>
                  </a>
                );
              })}
            </div>
          )}
        </div>
      )
    );
  }

  // Icon block
  if (block.type === "Icon") {
    const iconName = (block.settings["iconName"] as string) || "Star";
    const iconSize = (block.settings["iconSize"] as number) || 24;
    const iconColor = (block.settings["iconColor"] as string) || "#ffffff";

    return (
      wrapBlock(
        <div
          role="button"
          tabIndex={0}
          onClick={handleSelect}
          onKeyDown={handleKeyDown}
          className={buildContainerClass(
            `text-left transition ${contained ? "max-w-full" : ""}`,
            `rounded border p-3 ${
              isSelected
                ? `${selectedBorderClass} ${selectedSoftBg}`
                : "border-border/30 bg-gray-800/20 hover:border-border/50"
            }`
          )}
        >
          <div className="flex items-center justify-center">
            <span style={{ fontSize: `${iconSize}px`, color: iconColor }} role="img" aria-label={iconName}>
              {iconName === "Star" ? "\u2605" : iconName === "Heart" ? "\u2665" : iconName === "Check" ? "\u2713" : iconName === "Arrow" ? "\u2192" : "\u25CF"}
            </span>
          </div>
        </div>
      )
    );
  }

  // Fallback for unknown block types
  if (!showEditorChrome) {
    return null;
  }

  return (
    wrapBlock(
      <div
        role="button"
        tabIndex={0}
        onClick={handleSelect}
        onKeyDown={handleKeyDown}
        className={buildContainerClass(
          `flex w-full items-center gap-2 text-left text-sm transition overflow-hidden ${contained ? "max-w-full" : ""}`,
          `rounded border p-3 ${
            isSelected
              ? `${selectedBorderClass} ${selectedSoftBg}`
              : "border-border/30 bg-gray-800/20 hover:border-border/50"
          }`
        )}
      >
        <span className="flex-1 truncate text-gray-300">{block.type}</span>
      </div>
    )
  );
}

"use client";

import { Button } from "@/shared/ui";
import type { ColumnDef, Column } from "@tanstack/react-table";

import type { DatabaseInfo } from "../types";

// ✅ Use TanStack's Column type, and accept that the handler may be undefined.
const renderSortableHeader = <TData, TValue>(
  label: string,
  column: Column<TData, TValue>
): React.JSX.Element => {
  const direction = column.getIsSorted(); // false | "asc" | "desc"
  const handler = column.getToggleSortingHandler(); // ((event) => void) | undefined

  return (
    <Button
      type="button"
      onClick={handler ?? undefined}
      // optional: prevent "clickable" affordance if it can't sort
      disabled={!handler}
      className="inline-flex items-center gap-1 text-left text-sm font-medium text-foreground disabled:cursor-not-allowed disabled:opacity-60"
    >
      {label}
      <span className="text-xs text-muted-foreground">
        {direction === "asc" ? "▲" : direction === "desc" ? "▼" : "↕"}
      </span>
    </Button>
  );
};

export const getDatabaseColumns = (options?: {
  onPreview?: (backupName: string) => void;
  onRestoreRequest?: (backup: DatabaseInfo) => void;
  onDeleteRequest?: (backupName: string) => void;
}): ColumnDef<DatabaseInfo>[] => [
  {
    accessorKey: "name",
    header: ({ column }: { column: Column<DatabaseInfo, unknown> }): React.JSX.Element => renderSortableHeader("Name", column),
  },
  {
    accessorKey: "size",
    header: ({ column }: { column: Column<DatabaseInfo, unknown> }): React.JSX.Element => renderSortableHeader("Size", column),
    sortingFn: (rowA: any, rowB: any, columnId: string): number => {
      const toNumber = (value: string): number =>
        Number.parseFloat(value.replace(/[^0-9.]/g, "")) || 0;
      return (
        toNumber(rowA.getValue(columnId)) - toNumber(rowB.getValue(columnId))
      );
    },
  },
  {
    id: "createdAt",
    accessorFn: (row: DatabaseInfo): number => new Date(row.createdAt).getTime(),
    header: ({ column }: { column: Column<DatabaseInfo, unknown> }): React.JSX.Element => renderSortableHeader("Created", column),
    cell: ({ row }: { row: { original: DatabaseInfo } }): React.ReactNode => row.original.created,
  },
  {
    id: "lastModifiedAt",
    accessorFn: (row: DatabaseInfo): number => new Date(row.lastModifiedAt).getTime(),
    header: ({ column }: { column: Column<DatabaseInfo, unknown> }): React.JSX.Element => renderSortableHeader("Last Modified", column),
    cell: ({ row }: { row: { original: DatabaseInfo } }): React.ReactNode => row.original.lastModified,
  },
  {
    accessorKey: "lastRestored",
    header: "Last Restored",
    cell: ({ row }: { row: { original: DatabaseInfo } }): React.ReactNode => row.original.lastRestored || "Never",
  },
  {
    id: "actions",
    cell: ({ row }: { row: { original: DatabaseInfo } }): React.JSX.Element => {
      const backup = row.original;
      return (
        <div className="flex space-x-2">
          {options?.onPreview && (
            <Button
              variant="secondary"
              onClick={(): void => options.onPreview?.(backup.name)}
            >
              Preview
            </Button>
          )}

          <Button
            onClick={(): void => {
              options?.onRestoreRequest?.(backup);
            }}
          >
            Restore
          </Button>

          <Button
            variant="destructive"
            onClick={(): void => {
              options?.onDeleteRequest?.(backup.name);
            }}
          >
            Delete
          </Button>
        </div>
      );
    },
  },
];

"use client";

import { DataTable, Button, useToast, Input, SectionHeader, SectionPanel } from "@/shared/ui";
import { useState, useRef } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";






import { getDatabaseColumns } from "../components/DatabaseColumns";
import { LogModal } from "../components/LogModal";
import { RestoreModal } from "../components/RestoreModal";
import type { DatabaseInfo, DatabaseType } from "../types";
import {
  createDatabaseBackup,
  fetchDatabaseBackups,
  restoreDatabaseBackup,
  uploadDatabaseBackup,
  deleteDatabaseBackup,
} from "../api";

export default function DatabasesPage(): React.JSX.Element {
  const [activeTab, setActiveTab] = useState<DatabaseType>("postgresql");
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isLogModalOpen, setIsLogModalOpen] = useState(false);
  const [logModalContent, setLogModalContent] = useState("");
  const [isRestoreModalOpen, setIsRestoreModalOpen] = useState(false);
  const [selectedBackupForRestore, setSelectedBackupForRestore] = useState<string | null>(null);
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const backupsQuery = useQuery({
    queryKey: ["database-backups", activeTab],
    queryFn: async (): Promise<DatabaseInfo[]> => fetchDatabaseBackups(activeTab),
  });
  const data = backupsQuery.data ?? [];

  const createBackup = useMutation<{ ok: boolean; payload: DatabaseBackupResponse }, Error, { dbType: DatabaseType }>({
    mutationFn: async ({ dbType }: { dbType: DatabaseType }) => createDatabaseBackup(dbType),
    onSuccess: (_data, variables): void => {
      void queryClient.invalidateQueries({ queryKey: ["database-backups", variables.dbType] });
    },
  });

  const restoreBackup = useMutation<{ ok: boolean; payload: DatabaseRestoreResponse }, Error, { dbType: DatabaseType; backupName: string; truncateBeforeRestore: boolean }>({
    mutationFn: async ({
      dbType,
      backupName,
      truncateBeforeRestore,
    }: {
      dbType: DatabaseType;
      backupName: string;
      truncateBeforeRestore: boolean;
    }) =>
      restoreDatabaseBackup(dbType, {
        backupName,
        truncateBeforeRestore,
      }),
    onSuccess: (
      _data,
      variables
    ): void => {
      void queryClient.invalidateQueries({
        queryKey: ["database-backups", variables.dbType],
      });
    },
  });

  const uploadBackup = useMutation<{ ok: boolean; payload: DatabaseBackupResponse }, Error, { dbType: DatabaseType; file: File }>({
    mutationFn: async ({ dbType, file }: { dbType: DatabaseType; file: File }) =>
      uploadDatabaseBackup(dbType, file),
    onSuccess: (_data, variables): void => {
      void queryClient.invalidateQueries({ queryKey: ["database-backups", variables.dbType] });
    },
  });

  const deleteBackup = useMutation<{ ok: boolean; payload: DatabaseBackupResponse }, Error, { dbType: DatabaseType; backupName: string }>({
    mutationFn: async ({ dbType, backupName }: { dbType: DatabaseType; backupName: string }) =>
      deleteDatabaseBackup(dbType, backupName),
    onSuccess: (_data, variables): void => {
      void queryClient.invalidateQueries({ queryKey: ["database-backups", variables.dbType] });
    },
  });

  const openLogModal = (content: string): void => {
    setLogModalContent(content);
    setIsLogModalOpen(true);
  };

  const closeLogModal = (): void => {
    setIsLogModalOpen(false);
    setLogModalContent("");
    void queryClient.invalidateQueries({ queryKey: ["database-backups", activeTab] });
  };


  const handleRestoreRequest = (backup: DatabaseInfo): void => {
    setSelectedBackupForRestore(backup.name);
    setIsRestoreModalOpen(true);
  };

  const handleRestoreConfirm = async (truncate: boolean): Promise<void> => {
    const backupName = selectedBackupForRestore;
    setIsRestoreModalOpen(false);
    setSelectedBackupForRestore(null);

    if (!backupName) return;

    try {
      const { ok, payload } = await restoreBackup.mutateAsync({
        dbType: activeTab,
        backupName,
        truncateBeforeRestore: truncate,
      });
      const log = payload.log ?? "No log available.";

      if (ok) {
        openLogModal(
          `${payload.message ?? "Backup restored successfully."}\n\n---LOG---\n${log}`
        );
      } else {
        const meta = [
          payload.errorId ? `Error ID: ${payload.errorId}` : null,
          payload.stage ? `Stage: ${payload.stage}` : null,
          payload.backupName ? `Backup: ${payload.backupName}` : null,
        ]
          .filter(Boolean)
          .join("\n");

        openLogModal(
          `${payload.error ?? "Failed to restore backup."}${
            meta ? `\n\n${meta}` : ""
          }\n\n---LOG---\n${log}`
        );
      }
    } catch (error) {
      console.error("Error restoring backup:", error);
      openLogModal(`An error occurred during restoration.\n\n${String(error)}`);
    }
  };

  const handleBackup = async (): Promise<void> => {
    try {
      const { ok, payload } = (await createBackup.mutateAsync({ dbType: activeTab })) as {
        ok: boolean;
        payload: {
          log?: string;
          warning?: string;
          message?: string;
          error?: string;
        };
      };
      const log = payload.log ?? "No log available.";
      if (ok) {
        if (payload.warning) {
          openLogModal(
            `${payload.message ?? "Backup created"}: ${
              payload.warning
            }\n\n---LOG---\n${log}`
          );
        } else {
          openLogModal(
            `${
              payload.message ?? "Backup created successfully."
            }\n\n---LOG---\n${log}`
          );
        }
      } else {
        openLogModal(
          `${payload.error ?? "Failed to create backup."}\n\n---LOG---\n${log}`
        );
      }
    } catch (error) {
      console.error("Error creating backup:", error);
      openLogModal(`An error occurred during backup.\n\n${String(error)}`);
    }
  };

  const handleDeleteRequest = async (backupName: string): Promise<void> => {
    if (!window.confirm(`Delete backup ${backupName}? This cannot be undone.`)) return;
    try {
      const result = await deleteBackup.mutateAsync({ dbType: activeTab, backupName });
      if (result.ok) {
        toast("Backup deleted successfully.", { variant: "success" });
      } else {
        toast("Failed to delete backup.", { variant: "error" });
      }
    } catch (error) {
      console.error("Error deleting backup:", error);
      toast("An error occurred during deletion.", { variant: "error" });
    }
  };

  const handleUpload = async (event: React.ChangeEvent<HTMLInputElement>): Promise<void> => {
    const file = event.target.files?.[0];
    if (!file) return;

    try {
      const result = await uploadBackup.mutateAsync({ dbType: activeTab, file });
      if (result.ok) {
        toast("Backup uploaded successfully.", { variant: "success" });
      } else {
        toast("Failed to upload backup.", { variant: "error" });
      }
    } catch (error) {
      console.error("Error uploading backup:", error);
      toast("An error occurred during upload.", { variant: "error" });
    } finally {
      event.target.value = "";
    }
  };

  const triggerFileUpload = (): void => {
    fileInputRef.current?.click();
  };

  const handlePreview = (backupName: string): void => {
    const url = `/admin/databases/preview?backup=${encodeURIComponent(
      backupName
    )}&type=${activeTab}`;
    window.location.assign(url);
  };

  const handlePreviewCurrent = (): void => {
    window.location.assign(`/admin/databases/preview?mode=current&type=${activeTab}`);
  };

  return (
    <div className="container mx-auto py-10">
      {isLogModalOpen && (
        <LogModal content={logModalContent} onClose={closeLogModal} />
      )}

      {isRestoreModalOpen && selectedBackupForRestore && (
        <RestoreModal
          backupName={selectedBackupForRestore}
          onClose={(): void => {
            setIsRestoreModalOpen(false);
            setSelectedBackupForRestore(null);
          }}
          onConfirm={(t: boolean) => void handleRestoreConfirm(t)}
        />
      )}

      {/* Tabs */}
      <div className="mb-6 border-b border">
        <div className="flex gap-4">
          <Button
            onClick={(): void => setActiveTab("postgresql")}
            className={`px-4 py-2 font-medium transition ${
              activeTab === "postgresql"
                ? "border-b-2 border-blue-500 text-blue-500"
                : "text-gray-400 hover:text-gray-300"
            }`}
          >
            PostgreSQL
          </Button>
          <Button
            onClick={(): void => setActiveTab("mongodb")}
            className={`px-4 py-2 font-medium transition ${
              activeTab === "mongodb"
                ? "border-b-2 border-blue-500 text-blue-500"
                : "text-gray-400 hover:text-gray-300"
            }`}
          >
            MongoDB
          </Button>
        </div>
      </div>

      <SectionHeader
        title={`Databases - ${activeTab === "postgresql" ? "PostgreSQL" : "MongoDB"}`}
        description={
          activeTab === "postgresql"
            ? "PostgreSQL backups use pg_dump/pg_restore (.dump files). Restores are data-only and preserve your current schema."
            : "MongoDB backups use mongodump/mongorestore (.archive files). Full database dumps with BSON format."
        }
        actions={
          <>
            <Button
              onClick={(): void => {
                void handleBackup();
              }}
            >
              Create Backup
            </Button>
            <Button onClick={triggerFileUpload}>Upload Backup</Button>
            <Button variant="secondary" onClick={handlePreviewCurrent}>
              Preview Current DB
            </Button>
            <Input
              type="file"
              ref={fileInputRef}
              onChange={(e: React.ChangeEvent<HTMLInputElement>) => void handleUpload(e)}
              className="hidden"
              accept={activeTab === "postgresql" ? ".dump" : ".archive"}
            />
          </>
        }
        className="mb-6"
      />
      <SectionPanel className="p-6">
        <DataTable
          columns={getDatabaseColumns({
            onPreview: handlePreview,
            onRestoreRequest: handleRestoreRequest,
            onDeleteRequest: (name: string) => { void handleDeleteRequest(name); },
          })}
          data={data}
          initialSorting={[{ id: "lastModifiedAt", desc: true }]}
          sortingStorageKey={`stardb:database-backups:${activeTab}:sorting`}
        />
      </SectionPanel>
    </div>
  );
}

"use client";

import { Button, Label, Select, SelectContent, SelectItem, SelectTrigger, SelectValue, ModalShell, Checkbox } from "@/shared/ui";
import { useState } from "react";

import { logger } from "@/shared/utils/logger";
import { ExportLogViewer } from "./ExportLogViewer";
import type { CapturedLog } from "@/features/integrations/services/exports/log-capture";

import { useIntegrationSelection } from "./hooks/useIntegrationSelection";
import { useBaseComSettings } from "./hooks/useBaseComSettings";

type MassListProductModalProps = {
  productIds: string[];
  integrationId: string;
  connectionId: string;
  onClose: () => void;
  onSuccess: () => void;
};

import type { InventoryOption, Template } from "@/features/data-import-export/types/imports";

export default function MassListProductModal({
  productIds,
  integrationId: initialIntegrationId,
  connectionId: initialConnectionId,
  onClose,
  onSuccess,
}: MassListProductModalProps): React.JSX.Element {
  const [error, setError] = useState<string | null>(null);
  const [submitting, setSubmitting] = useState(false);
  const [progress, setProgress] = useState<{ current: number; total: number; errors: number } | null>(null);

  // Integration & connection selection
  const {
    loading: loadingIntegrations,
    selectedConnectionId,
    selectedIntegration,
    isBaseComIntegration,
  } = useIntegrationSelection(initialIntegrationId, initialConnectionId);

  // Base.com specific settings
  const {
    templates,
    selectedTemplateId,
    setSelectedTemplateId,
    inventories,
    selectedInventoryId,
    setSelectedInventoryId,
    loadingInventories,
    allowDuplicateSku,
    setAllowDuplicateSku,
  } = useBaseComSettings(isBaseComIntegration, selectedConnectionId);

  // Export logging - for mass operations, store all logs
  const [exportLogs, setExportLogs] = useState<CapturedLog[]>([]);
  const [logsOpen, setLogsOpen] = useState(false);

  const connectionName = (selectedIntegration?.connections as any[])?.find(
    (c: any) => c.id === selectedConnectionId
  )?.name || "";

  const handleSubmit = async (): Promise<void> => {
    if (isBaseComIntegration && !selectedInventoryId) {
      setError("Please select a Base.com inventory");
      return;
    }

    setSubmitting(true);
    setError(null);
    setProgress({ current: 0, total: productIds.length, errors: 0 });
    setExportLogs([]);
    setLogsOpen(true);

    let errors = 0;
    const allLogs: CapturedLog[] = [];

    for (let i = 0; i < productIds.length; i++) {
        const productId = productIds[i];
        if (!productId) continue;
        setProgress((prev: { current: number; total: number; errors: number } | null) => prev ? { ...prev, current: i + 1 } : null);

        try {
            if (isBaseComIntegration) {
                const res = await fetch(`/api/integrations/products/${productId}/export-to-base`, {
                  method: "POST",
                  headers: { "Content-Type": "application/json" },
                  body: JSON.stringify({
                    connectionId: selectedConnectionId,
                    inventoryId: selectedInventoryId,
                    templateId: selectedTemplateId !== "none" ? selectedTemplateId : undefined,
                    allowDuplicateSku,
                  }),
                });

                const data = (await res.json().catch(() => ({}))) as { logs?: CapturedLog[] };
                if (data.logs) {
                  allLogs.push(...data.logs);
                  setExportLogs([...allLogs]);
                }

                if (!res.ok) {
                    errors++;
                }
              } else {
                const res = await fetch(`/api/integrations/products/${productId}/listings`, {
                  method: "POST",
                  headers: { "Content-Type": "application/json" },
                  body: JSON.stringify({
                    integrationId: initialIntegrationId,
                    connectionId: selectedConnectionId,
                  }),
                });

                if (!res.ok) {
                    errors++;
                }
              }
        } catch (e: unknown) {
            logger.error("Failed to list product", e);
            errors++;
        }

        setProgress((prev: { current: number; total: number; errors: number } | null) => prev ? { ...prev, errors } : null);
    }

    setSubmitting(false);
    if (errors === 0) {
        onSuccess();
    } else {
        setError(`Completed with ${errors} errors.`);
        // Don't close immediately if there were errors, so user can see
        setTimeout(() => onSuccess(), 2000); 
    }
  };

  const loading = loadingIntegrations;

  return (
    <ModalShell
      title={`List ${productIds.length} Products to ${selectedIntegration?.name || "Marketplace"}`}
      onClose={onClose}
      size="md"
      showClose={!submitting}
      footer={
        !submitting && (
            <>
            <Button
                variant="outline"
                onClick={onClose}
                className="bg-gray-800 text-white hover:bg-gray-700"
            >
                Cancel
            </Button>
            <Button
                onClick={(): void => { void handleSubmit(); }}
                disabled={
                submitting ||
                (isBaseComIntegration && !selectedInventoryId)
                }
            >
                {isBaseComIntegration
                ? "Export to Base.com"
                : "List Products"}
            </Button>
            </>
        )
      }
    >
      <div className="space-y-6">
        {error && (
          <div className="rounded-md border border-red-500/40 bg-red-500/10 px-4 py-3 text-sm text-red-200">
            {error}
          </div>
        )}

        {submitting && progress && (
             <div className="space-y-2">
                 <p className="text-sm text-gray-300">Processing {progress.current} of {progress.total}...</p>
                 <div className="h-2 w-full rounded-full bg-gray-800">
                     <div 
                        className="h-full rounded-full bg-primary transition-all duration-300" 
                        style={{ width: `${(progress.current / progress.total) * 100}%` }}
                     />
                 </div>
                 {progress.errors > 0 && <p className="text-xs text-red-400">{progress.errors} failures so far</p>}
             </div>
        )}

        {!submitting && (
            <>
                <div className="rounded-md border bg-card/50 px-4 py-3">
                <p className="text-sm text-gray-300">
                    <span className="text-gray-500">Integration:</span>{" "}
                    <span className="font-medium">{selectedIntegration?.name || "Loading..."}</span>
                </p>
                <p className="text-sm text-gray-300">
                    <span className="text-gray-500">Account:</span>{" "}
                    <span className="font-medium">{connectionName || "Loading..."}</span>
                </p>
                </div>

                {loading ? (
                <p className="text-sm text-gray-400">Loading details...</p>
                ) : (
                <>
                    {isBaseComIntegration && (
                    <>
                        <div className="space-y-2">
                        <Label htmlFor="inventory">
                            Base.com Inventory {loadingInventories && "(Loading...)"}
                        </Label>
                        <Select
                            value={selectedInventoryId}
                            onValueChange={setSelectedInventoryId}
                            disabled={loadingInventories || inventories.length === 0}
                        >
                            <SelectTrigger id="inventory">
                            <SelectValue placeholder="Select inventory..." />
                            </SelectTrigger>
                            <SelectContent>
                            {(inventories as any[])
                                .filter((inventory: any): boolean => !!inventory.id)
                                .map((inventory: any) => (
                                <SelectItem key={inventory.id} value={inventory.id}>
                                    {inventory.name}
                                </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                        {inventories.length === 0 && !loadingInventories && (
                            <p className="text-xs text-red-400">
                            No inventories found. Please check your Base.com account.
                            </p>
                        )}
                        </div>

                        <div className="space-y-2">
                        <Label htmlFor="template">Template (Optional)</Label>
                        <Select
                            value={selectedTemplateId}
                            onValueChange={setSelectedTemplateId}
                        >
                            <SelectTrigger id="template">
                            <SelectValue placeholder="No template (use defaults)" />
                            </SelectTrigger>
                            <SelectContent>
                            <SelectItem value="none">No template</SelectItem>
                            {(templates as any[])
                                .filter((template: any): boolean => !!template.id)
                                .map((template: any) => (
                                <SelectItem key={template.id} value={template.id}>
                                    {template.name}
                                </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                        <p className="text-xs text-gray-500">
                            Templates define how product fields map to Base.com fields.
                        </p>
                        </div>

                        <div className="flex items-center gap-2 pt-2">
                        <Checkbox
                            id="allowDuplicateSku"
                            checked={allowDuplicateSku} 
                            onCheckedChange={(checked: boolean | "indeterminate"): void => setAllowDuplicateSku(Boolean(checked))}
                            className="h-4 w-4 rounded border bg-gray-900 text-blue-500"
                        />
                        <Label htmlFor="allowDuplicateSku" className="text-sm text-gray-300">
                            Allow duplicate SKUs
                        </Label>
                        </div>
                        <p className="text-xs text-gray-500">
                        When unchecked, export will fail if the SKU already exists in the Base.com inventory.
                        </p>
                    </>
                    )}
                </>
                )}
            </>
        )}
        {exportLogs.length > 0 && (
          <div className="mt-4 border-t border pt-4">
            <ExportLogViewer
              logs={exportLogs}
              isOpen={logsOpen}
              onToggle={setLogsOpen}
            />
          </div>
        )}
      </div>
    </ModalShell>
  );
}

"use client";
import { Button, Label, DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger, Select, SelectContent, SelectItem, SelectTrigger, SelectValue, ModalShell, Checkbox } from "@/shared/ui";
import { useEffect, useState } from "react";





import type { ProductWithImages } from "@/features/products";
import type {
  ImageRetryPreset,
  ImageTransformOptions,
} from "@/features/data-import-export";
import { ExportLogViewer } from "./ExportLogViewer";
import type { CapturedLog } from "@/features/integrations/services/exports/log-capture";
import { useImageRetryPresets } from "./useImageRetryPresets";

import { useIntegrationSelection } from "./hooks/useIntegrationSelection";
import { useBaseComSettings } from "./hooks/useBaseComSettings";
import { isImageExportError } from "./utils";

type SelectProductForListingModalProps = {
  integrationId: string;
  connectionId: string;
  onClose: () => void;
  onSuccess: () => void;
};

export default function SelectProductForListingModal({
  integrationId: initialIntegrationId,
  connectionId: initialConnectionId,
  onClose,
  onSuccess,
}: SelectProductForListingModalProps): React.JSX.Element {
  const [products, setProducts] = useState<ProductWithImages[]>([]);
  const [loadingProducts, setLoadingProducts] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedProductId, setSelectedProductId] = useState<string>("");
  const [submitting, setSubmitting] = useState(false);

  // Integration & connection selection
  const {
    loading: loadingIntegrations,
    selectedIntegrationId,
    selectedConnectionId,
    selectedIntegration,
    isBaseComIntegration,
  } = useIntegrationSelection(initialIntegrationId, initialConnectionId);

  // Base.com specific settings
  const {
    templates,
    selectedTemplateId,
    setSelectedTemplateId,
    inventories,
    selectedInventoryId,
    setSelectedInventoryId,
    loadingInventories,
    allowDuplicateSku,
    setAllowDuplicateSku,
  } = useBaseComSettings(isBaseComIntegration, selectedConnectionId);

  // Export logging
  const [exportLogs, setExportLogs] = useState<CapturedLog[]>([]);
  const [logsOpen, setLogsOpen] = useState(false);
  const imageRetryPresets = useImageRetryPresets();

  const connectionName = selectedIntegration?.connections.find(
    (c: any) => c.id === selectedConnectionId
  )?.name || "";

  // Load products
  useEffect(() => {
    const fetchProducts = async (): Promise<void> => {
      try {
        setLoadingProducts(true);
        const res = await fetch("/api/products");
        if (!res.ok) throw new Error("Failed to fetch products");
        const data = (await res.json()) as ProductWithImages[];
        setProducts(data);
      } catch (err) {
        setError(err instanceof Error ? err.message : "Failed to load products");
      } finally {
        setLoadingProducts(false);
      }
    };
    void fetchProducts();
  }, []);

  const exportToBase = async (options?: {
    imageBase64Mode?: "base-only" | "full-data-uri";
    imageTransform?: ImageTransformOptions | null;
  }): Promise<void> => {
    const payload: Record<string, unknown> = {
      connectionId: selectedConnectionId,
      inventoryId: selectedInventoryId,
      templateId: selectedTemplateId !== "none" ? selectedTemplateId : undefined,
      allowDuplicateSku,
    };

    if (options?.imageBase64Mode) {
      payload.imageBase64Mode = options.imageBase64Mode;
      payload.exportImagesAsBase64 = true;
    }
    if (options?.imageTransform) {
      payload.imageTransform = options.imageTransform;
      payload.exportImagesAsBase64 = true;
    }

    const res = await fetch(`/api/integrations/products/${selectedProductId}/export-to-base`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });

    const data = (await res.json().catch(() => ({}))) as { 
      logs?: CapturedLog[]; 
      skuExists?: boolean; 
      error?: string 
    };
    if (data.logs) {
      setExportLogs(data.logs);
    }

    if (!res.ok) {
      if (data.skuExists) {
        throw new Error(data.error || "SKU already exists in Base.com");
      }
      throw new Error(data.error || "Failed to export product to Base.com");
    }
  };

  const handleSubmit = async (): Promise<void> => {
    if (!selectedProductId) {
      setError("Please select a product");
      return;
    }

    if (!selectedConnectionId) {
      setError("Please select an account");
      return;
    }

    if (isBaseComIntegration && !selectedInventoryId) {
      setError("Please select a Base.com inventory");
      return;
    }

    try {
      setSubmitting(true);
      setError(null);
      setExportLogs([]);
      setLogsOpen(true);

      if (isBaseComIntegration) {
        await exportToBase();
        onSuccess();
      } else {
        const res = await fetch(`/api/integrations/products/${selectedProductId}/listings`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            integrationId: selectedIntegrationId,
            connectionId: selectedConnectionId,
          }),
        });

        if (!res.ok) {
          const data = (await res.json()) as { error?: string };
          throw new Error(data.error || "Failed to create listing");
        }

        onSuccess();
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to list product");
    } finally {
      setSubmitting(false);
    }
  };

  const handleImageRetry = async (preset: ImageRetryPreset): Promise<void> => {
    if (!selectedProductId || !isBaseComIntegration || !selectedInventoryId) {
      return;
    }
    try {
      setSubmitting(true);
      setError(null);
      setExportLogs([]);
      setLogsOpen(true);
      await exportToBase({
        imageBase64Mode: preset.imageBase64Mode,
        imageTransform: preset.transform,
      });
      onSuccess();
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to export product");
    } finally {
      setSubmitting(false);
    }
  };

  const getProductDisplayName = (product: ProductWithImages): string => {
    return product.name_en || product.name_pl || product.name_de || product.sku;
  };

  const loading = loadingProducts || loadingIntegrations;

  return (
    <ModalShell
      title={`List Product to ${selectedIntegration?.name || "Marketplace"}`}
      onClose={onClose}
      size="md"
      showClose={false}
      footer={
        <>
          <Button
            variant="outline"
            onClick={onClose}
            className="bg-gray-800 text-white hover:bg-gray-700"
          >
            Cancel
          </Button>
          <Button
            onClick={() => void handleSubmit()}
            disabled={
              submitting ||
              !selectedProductId ||
              (isBaseComIntegration && !selectedInventoryId)
            }
          >
            {submitting
              ? isBaseComIntegration
                ? "Exporting..."
                : "Listing..."
              : isBaseComIntegration
              ? "Export to Base.com"
              : "List Product"}
          </Button>
        </>
      }
    >
      <div className="space-y-6">
        {error && (
          <div className="rounded-md border border-red-500/40 bg-red-500/10 px-4 py-3 text-sm text-red-200">
            <div className="flex flex-col gap-3">
              <span>{error}</span>
              {isBaseComIntegration && isImageExportError(error) ? (
                <div className="flex flex-wrap items-center gap-2">
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <Button
                        variant="secondary"
                        size="sm"
                        className="bg-red-500/20 text-red-100 hover:bg-red-500/30"
                        disabled={submitting}
                      >
                        Retry image export
                      </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent align="start" className="bg-card border-border">
                      {imageRetryPresets.map((preset: ImageRetryPreset) => (
                        <DropdownMenuItem
                          key={preset.id}
                          onSelect={() => void handleImageRetry(preset)}
                          className="text-gray-200 focus:bg-gray-800/70"
                        >
                          <div className="flex flex-col">
                            <span className="text-sm">{preset.label}</span>
                            <span className="text-xs text-gray-400">
                              {preset.description}
                            </span>
                          </div>
                        </DropdownMenuItem>
                      ))}
                    </DropdownMenuContent>
                  </DropdownMenu>
                  <span className="text-xs text-red-200/80">
                    Applies JPEG resize/compression and retries automatically.
                  </span>
                </div>
              ) : null}
            </div>
          </div>
        )}

        <div className="rounded-md border bg-card/50 px-4 py-3">
          <p className="text-sm text-gray-300">
            <span className="text-gray-500">Integration:</span>{" "}
            <span className="font-medium">{selectedIntegration?.name || "Loading..."}</span>
          </p>
          <p className="text-sm text-gray-300">
            <span className="text-gray-500">Account:</span>{" "}
            <span className="font-medium">{connectionName || "Loading..."}</span>
          </p>
        </div>

        {loading ? (
          <p className="text-sm text-gray-400">Loading products...</p>
        ) : (
          <>
            <div className="space-y-2">
              <Label htmlFor="product">Select Product</Label>
              <Select
                value={selectedProductId}
                onValueChange={setSelectedProductId}
              >
                <SelectTrigger id="product">
                  <SelectValue placeholder="Select a product..." />
                </SelectTrigger>
                <SelectContent>
                  {products.map((product: any) => (
                    <SelectItem key={product.id} value={product.id}>
                      {getProductDisplayName(product)} ({product.sku})
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {isBaseComIntegration && (
              <>
                <div className="space-y-2">
                  <Label htmlFor="inventory">
                    Base.com Inventory {loadingInventories && "(Loading...)"}
                  </Label>
                  <Select
                    value={selectedInventoryId}
                    onValueChange={setSelectedInventoryId}
                    disabled={loadingInventories || inventories.length === 0}
                  >
                    <SelectTrigger id="inventory">
                      <SelectValue placeholder="Select inventory..." />
                    </SelectTrigger>
                    <SelectContent>
                      {inventories
                        .filter((inventory: any) => inventory.id)
                        .map((inventory: any) => (
                          <SelectItem key={inventory.id} value={inventory.id}>
                            {inventory.name}
                          </SelectItem>
                        ))}
                    </SelectContent>
                  </Select>
                  {inventories.length === 0 && !loadingInventories && (
                    <p className="text-xs text-red-400">
                      No inventories found. Please check your Base.com account.
                    </p>
                  )}
                </div>

                <div className="space-y-2">
                  <Label htmlFor="template">Template (Optional)</Label>
                  <Select
                    value={selectedTemplateId}
                    onValueChange={setSelectedTemplateId}
                  >
                    <SelectTrigger id="template">
                      <SelectValue placeholder="No template (use defaults)" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="none">No template</SelectItem>
                      {templates
                        .filter((template: any) => template.id)
                        .map((template: any) => (
                          <SelectItem key={template.id} value={template.id}>
                            {template.name}
                          </SelectItem>
                        ))}
                    </SelectContent>
                  </Select>
                  <p className="text-xs text-gray-500">
                    Templates define how product fields map to Base.com fields.
                  </p>
                </div>

                <div className="flex items-center gap-2 pt-2">
                  <Checkbox
                    id="allowDuplicateSku"
                    checked={allowDuplicateSku} onCheckedChange={(checked: boolean | "indeterminate"): void => setAllowDuplicateSku(Boolean(checked))}
                    className="h-4 w-4 rounded border bg-gray-900 text-blue-500"
                  />
                  <Label htmlFor="allowDuplicateSku" className="text-sm text-gray-300">
                    Allow duplicate SKUs
                  </Label>
                </div>
                <p className="text-xs text-gray-500">
                  When unchecked, export will fail if the SKU already exists in the Base.com inventory.
                </p>
              </>
            )}
          </>
        )}
        {exportLogs.length > 0 && (
          <div className="mt-4 border-t border pt-4">
            <ExportLogViewer
              logs={exportLogs}
              isOpen={logsOpen}
              onToggle={setLogsOpen}
            />
          </div>
        )}
      </div>
    </ModalShell>
  );
}

"use client";

import { useToast } from "@/shared/ui";
import { useEffect, useState, Suspense } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { useQueryClient } from "@tanstack/react-query";

import {
  Integration,
  IntegrationConnection,
  TestLogEntry,
  TestStatus,
  TestConnectionResponse,
  integrationDefinitions,
} from "@/features/integrations/types/integrations-ui";
import { defaultPlaywrightSettings } from "@/features/playwright";
import type { PlaywrightPersona } from "@/features/playwright";
import {
  buildPlaywrightSettings,
  fetchPlaywrightPersonas,
  findPlaywrightPersonaMatch,
} from "@/features/playwright";
import { normalizeSteps } from "@/features/integrations/utils/connections";
import { IntegrationList } from "@/features/integrations/components/connections/IntegrationList";
import { IntegrationModal } from "@/features/integrations/components/connections/IntegrationModal";
import {
  useConnectionSession,
  useIntegrationConnections,
  useIntegrations,
} from "@/features/integrations/hooks/useIntegrationQueries";
import {
  useCreateIntegration,
  useDeleteConnection,
  useUpsertConnection,
} from "@/features/integrations/hooks/useIntegrationMutations";

const EMPTY_INTEGRATIONS: Integration[] = [];
const EMPTY_CONNECTIONS: IntegrationConnection[] = [];

function IntegrationsContent(): React.JSX.Element {
  const { toast } = useToast();
  const router = useRouter();
  const searchParams = useSearchParams();
  const queryClient = useQueryClient();
  const integrationsQuery = useIntegrations();
  const createIntegrationMutation = useCreateIntegration();
  const upsertConnectionMutation = useUpsertConnection();
  const deleteConnectionMutation = useDeleteConnection();
  const integrations = integrationsQuery.data ?? EMPTY_INTEGRATIONS;
  const [activeIntegration, setActiveIntegration] =
    useState<Integration | null>(null);
  const connectionsQuery = useIntegrationConnections(activeIntegration?.id);
  const connections = connectionsQuery.data ?? EMPTY_CONNECTIONS;
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingConnectionId, setEditingConnectionId] = useState<string | null>(
    null
  );
  const [connectionForm, setConnectionForm] = useState({
    name: "",
    username: "",
    password: "",
  });

  const [testLog, setTestLog] = useState<TestLogEntry[]>([]);
  const [isTesting, setIsTesting] = useState(false);
  const [showTestLogModal, setShowTestLogModal] = useState(false);
  const [showTestErrorModal, setShowTestErrorModal] = useState(false);
  const [testError, setTestError] = useState<string | null>(null);
  const [testErrorMeta, setTestErrorMeta] = useState<{ 
    errorId?: string | undefined;
    integrationId?: string | null | undefined;
    connectionId?: string | null | undefined;
  } | null>(null);
  const [_lastTestError, setLastTestError] = useState<string | null>(null);
  const [showTestSuccessModal, setShowTestSuccessModal] = useState(false);
  const [testSuccessMessage, setTestSuccessMessage] = useState<string | null>(
    null
  );
  const [showPlaywrightSaved, setShowPlaywrightSaved] = useState(false);
  const [showSessionModal, setShowSessionModal] = useState(false);
  const [savingAllegroSandbox, setSavingAllegroSandbox] = useState(false);
  const [baseApiMethod, setBaseApiMethod] = useState("getInventories");
  const [baseApiParams, setBaseApiParams] = useState("{}");
  const [baseApiResponse, setBaseApiResponse] = useState<{ 
    data: unknown;
  } | null>(null);
  const [baseApiError, setBaseApiError] = useState<string | null>(null);
  const [baseApiLoading, setBaseApiLoading] = useState(false);
  const [allegroApiMethod, setAllegroApiMethod] = useState("GET");
  const [allegroApiPath, setAllegroApiPath] = useState("/sale/categories");
  const [allegroApiBody, setAllegroApiBody] = useState("{}");
  const [allegroApiResponse, setAllegroApiResponse] = useState<{ 
    status: number;
    statusText: string;
    data: unknown;
    refreshed?: boolean | undefined;
  } | null>(null);
  const [allegroApiError, setAllegroApiError] = useState<string | null>(null);
  const [allegroApiLoading, setAllegroApiLoading] = useState(false);

  const [selectedStep, setSelectedStep] = useState< 
    (TestLogEntry & { status: Exclude<TestStatus, "pending"> }) | null
  >(null);

  const [playwrightSettings, setPlaywrightSettings] = useState(
    defaultPlaywrightSettings
  );
  const [playwrightPersonas, setPlaywrightPersonas] = useState<PlaywrightPersona[]>([]);
  const [playwrightPersonasLoading, setPlaywrightPersonasLoading] = useState(true);
  const [playwrightPersonaId, setPlaywrightPersonaId] = useState<string | null>(null);

  const activeConnection = connections[0] || null;
  const sessionQuery = useConnectionSession(activeConnection?.id, {
    enabled: showSessionModal,
  });
  const sessionPayload = sessionQuery.data as
    | {
        error?: string;
        cookies?: {
          name?: string;
          value?: string;
          domain?: string;
          path?: string;
          expires?: number;
          httpOnly?: boolean;
          secure?: boolean;
          sameSite?: string;
        }[];
        origins?: { origin?: string; localStorage?: { name?: string; value?: string }[] }[];
        updatedAt?: string | null;
      }
    | null;
  const sessionCookies = sessionPayload?.cookies ?? [];
  const sessionOrigins = sessionPayload?.origins ?? [];
  const sessionUpdatedAt = sessionPayload?.updatedAt ?? null;
  const sessionError = sessionQuery.isError
    ? sessionQuery.error instanceof Error
      ? sessionQuery.error.message
      : "Failed to load session cookies."
    : sessionPayload?.error ?? null;

  useEffect(() => {
    const status = searchParams.get("allegro");
    if (!status) return;
    if (status === "connected") {
      toast("Allegro connected.", { variant: "success" });
    } else {
      const reason = searchParams.get("reason");
      const message = reason
        ? `Allegro authorization failed: ${reason}`
        : "Allegro authorization failed.";
      toast(message, { variant: "error" });
    }
    router.replace("/admin/integrations");
  }, [router, searchParams, toast]);

  useEffect(() => {
    if (!integrationsQuery.isError) return;
    const message =
      integrationsQuery.error instanceof Error
        ? integrationsQuery.error.message
        : "Failed to load integrations.";
    toast(message, { variant: "error" });
  }, [integrationsQuery.error, integrationsQuery.isError, toast]);

  useEffect(() => {
    if (!connectionsQuery.isError) return;
    const message =
      connectionsQuery.error instanceof Error
        ? connectionsQuery.error.message
        : "Failed to load connections.";
    toast(message, { variant: "error" });
  }, [connectionsQuery.error, connectionsQuery.isError, toast]);

  useEffect(() => {
    if (!activeIntegration) return;
    if (integrations.find((item: Integration) => item.id === activeIntegration.id)) return;
    setActiveIntegration(null);
  }, [activeIntegration, integrations]);

  useEffect(() => {
    if (!showPlaywrightSaved) return;
    const timeout = setTimeout(() => setShowPlaywrightSaved(false), 2500);
    return () => clearTimeout(timeout);
  }, [showPlaywrightSaved]);

  useEffect(() => {
    let active = true;
    const loadPersonas = async (): Promise<void> => {
      try {
        const stored = await fetchPlaywrightPersonas();
        if (!active) return;
        setPlaywrightPersonas(stored);
      } catch (error: unknown) {
        if (!active) return;
        const message =
          error instanceof Error ? error.message : "Failed to load personas.";
        toast(message, { variant: "error" });
      } finally {
        if (active) setPlaywrightPersonasLoading(false);
      }
    };
    void loadPersonas();
    return () => {
      active = false;
    };
  }, [toast]);

  const refreshConnections = (integrationId: string): void => {
    void queryClient.invalidateQueries({
      queryKey: ["integration-connections", integrationId],
    });
  };

  useEffect(() => {
    if (connections.length === 0) {
      setEditingConnectionId(null);
      setConnectionForm({ name: "", username: "", password: "" });
      return;
    }
    if (!editingConnectionId) {
      const connection = connections[0];
      if (!connection) return; // Guard against undefined connection

      setEditingConnectionId(connection.id);
      setConnectionForm({
        name: connection.name,
        username: connection.username,
        password: "",
      });
      setPlaywrightSettings({
        headless:
          connection.playwrightHeadless ?? defaultPlaywrightSettings.headless,
        slowMo: connection.playwrightSlowMo ?? defaultPlaywrightSettings.slowMo,
        timeout:
          connection.playwrightTimeout ?? defaultPlaywrightSettings.timeout,
        navigationTimeout:
          connection.playwrightNavigationTimeout ??
          defaultPlaywrightSettings.navigationTimeout,
        humanizeMouse:
          connection.playwrightHumanizeMouse ??
          defaultPlaywrightSettings.humanizeMouse,
        mouseJitter:
          connection.playwrightMouseJitter ??
          defaultPlaywrightSettings.mouseJitter,
        clickDelayMin:
          connection.playwrightClickDelayMin ??
          defaultPlaywrightSettings.clickDelayMin,
        clickDelayMax:
          connection.playwrightClickDelayMax ??
          defaultPlaywrightSettings.clickDelayMax,
        inputDelayMin:
          connection.playwrightInputDelayMin ??
          defaultPlaywrightSettings.inputDelayMin,
        inputDelayMax:
          connection.playwrightInputDelayMax ??
          defaultPlaywrightSettings.inputDelayMax,
        actionDelayMin:
          connection.playwrightActionDelayMin ??
          defaultPlaywrightSettings.actionDelayMin,
        actionDelayMax:
          connection.playwrightActionDelayMax ??
          defaultPlaywrightSettings.actionDelayMax,
        proxyEnabled:
          connection.playwrightProxyEnabled ??
          defaultPlaywrightSettings.proxyEnabled,
        proxyServer:
          connection.playwrightProxyServer ??
          defaultPlaywrightSettings.proxyServer,
        proxyUsername:
          connection.playwrightProxyUsername ??
          defaultPlaywrightSettings.proxyUsername,
        proxyPassword: "",
        emulateDevice:
          connection.playwrightEmulateDevice ??
          defaultPlaywrightSettings.emulateDevice,
        deviceName:
          connection.playwrightDeviceName ??
          defaultPlaywrightSettings.deviceName,
      });
    }
  }, [connections, editingConnectionId]);

  useEffect(() => {
    if (playwrightPersonas.length === 0) {
      setPlaywrightPersonaId(null);
      return;
    }
    const match = findPlaywrightPersonaMatch(
      playwrightSettings,
      playwrightPersonas
    );
    setPlaywrightPersonaId(match?.id ?? null);
  }, [playwrightPersonas, playwrightSettings]);

  const ensureIntegration = async (
    definition: (typeof integrationDefinitions)[number]
  ): Promise<Integration | null> => {
    let currentIntegrations = integrations;
    if (!currentIntegrations.length && integrationsQuery.isFetching) {
      const refreshed = await integrationsQuery.refetch();
      currentIntegrations = refreshed.data ?? integrationsQuery.data ?? [];
    }
    const existing = currentIntegrations.find(
      (integration: Integration) => integration.slug === definition.slug
    );
    if (existing) return existing;
    try {
      const created = await createIntegrationMutation.mutateAsync({
        name: definition.name,
        slug: definition.slug,
      });
      return created;
    } catch (error: unknown) {
      const message =
        error instanceof Error
          ? error.message
          : `Failed to add ${definition.name}.`;
      toast(message, { variant: "error" });
      return null;
    }
  };

  const handleIntegrationClick = async (
    definition: (typeof integrationDefinitions)[number]
  ): Promise<void> => {
    const integration = await ensureIntegration(definition);
    if (!integration) return;
    setActiveIntegration(integration);
    refreshConnections(integration.id);
    setIsModalOpen(true);
  };

  const handleSaveConnection = async (): Promise<void> => {
    if (!activeIntegration) return;
    if (!connectionForm.name.trim() || !connectionForm.username.trim()) {
      toast("Connection name and username are required.", {
        variant: "error",
      });
      return;
    }
    if (!editingConnectionId && !connectionForm.password.trim()) {
      toast("Password/Token is required.", { variant: "error" });
      return;
    }
    const payload = {
      name: connectionForm.name.trim(),
      username: connectionForm.username.trim(),
      ...(connectionForm.password.trim()
        ? { password: connectionForm.password.trim() }
        : {}),
    };
    try {
      await upsertConnectionMutation.mutateAsync({
        integrationId: activeIntegration.id,
        ...(editingConnectionId ? { connectionId: editingConnectionId } : {}),
        payload,
      });
      setConnectionForm({ name: "", username: "", password: "" });
      setEditingConnectionId(null);
    } catch (error: unknown) {
      const message =
        error instanceof Error ? error.message : "Failed to save connection.";
      toast(message, { variant: "error" });
    }
  };

  const handleAllegroAuthorize = (): void => {
    if (!activeIntegration || !activeConnection) {
      toast("Create an Allegro connection first.", { variant: "error" });
      return;
    }
    window.location.href = `/api/integrations/${activeIntegration.id}/connections/${activeConnection.id}/allegro/authorize`;
  };

  const handleAllegroDisconnect = async (): Promise<void> => {
    if (!activeIntegration || !activeConnection) return;
    try {
      const res = await fetch(
        `/api/integrations/${activeIntegration.id}/connections/${activeConnection.id}/allegro/disconnect`,
        { method: "POST" }
      );
      if (!res.ok) {
        const error = (await res.json()) as {
          error?: string;
          errorId?: string;
        };
        const message = error.error || "Failed to disconnect Allegro.";
        const suffix = error.errorId ? ` (Error ID: ${error.errorId})` : "";
        toast(`${message}${suffix}`, { variant: "error" });
        return;
      }
      toast("Allegro disconnected.", { variant: "success" });
      refreshConnections(activeIntegration.id);
    } catch (error: unknown) {
      console.error("Failed to disconnect Allegro:", error);
      toast("Failed to disconnect Allegro.", { variant: "error" });
    }
  };

  const handleDeleteConnection = async (connection: IntegrationConnection): Promise<void> => {
    const confirmed = window.confirm(`Delete connection "${connection.name}"?`);
    if (!confirmed) return;
    try {
      await deleteConnectionMutation.mutateAsync({
        integrationId: connection.integrationId,
        connectionId: connection.id,
      });
      if (editingConnectionId === connection.id) {
        setEditingConnectionId(null);
        setConnectionForm({ name: "", username: "", password: "" });
      }
    } catch (error: unknown) {
      const message =
        error instanceof Error ? error.message : "Failed to delete connection.";
      toast(message, { variant: "error" });
    }
  };

  const handleBaselinkerTest = async (connection: IntegrationConnection): Promise<void> => {
    if (!activeIntegration) return;
    setIsTesting(true);
    setTestLog([]);
    setSelectedStep(null);
    setShowTestLogModal(false);
    setShowTestErrorModal(false);
    setTestError(null);
    setTestErrorMeta(null);
    setLastTestError(null);
    setShowTestSuccessModal(false);
    setTestSuccessMessage(null);

    const requestUrl = `/api/integrations/${activeIntegration.id}/connections/${connection.id}/base/test`;
    const startedAt = performance.now();

    try {
      const res = await fetch(requestUrl, { method: "POST" });
      const contentType = res.headers.get("content-type") || "";

      let payload: TestConnectionResponse & { inventoryCount?: number };
      if (contentType.includes("application/json")) {
        payload = (await res.json()) as TestConnectionResponse & {
          inventoryCount?: number;
        };
      } else {
        payload = { error: await res.text() };
      }

      const normalizedSteps = normalizeSteps(payload.steps);

      if (!res.ok) {
        const failedStepDetail = 
          normalizedSteps.find((step: TestLogEntry) => step.status === "failed")?.detail ||
          "";

        const errorBody =
          payload.error || failedStepDetail || "No response body";
        const statusLabel = `${res.status} ${res.statusText}`.trim();
        const durationMs = Math.round(performance.now() - startedAt);

        const errorMessage = `Baselinker test failed.\nStatus: ${statusLabel}\nURL: ${requestUrl}\nDuration: ${durationMs}ms\n\nResponse:\n${errorBody}`;

        const steps: TestLogEntry[] = normalizedSteps.length
          ? normalizedSteps.map((step: TestLogEntry) =>
              step.status === "failed" && !step.detail
                ? { ...step, detail: errorMessage }
                : step
            )
          : [
              {
                step: "Connection test failed",
                status: "failed",
                timestamp: new Date().toISOString(),
                detail: errorMessage,
              },
            ];

        setTestLog(steps);
        setTestError(errorMessage);
        setTestErrorMeta({
          errorId: payload.errorId,
          integrationId: payload.integrationId,
          connectionId: payload.connectionId,
        });
        setLastTestError(errorMessage);
        setShowTestErrorModal(true);
        return;
      }

      if (normalizedSteps.length) {
        setTestLog(normalizedSteps);
      }

      const durationMs = Math.round(performance.now() - startedAt);
      const inventoryInfo = 
        payload.inventoryCount !== undefined
          ? `\nInventories found: ${payload.inventoryCount}`
          : "";
      setTestSuccessMessage(
        `Baselinker connection test succeeded.\nURL: ${requestUrl}\nDuration: ${durationMs}ms${inventoryInfo}`
      );
      setShowTestSuccessModal(true);
      setTestErrorMeta(null);
      refreshConnections(activeIntegration.id);
    } catch (error: unknown) {
      const durationMs = Math.round(performance.now() - startedAt);
      const message = error instanceof Error ? error.message : "Unknown error";
      const errorMessage = `Baselinker test failed.\nURL: ${requestUrl}\nDuration: ${durationMs}ms\nError: ${message}`;
      setTestError(errorMessage);
      setTestErrorMeta(null);
      setLastTestError(errorMessage);
      setShowTestErrorModal(true);
    } finally {
      setIsTesting(false);
    }
  };

  const handleAllegroTest = async (connection: IntegrationConnection): Promise<void> => {
    if (!activeIntegration) return;
    setIsTesting(true);
    setTestLog([]);
    setSelectedStep(null);
    setShowTestLogModal(false);
    setShowTestErrorModal(false);
    setTestError(null);
    setTestErrorMeta(null);
    setLastTestError(null);
    setShowTestSuccessModal(false);
    setTestSuccessMessage(null);

    const requestUrl = `/api/integrations/${activeIntegration.id}/connections/${connection.id}/allegro/test`;
    const startedAt = performance.now();

    try {
      const res = await fetch(requestUrl, { method: "POST" });
      const contentType = res.headers.get("content-type") || "";

      let payload: TestConnectionResponse;
      if (contentType.includes("application/json")) {
        payload = (await res.json()) as TestConnectionResponse;
      } else {
        payload = { error: await res.text() };
      }

      const normalizedSteps = normalizeSteps(payload.steps);

      if (!res.ok) {
        const failedStepDetail = 
          normalizedSteps.find((step: TestLogEntry) => step.status === "failed")?.detail ||
          "";
        const errorBody =
          payload.error || failedStepDetail || "No response body";
        const statusLabel = `${res.status} ${res.statusText}`.trim();
        const durationMs = Math.round(performance.now() - startedAt);

        const errorMessage = `Allegro connection test failed.\nStatus: ${statusLabel}\nURL: ${requestUrl}\nDuration: ${durationMs}ms\n\nResponse:\n${errorBody}`;

        const steps: TestLogEntry[] = normalizedSteps.length
          ? normalizedSteps.map((step: TestLogEntry) =>
              step.status === "failed" && !step.detail
                ? { ...step, detail: errorMessage }
                : step
            )
          : [
              {
                step: "Allegro connection test failed",
                status: "failed",
                timestamp: new Date().toISOString(),
                detail: errorMessage,
              },
            ];

        setTestLog(steps);
        setTestError(errorMessage);
        setTestErrorMeta({
          errorId: payload.errorId,
          integrationId: payload.integrationId,
          connectionId: payload.connectionId,
        });
        setLastTestError(errorMessage);
        setShowTestErrorModal(true);
        return;
      }

      if (normalizedSteps.length) {
        setTestLog(normalizedSteps);
      }

      const durationMs = Math.round(performance.now() - startedAt);
      let profileSummary = "";
      if (payload.profile && typeof payload.profile === "object") {
        const profile = payload.profile as Record<string, unknown>;
        const login = typeof profile.login === "string" ? profile.login : "";
        const name = typeof profile.name === "string" ? profile.name : "";
        const identifier = name || login;
        if (identifier) {
          profileSummary = `\nAccount: ${identifier}`;
        }
      }
      setTestSuccessMessage(
        `Allegro connection test succeeded.\nURL: ${requestUrl}\nDuration: ${durationMs}ms${profileSummary}`
      );
      setShowTestSuccessModal(true);
      setTestErrorMeta(null);
      refreshConnections(activeIntegration.id);
    } catch (error: unknown) {
      const durationMs = Math.round(performance.now() - startedAt);
      const message = error instanceof Error ? error.message : "Unknown error";
      const errorMessage = `Allegro connection test failed.\nURL: ${requestUrl}\nDuration: ${durationMs}ms\nError: ${message}`;
      setTestError(errorMessage);
      setTestErrorMeta(null);
      setLastTestError(errorMessage);
      setShowTestErrorModal(true);
    } finally {
      setIsTesting(false);
    }
  };

  const handleTestConnection = async (connection: IntegrationConnection): Promise<void> => {
    if (!activeIntegration) return;
    setIsTesting(true);
    setTestLog([]);
    setSelectedStep(null);
    setShowTestLogModal(false);
    setShowTestErrorModal(false);
    setTestError(null);
    setTestErrorMeta(null);
    setLastTestError(null);
    setShowTestSuccessModal(false);
    setTestSuccessMessage(null);

    const requestUrl = `/api/integrations/${activeIntegration.id}/connections/${connection.id}/test`;
    const startedAt = performance.now();

    try {
      const res = await fetch(requestUrl, { method: "POST" });
      const contentType = res.headers.get("content-type") || "";

      let payload: TestConnectionResponse;
      if (contentType.includes("application/json")) {
        payload = (await res.json()) as TestConnectionResponse;
      } else {
        payload = { error: await res.text() };
      }

      const normalizedSteps = normalizeSteps(payload.steps);

      if (!res.ok) {
        const failedStepDetail = 
          normalizedSteps.find((step: TestLogEntry) => step.status === "failed")?.detail ||
          "";

        const errorBody =
          payload.error || failedStepDetail || "No response body";
        const statusLabel = `${res.status} ${res.statusText}`.trim();
        const durationMs = Math.round(performance.now() - startedAt);

        const errorMessage = `Connection test failed.\nStatus: ${statusLabel}\nURL: ${requestUrl}\nDuration: ${durationMs}ms\n\nResponse:\n${errorBody}`;

        const steps: TestLogEntry[] = normalizedSteps.length
          ? normalizedSteps.map((step: TestLogEntry) =>
              step.status === "failed" && !step.detail
                ? { ...step, detail: errorMessage }
                : step
            )
          : [
              {
                step: "Connection test failed",
                status: "failed",
                timestamp: new Date().toISOString(),
                detail: errorMessage,
              },
            ];

        setTestLog(steps);
        setTestError(errorMessage);
        setTestErrorMeta({
          errorId: payload.errorId,
          integrationId: payload.integrationId,
          connectionId: payload.connectionId,
        });
        setLastTestError(errorMessage);
        setShowTestErrorModal(true);
        return;
      }

      if (normalizedSteps.length) {
        setTestLog(normalizedSteps);
      }

      const durationMs = Math.round(performance.now() - startedAt);
      setTestSuccessMessage(
        `Connection test succeeded.\nURL: ${requestUrl}\nDuration: ${durationMs}ms`
      );
      setShowTestSuccessModal(true);
      setTestErrorMeta(null);
      refreshConnections(activeIntegration.id);
    } catch (error: unknown) {
      const durationMs = Math.round(performance.now() - startedAt);
      const message = error instanceof Error ? error.message : "Unknown error";
      const errorMessage = `Connection test failed.\nURL: ${requestUrl}\nDuration: ${durationMs}ms\nError: ${message}`;
      setTestError(errorMessage);
      setTestErrorMeta(null);
      setLastTestError(errorMessage);
      setShowTestErrorModal(true);
    } finally {
      setIsTesting(false);
    }
  };

  const handleOpenSessionModal = (): void => {
    if (!activeConnection) return;
    setShowSessionModal(true);
  };

  const handleSelectPlaywrightPersona = (personaId: string | null): void => {
    if (!personaId) {
      setPlaywrightPersonaId(null);
      return;
    }
    const persona = playwrightPersonas.find((item: PlaywrightPersona) => item.id === personaId);
    if (!persona) return;
    setPlaywrightPersonaId(persona.id);
    setPlaywrightSettings(buildPlaywrightSettings(persona.settings));
    toast(`Applied persona "${persona.name}".`, { variant: "success" });
  };

  const handleSavePlaywrightSettings = async (): Promise<void> => {
    const connection = connections[0];
    if (!connection) return;

    try {
      await upsertConnectionMutation.mutateAsync({
        integrationId: activeIntegration?.id ?? connection.integrationId,
        connectionId: connection.id,
        payload: {
          name: connection.name,
          username: connection.username,
          playwrightHeadless: playwrightSettings.headless,
          playwrightSlowMo: playwrightSettings.slowMo,
          playwrightTimeout: playwrightSettings.timeout,
          playwrightNavigationTimeout: playwrightSettings.navigationTimeout,
          playwrightHumanizeMouse: playwrightSettings.humanizeMouse,
          playwrightMouseJitter: playwrightSettings.mouseJitter,
          playwrightClickDelayMin: playwrightSettings.clickDelayMin,
          playwrightClickDelayMax: playwrightSettings.clickDelayMax,
          playwrightInputDelayMin: playwrightSettings.inputDelayMin,
          playwrightInputDelayMax: playwrightSettings.inputDelayMax,
          playwrightActionDelayMin: playwrightSettings.actionDelayMin,
          playwrightActionDelayMax: playwrightSettings.actionDelayMax,
          playwrightProxyEnabled: playwrightSettings.proxyEnabled,
          playwrightProxyServer: playwrightSettings.proxyServer,
          playwrightProxyUsername: playwrightSettings.proxyUsername,
          playwrightProxyPassword: playwrightSettings.proxyPassword,
          playwrightEmulateDevice: playwrightSettings.emulateDevice,
          playwrightDeviceName: playwrightSettings.deviceName,
        },
      });
      setShowPlaywrightSaved(true);
    } catch (error: unknown) {
      const message =
        error instanceof Error
          ? error.message
          : "Failed to save Playwright settings.";
      toast(message, { variant: "error" });
    }
  };

  const handleAllegroSandboxToggle = async (value: boolean): Promise<void> => {
    if (!activeConnection) return;
    if (savingAllegroSandbox) return;
    setSavingAllegroSandbox(true);
    try {
      await upsertConnectionMutation.mutateAsync({
        integrationId: activeIntegration?.id ?? activeConnection.integrationId,
        connectionId: activeConnection.id,
        payload: {
          name: activeConnection.name,
          username: activeConnection.username,
          allegroUseSandbox: value,
        },
      });
      toast("Allegro sandbox setting updated.", { variant: "success" });
    } catch (error: unknown) {
      const message =
        error instanceof Error
          ? error.message
          : "Failed to update Allegro sandbox setting.";
      toast(message, { variant: "error" });
    } finally {
      setSavingAllegroSandbox(false);
    }
  };

  const handleAllegroSandboxConnect = async (): Promise<void> => {
    if (!activeIntegration || !activeConnection) {
      toast("Create an Allegro connection first.", { variant: "error" });
      return;
    }
    if (savingAllegroSandbox) return;
    setSavingAllegroSandbox(true);
    try {
      await upsertConnectionMutation.mutateAsync({
        integrationId: activeIntegration.id,
        connectionId: activeConnection.id,
        payload: {
          name: activeConnection.name,
          username: activeConnection.username,
          allegroUseSandbox: true,
        },
      });
      window.location.href = `/api/integrations/${activeIntegration.id}/connections/${activeConnection.id}/allegro/authorize`;
    } catch (error: unknown) {
      const message =
        error instanceof Error ? error.message : "Failed to enable Allegro sandbox.";
      toast(message, { variant: "error" });
    } finally {
      setSavingAllegroSandbox(false);
    }
  };

  const handleBaseApiRequest = async (): Promise<void> => {
    if (!activeIntegration || !activeConnection) {
      toast("Create a Base.com connection first.", { variant: "error" });
      return;
    }
    const methodInput = baseApiMethod.trim();
    const normalizedMethodKey = methodInput.toLowerCase().replace(/\s+/g, "");
    const methodAliases: Record<string, string> = {
      orderlog: "getOrdersLog",
      orderslog: "getOrdersLog",
      getorderslog: "getOrdersLog",
      detailedproductlist: "getInventoryProductsDetailed",
      detailedproducts: "getInventoryProductsDetailed",
      getinventoryproductsdetailed: "getInventoryProductsDetailed",
      detailedproduct: "getInventoryProductDetailed",
      getinventoryproductdetailed: "getInventoryProductDetailed",
      orders: "getOrders",
      getorders: "getOrders",
      inventories: "getInventories",
      getinventories: "getInventories",
      inventoryproducts: "getInventoryProductsList",
      getinventoryproductslist: "getInventoryProductsList",
      productslist: "getProductsList",
      getproductslist: "getProductsList",
      orderstatuses: "getOrderStatusList",
      getorderstatuslist: "getOrderStatusList",
    };
    const method = methodAliases[normalizedMethodKey] ?? methodInput;
    if (!method) {
      toast("Base API method is required.", { variant: "error" });
      return;
    }
    if (method !== methodInput) {
      setBaseApiMethod(method);
    }
    let params: unknown = {};
    if (baseApiParams.trim()) {
      try {
        params = JSON.parse(baseApiParams);
      } catch {
        toast("Parameters must be valid JSON.", { variant: "error" });
        return;
      }
    }
    const normalizedParams = 
      params && typeof params === "object" && !Array.isArray(params)
        ? { ...(params as Record<string, unknown>) }
        : {};
    const inventoryMethods = new Set([
      "getInventoryProductsList",
      "getInventoryProductsData",
      "getInventoryProductsDetailed",
    ]);
    const storageMethods = new Set(["getProductsList", "getProductsData"]);
    if (inventoryMethods.has(method)) {
      const inventoryValue = normalizedParams.inventory_id;
      const hasInventoryId =
        (typeof inventoryValue === "string" && inventoryValue.trim() !== "") ||
        (typeof inventoryValue === "number" && Number.isFinite(inventoryValue));
      const looksEmpty =
        !hasInventoryId || inventoryValue === 0 || inventoryValue === "0";
      if (looksEmpty && activeConnection.baseLastInventoryId) {
        normalizedParams.inventory_id = activeConnection.baseLastInventoryId;
      } else if (looksEmpty) {
        toast("Inventory ID is required. Run getInventories first.", {
          variant: "error",
        });
        return;
      }
    }
    if (storageMethods.has(method)) {
      const storageValue = normalizedParams.storage_id;
      const hasStorageId =
        (typeof storageValue === "string" && storageValue.trim() !== "") ||
        (typeof storageValue === "number" && Number.isFinite(storageValue));
      const looksEmpty =
        !hasStorageId || storageValue === 0 || storageValue === "0";
      if (looksEmpty && activeConnection.baseLastInventoryId) {
        normalizedParams.storage_id = activeConnection.baseLastInventoryId;
      } else if (looksEmpty) {
        toast("Storage ID is required. Run getInventories first.", {
          variant: "error",
        });
        return;
      }
    }
    const normalizedParamsText = JSON.stringify(normalizedParams, null, 2);
    if (normalizedParamsText !== baseApiParams) {
      setBaseApiParams(normalizedParamsText);
    }
    setBaseApiLoading(true);
    setBaseApiError(null);
    setBaseApiResponse(null);
    try {
      const res = await fetch(
        `/api/integrations/${activeIntegration.id}/connections/${activeConnection.id}/base/request`,
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ method, parameters: normalizedParams }),
        }
      );
      const payload = (await res.json()) as { error?: string; data?: unknown };
      if (!res.ok) {
        setBaseApiError(payload.error || "Request failed.");
        return;
      }
      setBaseApiResponse({ data: payload.data });
    } catch (error: unknown) {
      const message =
        error instanceof Error ? error.message : "Failed to send request.";
      setBaseApiError(message);
    } finally {
      setBaseApiLoading(false);
    }
  };

  const handleAllegroApiRequest = async (): Promise<void> => {
    if (!activeIntegration || !activeConnection) {
      toast("Select an integration connection first.", { variant: "error" });
      return;
    }
    const path = allegroApiPath.trim();
    if (!path.startsWith("/")) {
      toast("Allegro API path must start with /", { variant: "error" });
      return;
    }
    let body: unknown = undefined;
    if (allegroApiMethod !== "GET" && allegroApiBody.trim()) {
      try {
        body = JSON.parse(allegroApiBody);
      } catch {
        toast("Request body must be valid JSON.", { variant: "error" });
        return;
      }
    }
    setAllegroApiLoading(true);
    setAllegroApiError(null);
    setAllegroApiResponse(null);
    try {
      const res = await fetch(
        `/api/integrations/${activeIntegration.id}/connections/${activeConnection.id}/allegro/request`,
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            method: allegroApiMethod,
            path,
            body,
          }),
        }
      );
      const payload = (await res.json()) as {
        error?: string;
        status?: number;
        statusText?: string;
        data?: unknown;
        refreshed?: boolean;
      };
      if (!res.ok) {
        setAllegroApiError(payload.error || "Request failed.");
        return;
      }
      setAllegroApiResponse({
        status: payload.status ?? res.status,
        statusText: payload.statusText ?? "",
        data: payload.data,
        refreshed: payload.refreshed,
      });
    } catch (error: unknown) {
      const message =
        error instanceof Error ? error.message : "Failed to send request.";
      setAllegroApiError(message);
    } finally {
      setAllegroApiLoading(false);
    }
  };

  return (
    <div className="container mx-auto py-10">
      <IntegrationList
        integrations={integrations}
        onIntegrationClick={(def: (typeof integrationDefinitions)[number]): void => { void handleIntegrationClick(def); }}
      />

      {isModalOpen && activeIntegration && (
        <IntegrationModal
          activeIntegration={activeIntegration}
          connections={connections}
          onClose={(): void => setIsModalOpen(false)}
          editingConnectionId={editingConnectionId}
          setEditingConnectionId={setEditingConnectionId}
          connectionForm={connectionForm}
          setConnectionForm={setConnectionForm}
          onSaveConnection={(): void => { void handleSaveConnection(); }}
          onDeleteConnection={(c: IntegrationConnection): void => { void handleDeleteConnection(c); }}
          onTestConnection={(c: IntegrationConnection): void => { void handleTestConnection(c); }}
          onBaselinkerTest={(c: IntegrationConnection): void => { void handleBaselinkerTest(c); }}
          onAllegroTest={(c: IntegrationConnection): void => { void handleAllegroTest(c); }}
          isTesting={isTesting}
          testLog={testLog}
          onShowLog={(step: TestLogEntry): void => {
            setSelectedStep(
              step.status !== "pending"
                ? (step as TestLogEntry & { status: "ok" | "failed" })
                : null
            );
            setShowTestLogModal(true);
          }}
          showTestLogModal={showTestLogModal}
          onCloseTestLogModal={(): void => setShowTestLogModal(false)}
          selectedStep={selectedStep}
          showTestErrorModal={showTestErrorModal}
          testError={testError}
          testErrorMeta={testErrorMeta}
          onCloseTestErrorModal={(): void => setShowTestErrorModal(false)}
          showTestSuccessModal={showTestSuccessModal}
          testSuccessMessage={testSuccessMessage}
          onCloseTestSuccessModal={(): void => setShowTestSuccessModal(false)}
          showSessionModal={showSessionModal}
          sessionLoading={sessionQuery.isFetching}
          sessionError={sessionError}
          sessionCookies={sessionCookies}
          sessionOrigins={sessionOrigins}
          sessionUpdatedAt={sessionUpdatedAt}
          onCloseSessionModal={(): void => setShowSessionModal(false)}
          playwrightPersonas={playwrightPersonas}
          playwrightPersonasLoading={playwrightPersonasLoading}
          playwrightPersonaId={playwrightPersonaId}
          onSelectPlaywrightPersona={handleSelectPlaywrightPersona}
          playwrightSettings={playwrightSettings}
          setPlaywrightSettings={setPlaywrightSettings}
          onSavePlaywrightSettings={(): void => { void handleSavePlaywrightSettings(); }}
          showPlaywrightSaved={showPlaywrightSaved}
          onOpenSessionModal={(): void => { void handleOpenSessionModal(); }}
          savingAllegroSandbox={savingAllegroSandbox}
          onToggleAllegroSandbox={(v: boolean): void => { void handleAllegroSandboxToggle(v); }}
          onAllegroAuthorize={(): void => { void handleAllegroAuthorize(); }}
          onDisconnect={(): void => { void handleAllegroDisconnect(); }}
          onAllegroSandboxConnect={(): void => { void handleAllegroSandboxConnect(); }}
          baseApiMethod={baseApiMethod}
          setBaseApiMethod={setBaseApiMethod}
          baseApiParams={baseApiParams}
          setBaseApiParams={setBaseApiParams}
          baseApiLoading={baseApiLoading}
          baseApiError={baseApiError}
          baseApiResponse={baseApiResponse}
          onBaseApiRequest={(): void => { void handleBaseApiRequest(); }}
          allegroApiMethod={allegroApiMethod}
          setAllegroApiMethod={setAllegroApiMethod}
          allegroApiPath={allegroApiPath}
          setAllegroApiPath={setAllegroApiPath}
          allegroApiBody={allegroApiBody}
          setAllegroApiBody={setAllegroApiBody}
          allegroApiLoading={allegroApiLoading}
          allegroApiError={allegroApiError}
          allegroApiResponse={allegroApiResponse}
          onAllegroApiRequest={(): void => { void handleAllegroApiRequest(); }}
        />
      )}
    </div>
  );
}

