import prisma from "@/shared/lib/db/prisma";
import type { Prisma } from "@prisma/client";
import type {
  CategoryMapping,
  CategoryMappingWithDetails,
  CategoryMappingCreateInput,
  CategoryMappingUpdateInput,
} from "@/features/integrations/types/category-mapping";

export type CategoryMappingRepository = {
  create: (input: CategoryMappingCreateInput) => Promise<CategoryMapping>;
  update: (id: string, input: CategoryMappingUpdateInput) => Promise<CategoryMapping>;
  delete: (id: string) => Promise<void>;
  getById: (id: string) => Promise<CategoryMapping | null>;
  listByConnection: (connectionId: string, catalogId?: string) => Promise<CategoryMappingWithDetails[]>;
  getByExternalCategory: (
    connectionId: string,
    externalCategoryId: string,
    catalogId: string
  ) => Promise<CategoryMapping | null>;
  bulkUpsert: (
    connectionId: string,
    catalogId: string,
    mappings: { externalCategoryId: string; internalCategoryId: string }[]
  ) => Promise<number>;
  deleteByConnection: (connectionId: string) => Promise<number>;
};

function mapToRecord(record: {
  id: string;
  connectionId: string;
  externalCategoryId: string;
  internalCategoryId: string;
  catalogId: string;
  isActive: boolean;
  createdAt: Date;
  updatedAt: Date;
}): CategoryMapping {
  return {
    id: record.id,
    connectionId: record.connectionId,
    externalCategoryId: record.externalCategoryId,
    internalCategoryId: record.internalCategoryId,
    catalogId: record.catalogId,
    isActive: record.isActive,
    createdAt: record.createdAt,
    updatedAt: record.updatedAt,
  };
}

export function getCategoryMappingRepository(): CategoryMappingRepository {
  return {
    async create(input: CategoryMappingCreateInput): Promise<CategoryMapping> {
      const record = await prisma.categoryMapping.create({
        data: {
          connectionId: input.connectionId,
          externalCategoryId: input.externalCategoryId,
          internalCategoryId: input.internalCategoryId,
          catalogId: input.catalogId,
        },
      });
      return mapToRecord(record);
    },

    async update(id: string, input: CategoryMappingUpdateInput): Promise<CategoryMapping> {
      const record = await prisma.categoryMapping.update({
        where: { id },
        data: {
          ...(input.internalCategoryId !== undefined && {
            internalCategoryId: input.internalCategoryId,
          }),
          ...(input.isActive !== undefined && { isActive: input.isActive }),
        },
      });
      return mapToRecord(record);
    },

    async delete(id: string): Promise<void> {
      await prisma.categoryMapping.delete({
        where: { id },
      });
    },

    async getById(id: string): Promise<CategoryMapping | null> {
      const record = await prisma.categoryMapping.findUnique({
        where: { id },
      });
      return record ? mapToRecord(record) : null;
    },

    async listByConnection(
      connectionId: string,
      catalogId?: string
    ): Promise<CategoryMappingWithDetails[]> {
      const records = await prisma.categoryMapping.findMany({
        where: {
          connectionId,
          ...(catalogId && { catalogId }),
        },
        include: {
          externalCategory: true,
          internalCategory: true,
        },
        orderBy: [
          { externalCategory: { depth: "asc" } },
          { externalCategory: { name: "asc" } },
        ],
      });

      return records.map((r: any) => ({
        id: r.id,
        connectionId: r.connectionId,
        externalCategoryId: r.externalCategoryId,
        internalCategoryId: r.internalCategoryId,
        catalogId: r.catalogId,
        isActive: r.isActive,
        createdAt: r.createdAt,
        updatedAt: r.updatedAt,
        externalCategory: {
          id: r.externalCategory.id,
          connectionId: r.externalCategory.connectionId,
          externalId: r.externalCategory.externalId,
          name: r.externalCategory.name,
          parentExternalId: r.externalCategory.parentExternalId,
          path: r.externalCategory.path,
          depth: r.externalCategory.depth,
          isLeaf: r.externalCategory.isLeaf,
          metadata: r.externalCategory.metadata as Record<string, unknown> | null,
          fetchedAt: r.externalCategory.fetchedAt,
          createdAt: r.externalCategory.createdAt,
          updatedAt: r.externalCategory.updatedAt,
        },
        internalCategory: {
          id: r.internalCategory.id,
          name: r.internalCategory.name,
          description: r.internalCategory.description,
          color: r.internalCategory.color,
          parentId: r.internalCategory.parentId,
          catalogId: r.internalCategory.catalogId,
          createdAt: r.internalCategory.createdAt,
          updatedAt: r.internalCategory.updatedAt,
        },
      }));
    },

    async getByExternalCategory(
      connectionId: string,
      externalCategoryId: string,
      catalogId: string
    ): Promise<CategoryMapping | null> {
      const record = await prisma.categoryMapping.findUnique({
        where: {
          connectionId_externalCategoryId_catalogId: {
            connectionId,
            externalCategoryId,
            catalogId,
          },
        },
      });
      return record ? mapToRecord(record) : null;
    },

    async bulkUpsert(
      connectionId: string,
      catalogId: string,
      mappings: { externalCategoryId: string; internalCategoryId: string }[]
    ): Promise<number> {
      let count = 0;
      await prisma.$transaction(async (tx: Prisma.TransactionClient) => {
        for (const mapping of mappings) {
          await tx.categoryMapping.upsert({
            where: {
              connectionId_externalCategoryId_catalogId: {
                connectionId,
                externalCategoryId: mapping.externalCategoryId,
                catalogId,
              },
            },
            create: {
              connectionId,
              externalCategoryId: mapping.externalCategoryId,
              internalCategoryId: mapping.internalCategoryId,
              catalogId,
            },
            update: {
              internalCategoryId: mapping.internalCategoryId,
            },
          });
          count++;
        }
      });
      return count;
    },

    async deleteByConnection(connectionId: string): Promise<number> {
      const result = await prisma.categoryMapping.deleteMany({
        where: { connectionId },
      });
      return result.count;
    },
  };
}

import prisma from "@/shared/lib/db/prisma";
import type { Prisma } from "@prisma/client";
import type {
  ExternalCategory,
  ExternalCategoryWithChildren,
  ExternalCategorySyncInput,
  BaseCategory,
} from "@/features/integrations/types/category-mapping";

export type ExternalCategoryRepository = {
  syncFromBase: (connectionId: string, categories: BaseCategory[]) => Promise<number>;
  listByConnection: (connectionId: string) => Promise<ExternalCategory[]>;
  getTreeByConnection: (connectionId: string) => Promise<ExternalCategoryWithChildren[]>;
  getById: (id: string) => Promise<ExternalCategory | null>;
  getByExternalId: (connectionId: string, externalId: string) => Promise<ExternalCategory | null>;
  deleteByConnection: (connectionId: string) => Promise<number>;
};

/**
 * Builds a full path string for a category based on its parent chain.
 */
function buildCategoryPath(
  categoryId: string,
  categoriesById: Map<string, BaseCategory>
): string {
  const parts: string[] = [];
  let currentId: string | null = categoryId;
  const visited = new Set<string>();

  while (currentId && !visited.has(currentId)) {
    visited.add(currentId);
    const cat = categoriesById.get(currentId);
    if (!cat) break;
    parts.unshift(cat.name);
    currentId = cat.parentId;
  }

  return parts.join(" > ");
}

/**
 * Calculates the depth of a category in the hierarchy.
 */
function calculateDepth(
  categoryId: string,
  categoriesById: Map<string, BaseCategory>
): number {
  let depth = 0;
  let currentId: string | null = categoryId;
  const visited = new Set<string>();

  while (currentId && !visited.has(currentId)) {
    visited.add(currentId);
    const cat = categoriesById.get(currentId);
    if (!cat || !cat.parentId) break;
    depth++;
    currentId = cat.parentId;
  }

  return depth;
}

/**
 * Determines if a category is a leaf (has no children).
 */
function isLeafCategory(categoryId: string, categories: BaseCategory[]): boolean {
  return !categories.some((cat: BaseCategory) => cat.parentId === categoryId);
}

function buildTree(
  categories: ExternalCategory[],
  parentExternalId: string | null = null
): ExternalCategoryWithChildren[] {
  return categories
    .filter((cat: ExternalCategory) => cat.parentExternalId === parentExternalId)
    .map((cat: ExternalCategory) => ({
      ...cat,
      children: buildTree(categories, cat.externalId),
    }))
    .sort((a: ExternalCategoryWithChildren, b: ExternalCategoryWithChildren) => a.name.localeCompare(b.name));
}

export function getExternalCategoryRepository(): ExternalCategoryRepository {
  return {
    async syncFromBase(connectionId: string, categories: BaseCategory[]): Promise<number> {
      // Build lookup map for path calculation
      const categoriesById = new Map<string, BaseCategory>();
      for (const cat of categories) {
        categoriesById.set(cat.id, cat);
      }

      // Prepare upsert data
      const now = new Date();
      const syncInputs: ExternalCategorySyncInput[] = categories.map((cat: BaseCategory) => ({
        connectionId,
        externalId: cat.id,
        name: cat.name,
        parentExternalId: cat.parentId,
        path: buildCategoryPath(cat.id, categoriesById),
        depth: calculateDepth(cat.id, categoriesById),
        isLeaf: isLeafCategory(cat.id, categories),
      }));

      // Upsert all categories in a transaction
      let count = 0;
      await prisma.$transaction(async (tx: Prisma.TransactionClient) => {
        for (const input of syncInputs) {
          await tx.externalCategory.upsert({
            where: {
              connectionId_externalId: {
                connectionId: input.connectionId,
                externalId: input.externalId,
              },
            },
            create: {
              connectionId: input.connectionId,
              externalId: input.externalId,
              name: input.name,
              parentExternalId: input.parentExternalId,
              path: input.path,
              depth: input.depth,
              isLeaf: input.isLeaf,
              fetchedAt: now,
            },
            update: {
              name: input.name,
              parentExternalId: input.parentExternalId,
              path: input.path,
              depth: input.depth,
              isLeaf: input.isLeaf,
              fetchedAt: now,
            },
          });
          count++;
        }
      });

      return count;
    },

    async listByConnection(connectionId: string): Promise<ExternalCategory[]> {
      const records = await prisma.externalCategory.findMany({
        where: { connectionId },
        orderBy: [{ depth: "asc" }, { name: "asc" }],
      });

      return records.map((r: any) => ({
        id: r.id,
        connectionId: r.connectionId,
        externalId: r.externalId,
        name: r.name,
        parentExternalId: r.parentExternalId,
        path: r.path,
        depth: r.depth,
        isLeaf: r.isLeaf,
        metadata: r.metadata as Record<string, unknown> | null,
        fetchedAt: r.fetchedAt,
        createdAt: r.createdAt,
        updatedAt: r.updatedAt,
      }));
    },

    async getTreeByConnection(connectionId: string): Promise<ExternalCategoryWithChildren[]> {
      const records = await prisma.externalCategory.findMany({
        where: { connectionId },
        orderBy: [{ depth: "asc" }, { name: "asc" }],
      });

      const categories: ExternalCategory[] = records.map((r: any) => ({
        id: r.id,
        connectionId: r.connectionId,
        externalId: r.externalId,
        name: r.name,
        parentExternalId: r.parentExternalId,
        path: r.path,
        depth: r.depth,
        isLeaf: r.isLeaf,
        metadata: r.metadata as Record<string, unknown> | null,
        fetchedAt: r.fetchedAt,
        createdAt: r.createdAt,
        updatedAt: r.updatedAt,
      }));

      return buildTree(categories, null);
    },

    async getById(id: string): Promise<ExternalCategory | null> {
      const record = await prisma.externalCategory.findUnique({
        where: { id },
      });

      if (!record) return null;

      return {
        id: record.id,
        connectionId: record.connectionId,
        externalId: record.externalId,
        name: record.name,
        parentExternalId: record.parentExternalId,
        path: record.path,
        depth: record.depth,
        isLeaf: record.isLeaf,
        metadata: record.metadata as Record<string, unknown> | null,
        fetchedAt: record.fetchedAt,
        createdAt: record.createdAt,
        updatedAt: record.updatedAt,
      };
    },

    async getByExternalId(
      connectionId: string,
      externalId: string
    ): Promise<ExternalCategory | null> {
      const record = await prisma.externalCategory.findUnique({
        where: {
          connectionId_externalId: { connectionId, externalId },
        },
      });

      if (!record) return null;

      return {
        id: record.id,
        connectionId: record.connectionId,
        externalId: record.externalId,
        name: record.name,
        parentExternalId: record.parentExternalId,
        path: record.path,
        depth: record.depth,
        isLeaf: record.isLeaf,
        metadata: record.metadata as Record<string, unknown> | null,
        fetchedAt: record.fetchedAt,
        createdAt: record.createdAt,
        updatedAt: record.updatedAt,
      };
    },

    async deleteByConnection(connectionId: string): Promise<number> {
      const result = await prisma.externalCategory.deleteMany({
        where: { connectionId },
      });
      return result.count;
    },
  };
}

import { TestLogEntry, TestStatus } from "@/features/integrations/types/integrations-ui";

export const coerceStatus = (value: unknown): TestStatus => {
  return value === "pending" || value === "ok" || value === "failed"
    ? value
    : "failed";
};

export const normalizeSteps = (value: unknown): TestLogEntry[] => {
  if (!Array.isArray(value)) return [];
  return value.map((raw: any) => {
    const s =
      raw && typeof raw === "object"
        ? (raw as Record<string, unknown>)
        : {};
    const stepValue = s?.step;
    return {
      step:
        typeof stepValue === "string"
          ? stepValue
          : stepValue == null
            ? ""
            : typeof stepValue === "number" || typeof stepValue === "boolean"
              ? String(stepValue)
              : JSON.stringify(stepValue),
      status: coerceStatus(s?.status),
      timestamp:
        typeof s?.timestamp === "string"
          ? s.timestamp
          : new Date().toISOString(),
      ...(typeof s?.detail === "string" && { detail: s.detail }),
    };
  });
};

import {
  countryMappings,
  defaultCountries,
  defaultCurrencies,
  defaultLanguages,
} from "@/features/internationalization/lib/internationalizationDefaults";

const currencyByCode = new Map(
  defaultCurrencies.map((currency: { code: string; name: string; symbol?: string | null }) => [currency.code, currency])
);

const countryByCode = new Map(
  defaultCountries.map((country: { code: string; name: string }) => [country.code, country])
);

export const fallbackCurrencies = defaultCurrencies.map((currency: { code: string; name: string; symbol?: string | null }) => ({
  id: currency.code,
  code: currency.code,
  name: currency.name,
  symbol: currency.symbol ?? null,
}));

export const fallbackCountries = defaultCountries.map((country: { code: string; name: string }) => {
  const matchingMappings = countryMappings.filter(
    (mapping: { countryCode: string; currencyCode: string; languageCodes: string[] }) => mapping.countryCode === country.code
  );
  const currencies = matchingMappings
    .map((mapping: { currencyCode: string }) => currencyByCode.get(mapping.currencyCode))
    .filter(Boolean)
    .map((currency: any) => ({
      currencyId: currency!.code,
      currency: {
        id: currency!.code,
        code: currency!.code,
        name: currency!.name,
        symbol: currency!.symbol ?? null,
      },
    }));

  return {
    id: country.code,
    code: country.code,
    name: country.name,
    currencies,
  };
});

export const fallbackLanguages = defaultLanguages.map((language: { code: string; name: string; nativeName: string }) => {
  const matchingMappings = countryMappings.filter((mapping: { countryCode: string; currencyCode: string; languageCodes: string[] }) =>
    mapping.languageCodes.includes(language.code)
  );
  const countries = matchingMappings
    .map((mapping: { countryCode: string }) => countryByCode.get(mapping.countryCode))
    .filter(Boolean)
    .map((country: any) => ({
      countryId: country!.code,
      country: {
        id: country!.code,
        code: country!.code,
        name: country!.name,
      },
    }));

  return {
    id: language.code,
    code: language.code,
    name: language.name,
    nativeName: language.nativeName,
    countries,
  };
});

"use client";

import { Button, Input, Tabs, TabsContent, TabsList, TabsTrigger, useToast, AppModal, ModalShell, SectionHeader, SectionPanel } from "@/shared/ui";
import { Suspense, useCallback, useEffect, useMemo, useState } from "react";
import Link from "next/link";
import { useSearchParams } from "next/navigation";




import { Loader2, RefreshCcw, Trash2, XCircle, Eye } from "lucide-react";




import ProductListingJobsPanel from "@/features/jobs/components/ProductListingJobsPanel";
import type { ProductAiJob } from "@/shared/types/jobs";
import type { ProductAiJobsPanelProps } from "@/features/jobs/types/jobs-ui";

export default function ProductAiJobsPanel({
  title = "AI Jobs",
  description = "Monitor AI, import, and export jobs across the platform.",
  showTabs = true,
}: ProductAiJobsPanelProps): React.JSX.Element {
  const { toast } = useToast();
  const searchParams = useSearchParams();
  const [jobs, setJobs] = useState<ProductAiJob[]>([]);
  const [loading, setLoading] = useState(true);
  const [query, setQuery] = useState("");
  const [actionId, setActionId] = useState<string | null>(null);
  const [bulkDeleting, setBulkDeleting] = useState(false);
  const [bulkDeletingAll, setBulkDeletingAll] = useState(false);
  const [selectedJob, setSelectedJob] = useState<ProductAiJob | null>(null);

  const getPayload = (job: ProductAiJob): Record<string, unknown> | null => {
    return job.payload && typeof job.payload === "object"
      ? (job.payload as Record<string, unknown>)
      : null;
  };

  const getJobMeta = (job: ProductAiJob): any => {
    const payload = getPayload(job);
    const graph = payload?.graph as Record<string, unknown> | undefined;
    const context = payload?.context as Record<string, unknown> | undefined;
    const entityType =
      (payload?.entityType as string | undefined) ??
      (context?.entityType as string | undefined) ??
      (graph?.entityType as string | undefined);
    const entityId =
      (payload?.entityId as string | undefined) ??
      (context?.entityId as string | undefined) ??
      (payload?.productId as string | undefined) ??
      job.productId;
    const pathName = (graph?.pathName as string | undefined) ?? undefined;
    const pathId = (graph?.pathId as string | undefined) ?? undefined;
    const nodeTitle = (graph?.nodeTitle as string | undefined) ?? undefined;
    const source = (payload?.source as string | undefined) ?? undefined;
    const displayEntity =
      job.product?.name_en || job.product?.sku
        ? `${job.product?.name_en || "Untitled"} (${job.product?.sku || "N/A"})`
        : entityType || entityId
          ? `${entityType ?? "entity"} · ${entityId ?? "unknown"}`
          : "N/A";
    const subEntity = job.product?.sku
      ? `SKU: ${job.product.sku}`
      : pathName || pathId
        ? `Path: ${pathName ?? pathId}`
        : entityId
          ? `ID: ${entityId}`
          : source
            ? `Source: ${source}`
            : undefined;

    return {
      payload,
      graph,
      context,
      entityType,
      entityId,
      pathName,
      pathId,
      nodeTitle,
      source,
      displayEntity,
      subEntity,
    };
  };

  const defaultTab = useMemo((): string => {
    if (!showTabs) return "ai";
    const tab = searchParams?.get("tab") ?? "ai";
    return ["ai", "import", "export"].includes(tab) ? tab : "ai";
  }, [searchParams, showTabs]);

  const loadJobs = useCallback(async (): Promise<void> => {
    setLoading(true);
    try {
      const res = await fetch("/api/products/ai-jobs");
      if (!res.ok) throw new Error("Failed to load jobs.");
      const data = (await res.json()) as { jobs?: ProductAiJob[] };
      setJobs(data.jobs ?? []);
    } catch (error: unknown) {
      toast(error instanceof Error ? error.message : "Failed to load jobs.", { variant: "error" });
    } finally {
      setLoading(false);
    }
  }, [toast]);

  useEffect(() => {
    void loadJobs();
  }, [loadJobs]);

  useEffect(() => {
    const hasPendingJobs = jobs.some((job: ProductAiJob) => job.status === "pending" || job.status === "running");
    if (!hasPendingJobs) {
      return;
    }

    const interval = setInterval(() => void loadJobs(), 5000);
    return (): void => clearInterval(interval);
  }, [jobs, loadJobs]);

  const cancelJob = async (jobId: string): Promise<void> => {
    setActionId(jobId);
    try {
      const res = await fetch(`/api/products/ai-jobs/${jobId}`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action: "cancel" }),
      });
      if (!res.ok) throw new Error("Failed to cancel job.");
      await loadJobs();
      toast("Job canceled", { variant: "success" });
    } catch (error: unknown) {
      toast(error instanceof Error ? error.message : "Failed to cancel job.", { variant: "error" });
    } finally {
      setActionId(null);
    }
  };

  const deleteJob = async (jobId: string): Promise<void> => {
    setActionId(jobId);
    try {
      const res = await fetch(`/api/products/ai-jobs/${jobId}`, {
        method: "DELETE",
      });
      if (!res.ok) throw new Error("Failed to delete job.");
      await loadJobs();
      toast("Job deleted", { variant: "success" });
    } catch (error: unknown) {
      toast(error instanceof Error ? error.message : "Failed to delete job.", { variant: "error" });
    } finally {
      setActionId(null);
    }
  };

  const clearCompleted = async (): Promise<void> => {
    if (!window.confirm("Delete all completed jobs? This cannot be undone.")) return;
    setBulkDeleting(true);
    try {
      const res = await fetch("/api/products/ai-jobs?scope=terminal", {
        method: "DELETE",
      });
      if (!res.ok) throw new Error("Failed to delete completed jobs.");
      await loadJobs();
      toast("Jobs cleared", { variant: "success" });
    } catch (error: unknown) {
      toast(error instanceof Error ? error.message : "Failed to delete completed jobs.", { variant: "error" });
    } finally {
      setBulkDeleting(false);
    }
  };

  const clearAllJobs = async (): Promise<void> => {
    if (!window.confirm("Delete ALL AI jobs (including running/pending)?")) return;
    setBulkDeletingAll(true);
    try {
      const res = await fetch("/api/products/ai-jobs?scope=all", {
        method: "DELETE",
      });
      if (!res.ok) throw new Error("Failed to delete all jobs.");
      await loadJobs();
      toast("All jobs deleted", { variant: "success" });
    } catch (error: unknown) {
      toast(error instanceof Error ? error.message : "Failed to delete all jobs.", { variant: "error" });
    } finally {
      setBulkDeletingAll(false);
    }
  };

  const filteredJobs = jobs.filter((job: ProductAiJob) => {
    const meta = getJobMeta(job);
    return [
      job.id,
      job.status,
      job.type,
      meta.entityType,
      meta.entityId,
      meta.pathName,
      meta.pathId,
      meta.nodeTitle,
      meta.source,
      job.product?.name_en,
      job.product?.sku,
    ].some((val: string | undefined) => val?.toLowerCase().includes(query.toLowerCase()));
  });

  const aiContent = (
    <>
      <div className="flex flex-wrap items-center justify-between gap-3">
        <Input
          placeholder="Search by ID, entity, path, or model..."
          value={query}
          onChange={(e: React.ChangeEvent<HTMLInputElement>): void => setQuery(e.target.value)}
          className="max-w-md bg-gray-900 border-border text-white"
        />
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={(): void => { void loadJobs(); }} disabled={loading}>
            <RefreshCcw className={`mr-2 h-4 w-4 ${loading ? "animate-spin" : ""}`} />
            Refresh
          </Button>
          <Button variant="destructive" size="sm" onClick={(): void => { void clearCompleted(); }} disabled={bulkDeleting}>
            <Trash2 className="mr-2 h-4 w-4" />
            Clear Finished
          </Button>
          <Button variant="destructive" size="sm" onClick={(): void => { void clearAllJobs(); }} disabled={bulkDeletingAll}>
            <Trash2 className="mr-2 h-4 w-4" />
            Clear All
          </Button>
        </div>
      </div>

      <div className="rounded-lg border border-border bg-card overflow-hidden">
        <table className="w-full text-left text-sm text-gray-300">
          <thead className="bg-gray-900 text-xs uppercase text-gray-500">
            <tr>
              <th className="px-4 py-3">Entity</th>
              <th className="px-4 py-3">Type / ID</th>
              <th className="px-4 py-3">Status</th>
              <th className="px-4 py-3">Timing</th>
              <th className="px-4 py-3 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-border">
            {filteredJobs.length === 0 ? (
              <tr>
                <td colSpan={5} className="px-4 py-10 text-center text-gray-500">
                  {loading ? "Loading jobs..." : "No jobs found."}
                </td>
              </tr>
            ) : (
              filteredJobs.map((job: ProductAiJob) => {
                const meta = getJobMeta(job);
                return (
                  <tr key={job.id} className="hover:bg-card/50">
                  <td className="px-4 py-4">
                    <div className="font-medium text-white">{meta.displayEntity}</div>
                    {meta.subEntity && (
                      <div className="text-xs text-gray-500">{meta.subEntity}</div>
                    )}
                  </td>
                  <td className="px-4 py-4">
                    <div className="text-xs font-mono">{job.type}</div>
                    <div className="text-[10px] text-gray-600">{job.id}</div>
                  </td>
                  <td className="px-4 py-4">
                    <span className={`inline-flex items-center rounded-full px-2 py-0.5 text-[10px] font-medium 
                      ${job.status === "completed" ? "bg-green-500/10 text-green-400" : 
                        job.status === "failed" ? "bg-red-500/10 text-red-400" :
                        job.status === "running" ? "bg-blue-500/10 text-blue-400" :
                        job.status === "canceled" ? "bg-gray-500/10 text-gray-400" :
                        "bg-yellow-500/10 text-yellow-400"}`}>
                      {job.status.toUpperCase()}
                    </span>
                    {job.errorMessage && (
                      <div className="mt-1 max-w-[200px] truncate text-[10px] text-red-400" title={job.errorMessage}>
                        {job.errorMessage}
                      </div>
                    )}
                  </td>
                  <td className="px-4 py-4 text-xs">
                    <div>Created: {new Date(job.createdAt).toLocaleTimeString()}</div>
                    {job.finishedAt && (
                      <div className="text-gray-500">Finished: {new Date(job.finishedAt).toLocaleTimeString()}</div>
                    )}
                  </td>
                  <td className="px-4 py-4 text-right">
                    <div className="flex justify-end gap-2">
                      <Button 
                        variant="ghost" 
                        size="icon" 
                        className="h-8 w-8 text-blue-500 hover:text-blue-400"
                        onClick={(): void => setSelectedJob(job)}
                      >
                        <Eye className="h-4 w-4" />
                      </Button>
                      {(job.status === "pending" || job.status === "running") && (
                        <Button 
                          variant="ghost" 
                          size="icon" 
                          className="h-8 w-8 text-yellow-500 hover:text-yellow-400"
                          onClick={(): void => { void cancelJob(job.id); }}
                          disabled={actionId === job.id}
                        >
                          {actionId === job.id ? <Loader2 className="h-4 w-4 animate-spin" /> : <XCircle className="h-4 w-4" />}
                        </Button>
                      )}
                      <Button 
                        variant="ghost" 
                        size="icon" 
                        className="h-8 w-8 text-red-500 hover:text-red-400"
                        onClick={(): void => { void deleteJob(job.id); }}
                        disabled={actionId === job.id}
                      >
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    </div>
                  </td>
                </tr>
                );
              })
            )}
          </tbody>
        </table>
      </div>
    </>
  );

  return (
    <div className="container mx-auto py-10">
      <SectionHeader
        title={title}
        description={description}
        className="mb-6"
      />

      {showTabs ? (
        <Tabs defaultValue={defaultTab} className="space-y-6">
          <TabsList className="grid w-full grid-cols-3">
            <TabsTrigger value="ai">AI Jobs</TabsTrigger>
            <TabsTrigger value="import">Import Jobs</TabsTrigger>
            <TabsTrigger value="export">Export Jobs</TabsTrigger>
          </TabsList>

          <TabsContent value="ai" className="space-y-4">
            {aiContent}
          </TabsContent>

          <TabsContent value="import" className="space-y-4">
            <SectionPanel className="p-6">
              <h2 className="text-2xl font-bold text-white">Import Jobs</h2>
              <p className="mt-2 text-sm text-gray-400">
                Import jobs will appear here once import tracking is enabled.
              </p>
              <div className="mt-4">
                <Link href="/admin/integrations/imports" className="text-sm text-blue-400 underline">
                  Go to Imports
