                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <div className="text-[10px] uppercase text-gray-500 font-bold">Model</div>
                        <div className="text-white text-sm font-mono">
                          {(selectedJob.payload as { modelId?: string } | null)?.modelId ||
                            "Unknown"}
                        </div>
                        <div className="text-[10px] uppercase text-gray-500 font-bold mt-2">
                          Vision Enabled
                        </div>
                        <div className="text-white text-sm">
                          {(selectedJob.payload as { vision?: boolean } | null)?.vision
                            ? "Yes"
                            : "No"}
                        </div>
                      </div>
                      <div className="space-y-2">
                        <div className="text-[10px] uppercase text-gray-500 font-bold">Image URLs</div>
                        {Array.isArray(
                          (selectedJob.payload as { imageUrls?: string[] } | null)?.imageUrls
                        ) &&
                        (selectedJob.payload as { imageUrls?: string[] } | null)?.imageUrls
                          ?.length ? (
                          <div className="rounded-md bg-gray-900 p-3 text-[11px] text-gray-300 border border-border max-h-40 overflow-auto">
                            {(selectedJob.payload as { imageUrls?: string[] } | null)?.imageUrls?.map(
                              (url: string, index: number) => (
                                <div key={`${url}-${index}`} className="truncate">
                                  {url}
                                </div>
                              )
                            )}
                          </div>
                        ) : (
                          <div className="text-[11px] text-gray-500">No image URLs in payload.</div>
                        )}
                      </div>
                    </div>
                    <div className="mt-4 space-y-2">
                      <div className="text-[10px] uppercase text-gray-500 font-bold">Prompt</div>
                      <pre className="max-h-60 overflow-auto rounded-md bg-gray-900 p-3 text-[11px] text-gray-300 border border-border whitespace-pre-wrap">
                        {(selectedJob.payload as { prompt?: string } | null)?.prompt ||
                          "No prompt provided."}
                      </pre>
                    </div>
                  </div>
                )}

                {selectedJob.result && typeof selectedJob.result === 'object' && 'analysisInitial' in (selectedJob.result as object) ? (
                  <div className="space-y-4">
                    <div className="text-gray-400 font-bold text-xs uppercase mb-2">AI Processing Results</div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <div className="text-blue-400 uppercase text-[10px] font-bold">Path 1: Image Analysis (Initial)</div>
                        <div className="rounded-md bg-gray-900 p-3 text-[11px] text-gray-300 border border-border max-h-40 overflow-auto">
                          {selectedJob.result.analysisInitial || selectedJob.result.analysis || 'N/A'}
                        </div>
                      </div>

                      {selectedJob.result.analysisFinal && (
                        <div className="space-y-2">
                          <div className="text-blue-400 uppercase text-[10px] font-bold">Path 1: Image Analysis (Final)</div>
                          <div className="rounded-md bg-gray-900 p-3 text-[11px] text-gray-300 border border-border max-h-40 overflow-auto">
                            {selectedJob.result.analysisFinal}
                          </div>
                        </div>
                      )}
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <div className="text-purple-400 uppercase text-[10px] font-bold">Path 2: Description (Initial)</div>
                        <div className="rounded-md bg-gray-900 p-3 text-[11px] text-gray-300 border border-border max-h-40 overflow-auto whitespace-pre-wrap">
                          {selectedJob.result.descriptionInitial || selectedJob.result.description || 'N/A'}
                        </div>
                      </div>

                      {selectedJob.result.descriptionFinal && (
                        <div className="space-y-2">
                          <div className="text-purple-400 uppercase text-[10px] font-bold">Path 2: Description (Final)</div>
                          <div className="rounded-md bg-gray-900 p-3 text-[11px] text-gray-300 border border-border max-h-40 overflow-auto whitespace-pre-wrap">
                            {selectedJob.result.descriptionFinal}
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                ) : selectedJob.result && typeof selectedJob.result === 'object' && 'translations' in (selectedJob.result as object) ? (
                  <div className="space-y-4">
                    <div className="text-gray-400 font-bold text-xs uppercase mb-2">Translation Results</div>

                    {selectedJob.result.translationModel && (
                      <div className="rounded-md bg-card/50 border border-border p-4 mb-4">
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                          <div>
                            <div className="text-green-400 text-[10px] font-bold uppercase mb-1">Translation Model</div>
                            <div className="text-white font-mono text-sm">{selectedJob.result.translationModel}</div>
                          </div>
                          {selectedJob.result.sourceLanguage && (
                            <div>
                              <div className="text-gray-500 text-[10px] font-bold uppercase mb-1">Source Language</div>
                              <div className="text-white text-sm">{selectedJob.result.sourceLanguage}</div>
                            </div>
                          )}
                          {selectedJob.result.targetLanguages && (
                            <div>
                              <div className="text-gray-500 text-[10px] font-bold uppercase mb-1">Target Languages</div>
                              <div className="text-white text-sm">{selectedJob.result.targetLanguages.join(', ')}</div>
                            </div>
                          )}
                        </div>
                      </div>
                    )}

                    <div className="space-y-4">
                      {selectedJob.result.translations && Object.entries(selectedJob.result.translations).map(([lang, trans]: [string, any]) => (
                        <div key={lang} className="rounded-md border border-border bg-card/30 p-4">
                          <div className="text-green-400 uppercase text-[10px] font-bold mb-3">{lang}</div>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                              <div className="text-gray-500 text-[10px] font-bold uppercase mb-1">Translated Name</div>
                              <div className="text-white text-sm p-2 bg-gray-900 rounded border border-border">
                                {trans.name || 'N/A'}
                              </div>
                            </div>
                            <div>
                              <div className="text-gray-500 text-[10px] font-bold uppercase mb-1">Translated Description</div>
                              <div className="text-white text-sm p-2 bg-gray-900 rounded border border-border max-h-32 overflow-auto whitespace-pre-wrap">
                                {trans.description || 'N/A'}
                              </div>
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="space-y-2">
                      <div className="text-gray-500 uppercase text-[10px] font-bold">Payload (Input Config)</div>
                      <pre className="max-h-60 overflow-auto rounded-md bg-gray-900 p-3 text-[11px] text-gray-400 border border-border">
                        {JSON.stringify(selectedJob.payload, null, 2)}
                      </pre>
                    </div>
                    <div className="space-y-2">
                      <div className="text-gray-500 uppercase text-[10px] font-bold">Result (Output)</div>
                      <pre className="max-h-60 overflow-auto rounded-md bg-gray-900 p-3 text-[11px] text-gray-300 border border-border whitespace-pre-wrap">
                        {selectedJob.result ? JSON.stringify(selectedJob.result, null, 2) : "No result yet."}
                      </pre>
                    </div>
                  </div>
                )}

                <div className="text-[10px] text-gray-600">
                  Created: {new Date(selectedJob.createdAt).toLocaleString()} 
                  {selectedJob.startedAt && ` | Started: ${new Date(selectedJob.startedAt).toLocaleString()}`}
                  {selectedJob.finishedAt && ` | Finished: ${new Date(selectedJob.finishedAt).toLocaleString()}`}
                </div>
              </div>
          </ModalShell>
        </AppModal>
      )}
    </div>
  );
}

export function ProductAiJobsPanelSuspense(props: ProductAiJobsPanelProps): React.JSX.Element {
  return (
    <Suspense fallback={<div className="container mx-auto py-10"><div className="text-gray-400">Loading...</div></div>}>
      <ProductAiJobsPanel {...props} />
    </Suspense>
  );
}

"use client";

import { Button, ModalShell, Input, AppModal, Label, ListPanel, SectionHeader, SectionPanel } from "@/shared/ui";
import { useEffect, useState } from "react";
import Link from "next/link";
import {
  RefreshCw,
  ExternalLink,
  Clock,
  CheckCircle,
  XCircle,
  Loader2,
  Trash2,
  Eye,
} from "lucide-react";




import type { ListingJob, ListingAttempt, ProductJob } from "@/shared/types/listing-jobs";




type ProductListingJobsPanelProps = {
  showBackToProducts?: boolean;
};

type ListingRow = {
  job: ProductJob;
  listing: ListingJob;
  attempt: ListingAttempt | null;
  attemptIndex: number | null;
};

const getStatusIcon = (status: string): React.JSX.Element => {
  switch (status) {
    case "pending":
      return <Clock className="size-4 text-yellow-500" />;
    case "completed":
    case "success":
    case "listed":
      return <CheckCircle className="size-4 text-green-500" />;
    case "deleted":
    case "removed":
      return <XCircle className="size-4 text-gray-400" />;
    case "failed":
    case "error":
      return <XCircle className="size-4 text-red-500" />;
    case "processing":
    case "in_progress":
      return <Loader2 className="size-4 animate-spin text-blue-500" />;
    default:
      return <Clock className="size-4 text-gray-500" />;
  }
};

const getStatusColor = (status: string): string => {
  switch (status) {
    case "pending":
      return "bg-yellow-900/20 text-yellow-300 border-yellow-900/50";
    case "completed":
    case "success":
    case "listed":
      return "bg-green-900/20 text-green-300 border-green-900/50";
    case "deleted":
    case "removed":
      return "bg-card/40 text-gray-300 border-border";
    case "failed":
    case "error":
      return "bg-red-900/20 text-red-300 border-red-900/50";
    case "processing":
    case "in_progress":
      return "bg-blue-900/20 text-blue-300 border-blue-900/50";
    default:
      return "bg-gray-900/20 text-gray-300 border-gray-900/50";
  }
};

export default function ProductListingJobsPanel({
  showBackToProducts = true,
}: ProductListingJobsPanelProps): React.JSX.Element {
  const [jobs, setJobs] = useState<ProductJob[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [refreshing, setRefreshing] = useState(false);
  const [deleting, setDeleting] = useState<string | null>(null);
  const [query, setQuery] = useState("");
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(25);
  const [selectedListing, setSelectedListing] = useState<{
    job: ProductJob;
    listing: ListingJob;
    attempt: ListingAttempt | null;
    attemptIndex: number | null;
  } | null>(null);
  const [historyExpanded, setHistoryExpanded] = useState(false);
  const [historySort, setHistorySort] = useState<"desc" | "asc">("desc");

  const fetchJobs = async (): Promise<void> => {
    try {
      setLoading(true);
      setError(null);
      const res = await fetch("/api/integrations/jobs");
      if (!res.ok) {
        throw new Error("Failed to fetch listing jobs");
      }
      const data = (await res.json()) as ProductJob[];
      setJobs(data);
    } catch (err: unknown) {
      console.error("Failed to fetch jobs:", err);
      setError(err instanceof Error ? err.message : "Failed to fetch jobs");
    } finally {
      setLoading(false);
    }
  };

  const handleRefresh = async (): Promise<void> => {
    setRefreshing(true);
    await fetchJobs();
    setRefreshing(false);
  };

  const handleCancelListing = async (productId: string, listingId: string): Promise<void> => {
    if (!window.confirm("Cancel this listing job? This will remove it from the queue.")) {
      return;
    }

    try {
      setDeleting(listingId);
      const res = await fetch(`/api/integrations/products/${productId}/listings/${listingId}`, {
        method: "DELETE",
      });

      if (!res.ok) {
        throw new Error("Failed to cancel listing");
      }

      setJobs((prev: ProductJob[]) =>
        prev
          .map((job: ProductJob) => ({
            ...job,
            listings: job.listings.filter((l: ListingJob) => l.id !== listingId),
          }))
          .filter((job: ProductJob) => job.listings.length > 0)
      );
    } catch (err: unknown) {
      console.error("Failed to cancel listing:", err);
      setError(err instanceof Error ? err.message : "Failed to cancel listing");
    } finally {
      setDeleting(null);
    }
  };

  useEffect(() => {
    void fetchJobs();
  }, []);

  useEffect(() => {
    setHistoryExpanded(false);
    setHistorySort("desc");
  }, [selectedListing?.listing.id]);

  useEffect(() => {
    setPage(1);
  }, [query, jobs]);

  useEffect(() => {
    const hasPending = jobs.some((job: ProductJob) =>
      job.listings.some(
        (listing: ListingJob) =>
          listing.status === "pending" ||
          listing.status === "processing" ||
          listing.status === "in_progress"
      )
    );

    if (!hasPending) {
      return;
    }

    const interval = setInterval(() => {
      void fetchJobs();
    }, 10000);

    return (): void => clearInterval(interval);
  }, [jobs]);

  const formatDateTime = (value: Date | string | null): string => {
    if (!value) return "—";
    const date: Date = value instanceof Date ? value : new Date(value);
    if (Number.isNaN(date.getTime())) return "—";
    return date.toLocaleString();
  };

  const getSortedHistory = (history: ListingJob["exportHistory"]): ListingAttempt[] => {
    if (!history?.length) return [];
    const sorted = [...history].sort((a: ListingAttempt, b: ListingAttempt) => {
      const aTime: number = new Date(a.exportedAt).getTime();
      const bTime: number = new Date(b.exportedAt).getTime();
      return historySort === "asc" ? aTime - bTime : bTime - aTime;
    });
    return sorted;
  };

  const listingRows: ListingRow[] = jobs.flatMap((job: ProductJob) =>
    job.listings.flatMap((listing: ListingJob): ListingRow[] => {
      const history = listing.exportHistory ?? [];
      if (history.length === 0) {
        return [{ job, listing, attempt: null, attemptIndex: null }];
      }
      return history.map((attempt: ListingAttempt, index: number) => ({
        job,
        listing,
        attempt,
        attemptIndex: index,
      }));
    })
  );

  const filteredRows = listingRows.filter(({ job, listing, attempt }: ListingRow) => {
    if (!query.trim()) return true;
    const target = [
      job.productName,
      job.productSku ?? "",
      job.productId,
      listing.integrationName,
      listing.connectionName,
      attempt?.status ?? listing.status,
      listing.id,
      listing.externalListingId ?? "",
      attempt?.inventoryId ?? "",
      attempt?.templateId ?? "",
      attempt?.warehouseId ?? "",
      attempt?.externalListingId ?? "",
      ...(attempt?.fields ?? []),
    ]
      .join(" ")
      .toLowerCase();
    return target.includes(query.trim().toLowerCase());
  });

  const sortedRows = [...filteredRows].sort((a: ListingRow, b: ListingRow) => {
    const aTime: number = new Date(a.attempt?.exportedAt ?? a.listing.updatedAt ?? a.listing.createdAt).getTime();
    const bTime: number = new Date(b.attempt?.exportedAt ?? b.listing.updatedAt ?? b.listing.createdAt).getTime();
    return bTime - aTime;
  });
  const totalRows = sortedRows.length;
  const totalPages = Math.max(1, Math.ceil(totalRows / pageSize));
  const clampedPage = Math.min(page, totalPages);
  const startIndex = (clampedPage - 1) * pageSize;
  const endIndex = startIndex + pageSize;
  const pagedRows = sortedRows.slice(startIndex, endIndex);

  const selectedAttempt = selectedListing?.attempt ?? null;
  const selectedStatus = selectedAttempt?.status ?? selectedListing?.listing.status ?? "";

  const header = (
    <SectionHeader
      title="Export Jobs"
      description="Track product export and listing jobs across all integrations"
      size="md"
      actions={
        <>
          <Button
            onClick={() => void handleRefresh()}
            disabled={refreshing}
            variant="outline"
            size="sm"
          >
            <RefreshCw
              className={`mr-2 size-4 ${refreshing ? "animate-spin" : ""}`}
            />
            Refresh
          </Button>
          {showBackToProducts && (
            <Button asChild variant="outline" size="sm">
              <Link href="/admin/products">Back to Products</Link>
            </Button>
          )}
        </>
      }
    />
  );

  const filters = !loading && !error ? (
    <SectionPanel>
      <div className="flex flex-wrap items-center justify-between gap-3">
        <Input
          placeholder="Search by product, SKU, integration, or ID..."
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          className="h-8 text-sm sm:max-w-md"
        />
      </div>
    </SectionPanel>
  ) : null;

  const footer = !loading && !error ? (
    <div className="flex flex-wrap items-center justify-between gap-3 text-xs text-gray-400">
      <div>
        Showing {totalRows === 0 ? 0 : startIndex + 1}–{Math.min(endIndex, totalRows)} of {totalRows}
      </div>
      <div className="flex items-center gap-2">
        <Label htmlFor="exportJobsPageSize">Rows</Label>
        <select
          id="exportJobsPageSize"
          className="rounded-md border border-border bg-gray-900 px-2 py-1 text-xs text-white"
          value={pageSize}
          onChange={(event: React.ChangeEvent<HTMLSelectElement>): void => {
            setPageSize(Number(event.target.value));
            setPage(1);
          }}
        >
          {[10, 25, 50, 100].map((size: number) => (
            <option key={size} value={size}>
              {size}
            </option>
          ))}
        </select>
        <Button
          variant="outline"
          size="sm"
          onClick={(): void => setPage((current: number) => Math.max(1, current - 1))}
          disabled={clampedPage <= 1}
          className="border bg-gray-800 hover:bg-gray-700"
        >
          Prev
        </Button>
        <span className="min-w-[72px] text-center">
          {clampedPage} / {totalPages}
        </span>
        <Button
          variant="outline"
          size="sm"
          onClick={(): void => setPage((current: number) => Math.min(totalPages, current + 1))}
          disabled={clampedPage >= totalPages}
          className="border bg-gray-800 hover:bg-gray-700"
        >
          Next
        </Button>
      </div>
    </div>
  ) : null;

  return (
    <>
      <ListPanel
        header={header}
        alerts={
          error ? (
            <div className="rounded-md border border-red-500/40 bg-red-500/10 px-4 py-3 text-sm text-red-200">
              {error}
            </div>
          ) : null
        }
        filters={filters}
        footer={footer}
      >
        {loading ? (
          <div className="flex items-center justify-center py-12">
            <Loader2 className="size-8 animate-spin text-gray-500" />
          </div>
        ) : !error ? (
          <div className="rounded-lg border border-border bg-card overflow-hidden">
            <table className="w-full text-left text-sm text-gray-300">
              <thead className="bg-gray-900 text-xs uppercase text-gray-500">
                <tr>
                  <th className="px-4 py-3">Product</th>
                  <th className="px-4 py-3">Type / ID</th>
                  <th className="px-4 py-3">Status</th>
                  <th className="px-4 py-3">Timing</th>
                  <th className="px-4 py-3 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {pagedRows.length === 0 ? (
                  <tr>
                    <td colSpan={5} className="px-4 py-10 text-center text-gray-500">
                      {loading ? "Loading export jobs..." : "No export jobs found."}
                    </td>
                  </tr>
                ) : (
                  pagedRows.map(({ job, listing, attempt, attemptIndex }: ListingRow) => {
                    const status = attempt?.status ?? listing.status ?? "unknown";
                    const typeLabel =
                      status === "deleted" || status === "removed" ? "Removal" : "Export";
                    const attemptLabel =
                      attemptIndex !== null ? `Attempt ${attemptIndex + 1}` : "Listing";
                    return (
                      <tr
                        key={`${job.productId}-${listing.id}-${attemptIndex ?? "current"}`}
                        className="hover:bg-card/50"
                      >
                        <td className="px-4 py-4">
                          <div className="flex items-start gap-2">
                            <div>
                              <div className="font-medium text-white">{job.productName}</div>
                              <div className="text-xs text-gray-500">
                                SKU: {job.productSku || "N/A"}
                              </div>
                            </div>
                            <Link
                              href={`/admin/products?id=${job.productId}`}
                              className="text-blue-400 hover:text-blue-300"
                              aria-label="Open product"
                            >
                              <ExternalLink className="size-4" />
                            </Link>
                          </div>
                        </td>
                        <td className="px-4 py-4">
                          <div className="text-xs font-mono">
                            {typeLabel}: {listing.integrationName}
                          </div>
                          <div className="text-[10px] text-gray-600">
                            {attemptLabel} · {listing.id}
                          </div>
                        </td>
                        <td className="px-4 py-4">
                          <span
                            className={`inline-flex items-center gap-1 rounded-full border px-2 py-0.5 text-[10px] font-medium ${getStatusColor(
                              status
                            )}`}
                          >
                            {getStatusIcon(status)}
                            {status.toUpperCase()}
                          </span>
                        </td>
                        <td className="px-4 py-4 text-xs">
                          {attempt?.exportedAt ? (
                            <>
                              <div>Attempted: {formatDateTime(attempt.exportedAt)}</div>
                              <div className="text-gray-500">
                                Listing updated: {formatDateTime(listing.updatedAt)}
                              </div>
                            </>
                          ) : (
                            <>
                              <div>Created: {formatDateTime(listing.createdAt)}</div>
                              <div className="text-gray-500">
                                Updated: {formatDateTime(listing.updatedAt)}
                              </div>
                            </>
                          )}
                        </td>
                        <td className="px-4 py-4 text-right">
                          <div className="flex justify-end gap-2">
                            <Button
                              variant="ghost"
                              size="icon"
                              className="h-8 w-8 text-blue-500 hover:text-blue-400"
                              onClick={(): void =>
                                setSelectedListing({
                                  job,
                                  listing,
                                  attempt: attempt ?? null,
                                  attemptIndex,
                                })
                              }
                              aria-label="View export job details"
                            >
                              <Eye className="h-4 w-4" />
                            </Button>
                            {attempt === null &&
                              (listing.status === "pending" || listing.status === "failed") && (
                                <Button
                                  variant="ghost"
                                  size="icon"
                                  className="h-8 w-8 text-red-500 hover:text-red-400"
                                  onClick={(): void => { void handleCancelListing(job.productId, listing.id); }}
                                  disabled={deleting === listing.id}
                                  aria-label="Cancel export job"
                                >
                                  {deleting === listing.id ? (
                                    <Loader2 className="h-4 w-4 animate-spin" />
                                  ) : (
                                    <Trash2 className="h-4 w-4" />
                                  )}
                                </Button>
                              )}
                          </div>
                        </td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>
        ) : null}
      </ListPanel>
      {selectedListing && (
        <AppModal
          open={true}
          onOpenChange={(open: boolean): void => { if (!open) setSelectedListing(null); }}
          title="Export Job Details"
        >
          <ModalShell
            title="Export Job Details"
            onClose={(): void => setSelectedListing(null)}
            size="lg"
          >
            <div className="space-y-6 text-sm">
              <div className="grid grid-cols-2 gap-4 rounded-md bg-gray-900 p-4">
                <div>
                  <div className="text-gray-500 uppercase text-[10px] font-bold">Status</div>
                  <div className="text-white font-medium">
                    {selectedStatus || selectedListing.listing.status}
                  </div>
                </div>
                <div>
                  <div className="text-gray-500 uppercase text-[10px] font-bold">Integration</div>
                  <div className="text-white font-medium">
                    {selectedListing.listing.integrationName}
                  </div>
                </div>
                <div>
                  <div className="text-gray-500 uppercase text-[10px] font-bold">Connection</div>
                  <div className="text-white font-medium">
                    {selectedListing.listing.connectionName}
                  </div>
                </div>
                <div>
                  <div className="text-gray-500 uppercase text-[10px] font-bold">Product</div>
                  <div className="text-white font-medium">
                    {selectedListing.job.productName}
