  isEditorModeLocked?: boolean;
  isMigrating?: boolean;
  onMigrateToWysiwyg?: () => void;
  onMigrateToMarkdown?: () => void;
}

export function MarkdownToolbar({
  noteFiles,
  textColor,
  setTextColor,
  fontFamily,
  setFontFamily,
  showPreview,
  setShowPreview,
  onApplyWrap,
  onApplyLinePrefix,
  onInsertAtCursor,
  onApplyBulletList,
  onApplyChecklist,
  onApplySpanStyle,
  onInsertFileReference,
  onUndo,
  onRedo,
  canUndo = false,
  canRedo = false,
  editorMode,
  onEditorModeChange,
  isEditorModeLocked = false,
  isMigrating = false,
  onMigrateToWysiwyg,
  onMigrateToMarkdown,
