import type { CategoryWithChildren } from "@/shared/types/notes";
import { darkenColor } from "@/shared/utils/color-utils";
import { autoformatMarkdown } from "@/shared/utils/markdown-utils";

export { darkenColor, autoformatMarkdown };

export const getCategoryIdsWithDescendants = (
  targetId: string,
  categories: CategoryWithChildren[]
): string[] => {
  const collectAllDescendantIds = (node: CategoryWithChildren): string[] => {
    const ids = [node.id];
    if (node.children && node.children.length > 0) {
      for (const child of node.children) {
        ids.push(...collectAllDescendantIds(child));
      }
    }
    return ids;
  };

  const findCategory = (
    cats: CategoryWithChildren[]
  ): CategoryWithChildren | null => {
    for (const cat of cats) {
      if (cat.id === targetId) {
        return cat;
      }
      if (cat.children && cat.children.length > 0) {
        const found = findCategory(cat.children);
        if (found) return found;
      }
    }
    return null;
  };

  const targetCategory = findCategory(categories);
  if (!targetCategory) {
    return [];
  }

  return collectAllDescendantIds(targetCategory);
};

export const buildBreadcrumbPath = (
  categoryId: string | null,
  noteTitle: string | null,
  categories: CategoryWithChildren[]
) => {
  const path: Array<{ id: string | null; name: string; isNote?: boolean }> = [];

  const findPath = (
    cats: CategoryWithChildren[],
    targetId: string
  ): boolean => {
    for (const cat of cats) {
      if (cat.id === targetId) {
        path.unshift({ id: cat.id, name: cat.name });
        return true;
      }
      if (cat.children && cat.children.length > 0) {
        const found = findPath(cat.children, targetId);
        if (found) {
          path.unshift({ id: cat.id, name: cat.name });
          return true;
        }
      }
    }
    return false;
  };

  if (categoryId) {
    findPath(categories, categoryId);
  }

  if (noteTitle) {
    path.push({ id: null, name: noteTitle, isNote: true });
  }

  return path;
};

const escapeHtml = (value: string): string =>
  value
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");

const preserveSpans = (value: string) => {
  const tokens: string[] = [];

  const withTokens = value.replace(/<span\b[^>]*>[\s\S]*?<\/span>/gi, (match) => {
    const token = `__SPAN_${tokens.length}__`;

    tokens.push(match);

    return token;
  });

  return { withTokens, tokens };
};

const restoreSpans = (value: string, tokens: string[]) => {
  let restored = value;

  tokens.forEach((token, index) => {
    restored = restored.replace(`__SPAN_${index}__`, token);
  });

  return restored;
};

const renderInlineMarkdown = (value: string) => {
  const { withTokens, tokens } = preserveSpans(value);

  const escaped = escapeHtml(withTokens);

  const withCode = escaped.replace(
    /`([^`]+)`/g,
    '<code style="background-color: var(--note-inline-code-bg, rgba(15, 23, 42, 0.12)); color: var(--note-code-text, #e2e8f0); padding: 0.1rem 0.25rem; border-radius: 0.25rem; font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, \"Liberation Mono\", \"Courier New\", monospace; font-size: 0.85em;">$1</code>'
  );

  // Handle images first (before links, since syntax is similar)

  const withImages = withCode.replace(
    /!\[([^\]]*)\]\(([^)]+)\)/g,
    '<img src="$2" alt="$1" style="max-width: 100%; height: auto; border-radius: 0.5rem; margin: 0.5rem 0;" />'
  );

  const withLinks = withImages.replace(
    /\[([^\]]+)\]\(([^)]+)\)/g,
    '<a href="$2" style="color: var(--note-link-color, #38bdf8); text-decoration: underline; cursor: pointer;" target="_blank" rel="noreferrer">$1</a>'
  );

  const withStrong = withLinks.replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>");

  const withEm = withStrong.replace(/\*(.+?)\*/g, "<em>$1</em>");

  return restoreSpans(withEm, tokens);
};

const highlightCode = (value: string) => {
  let escaped = escapeHtml(value);

  escaped = escaped.replace(
    /\b(\d+(\.\d+)?)\b/g,
    '<span style="color: #fbbf24;">$1</span>'
  );

  escaped = escaped.replace(
    /\b(const|let|var|function|return|if|else|for|while|switch|case|break|continue|try|catch|finally|class|new|import|from|export|default|async|await|type|interface|extends)\b/g,
    '<span style="color: #38bdf8;">$1</span>'
  );

  return escaped;
};

export const renderMarkdownToHtml = (value: string): string => {
  const { withTokens, tokens } = preserveSpans(value);
  const lines = withTokens.split(/\r?\n/);

  let html = "";

  let inList = false;

  let inCodeBlock = false;

  let codeLines: string[] = [];

  let inTable = false;

  let tableHeaderCells: string[] = [];

  let tableRows: string[][] = [];

  const flushTable = () => {
    if (!inTable) return;

    const header = tableHeaderCells

      .map((cell) => `<th>${renderInlineMarkdown(cell.trim())}</th>`)

      .join("");

    const body = tableRows

      .map(
        (row) =>
          `<tr>${row

            .map((cell) => `<td>${renderInlineMarkdown(cell.trim())}</td>`)

            .join("")}</tr>`
      )

      .join("");

    html += `<table><thead><tr>${header}</tr></thead><tbody>${body}</tbody></table>`;

    inTable = false;

    tableHeaderCells = [];

    tableRows = [];
  };

  for (let index = 0; index < lines.length; index += 1) {
    const line = lines[index]!;

    if (line.trim().startsWith("```")) {
      flushTable();

      if (inList) {
        html += "</ul>";

        inList = false;
      }

      if (inCodeBlock) {
        const rawCode = codeLines.join("\n");

        const encoded = encodeURIComponent(rawCode);

        const highlighted = codeLines.map((codeLine) => highlightCode(codeLine)).join("\n");

        html += `<div data-code="${encoded}" style="position: relative; margin: 0.75rem 0; border: 1px solid rgba(148, 163, 184, 0.2); border-radius: 0.5rem; overflow: hidden;"><button type="button" data-copy-code="true" style="position: absolute; top: 0.5rem; right: 0.5rem; background: rgba(148, 163, 184, 0.15); border: 1px solid rgba(148, 163, 184, 0.35); color: var(--note-code-text, #e2e8f0); font-size: 0.7rem; padding: 0.2rem 0.45rem; border-radius: 0.4rem; cursor: pointer; opacity: 0; transition: opacity 0.15s ease; z-index: 10;">Copy</button><pre style="background-color: var(--note-code-bg, #0f172a); color: var(--note-code-text, #e2e8f0); padding: 0.75rem; margin: 0; overflow-x: auto;"><code style="font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, \"Liberation Mono\", \"Courier New\", monospace; font-size: 0.85em; white-space: pre;">${highlighted}</code></pre></div>`;

        codeLines = [];

        inCodeBlock = false;
      } else {
        inCodeBlock = true;

        codeLines = [];
      }

      continue;
    }

    if (inCodeBlock) {
      codeLines.push(line);

      continue;
    }

    const trimmed = line.trim();

    const headingMatch = /^(#{1,3})\s+(.+)$/.exec(trimmed);

    if (headingMatch) {
      flushTable();

      if (inList) {
        html += "</ul>";

        inList = false;
      }

      const level = headingMatch[1]!.length;

      html += `<h${level}>${renderInlineMarkdown(headingMatch[2]!)}</h${level}>`;

      continue;
    }

    if (/^---+$/.test(trimmed)) {
      flushTable();

      if (inList) {
        html += "</ul>";

        inList = false;
      }

      html += "<hr />";

      continue;
    }

    if (trimmed.startsWith(">")) {
      flushTable();

      if (inList) {
        html += "</ul>";

        inList = false;
      }

      const quoteText = trimmed.replace(/^>\s?/, "");

      html += `<blockquote>${renderInlineMarkdown(quoteText)}</blockquote>`;

      continue;
    }

    if (/\|/.test(trimmed)) {
      const nextLine = lines[index + 1] ?? "";

      const isSeparatorLine = /^\s*\|?\s*-[-\s|]*\|?\s*$/.test(trimmed);

      const isSeparatorNext = /^\s*\|?\s*-[-\s|]*\|?\s*$/.test(nextLine.trim());

      if (inTable && isSeparatorLine) {
        continue;
      }

      if (!inTable && isSeparatorNext) {
        flushTable();

        if (inList) {
          html += "</ul>";

          inList = false;
        }

        inTable = true;

        tableHeaderCells = trimmed

          .split("|")

          .filter((cell) => cell.trim().length > 0);

        continue;
      }

      if (inTable) {
        const cells = trimmed

          .split("|")

          .filter((cell) => cell.trim().length > 0);

        tableRows.push(cells);

        continue;
      }
    }

    const listMatch = /^[-*]\s+(.+)$/.exec(trimmed);

    if (listMatch) {
      flushTable();

      if (!inList) {
        html += "<ul>";

        inList = true;
      }

      const taskMatch = /^\((\s|x|X)\)\s+(.+)$/.exec(listMatch[1]!);

      if (taskMatch) {
        const checked = taskMatch[1]!.toLowerCase() === "x";

        html += `<li><input type="checkbox" disabled ${checked ? "checked" : ""} /> ${renderInlineMarkdown(taskMatch[2]!)}</li>`;
      } else {
        html += `<li>${renderInlineMarkdown(listMatch[1]!)}</li>`;
      }

      continue;
    }

    if (inList) {
      html += "</ul>";

      inList = false;
    }

    if (inTable) {
      flushTable();
    }

    if (!trimmed) {
      html += "<br />";

      continue;
    }

    html += `<p>${renderInlineMarkdown(line)}</p>`;
  }

  if (inList) {
    html += "</ul>";
  }

  if (inTable) {
    flushTable();
  }

  if (inCodeBlock) {
    const rawCode = codeLines.join("\n");

    const encoded = encodeURIComponent(rawCode);

    const highlighted = codeLines.map((codeLine) => highlightCode(codeLine)).join("\n");

    html += `<div data-code="${encoded}" style="position: relative; margin: 0.75rem 0; border: 1px solid rgba(148, 163, 184, 0.2); border-radius: 0.5rem; overflow: hidden;"><button type="button" data-copy-code="true" style="position: absolute; top: 0.5rem; right: 0.5rem; background: rgba(148, 163, 184, 0.15); border: 1px solid rgba(148, 163, 184, 0.35); color: var(--note-code-text, #e2e8f0); font-size: 0.7rem; padding: 0.2rem 0.45rem; border-radius: 0.4rem; cursor: pointer; opacity: 0; transition: opacity 0.15s ease; z-index: 10;">Copy</button><pre style="background-color: var(--note-code-bg, #0f172a); color: var(--note-code-text, #e2e8f0); padding: 0.75rem; margin: 0; overflow-x: auto;"><code style="font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, \"Liberation Mono\", \"Courier New\", monospace; font-size: 0.85em; white-space: pre;">${highlighted}</code></pre></div>`;
  }

  return restoreSpans(html, tokens);
};

"use client";

import { useEffect } from "react";
import { usePathname, useSearchParams } from "next/navigation";
import { useSession } from "next-auth/react";
import { initClientErrorReporting, setClientErrorBaseContext } from "@/features/observability/utils/client-error-logger";
import { CLIENT_LOGGING_KEYS } from "@/features/observability/constants/client-logging";
import { parseJsonSetting } from "@/shared/utils/settings-json";
import { useSettingsMap } from "@/shared/hooks/useSettings";

export default function ClientErrorReporter() {
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const { data: session } = useSession();
  const settingsQuery = useSettingsMap();

  useEffect(() => {
    initClientErrorReporting();
  }, []);

  useEffect(() => {
    if (!settingsQuery.data) return;
    const featureFlags = parseJsonSetting<Record<string, unknown> | null>(
      settingsQuery.data.get(CLIENT_LOGGING_KEYS.featureFlags),
      null
    );
    const tags = parseJsonSetting<Record<string, unknown> | null>(
      settingsQuery.data.get(CLIENT_LOGGING_KEYS.tags),
      null
    );
    setClientErrorBaseContext({
      featureFlags,
      tags,
    });
  }, [settingsQuery.data]);

  useEffect(() => {
    const context = {
      app: {
        version: process.env.NEXT_PUBLIC_APP_VERSION ?? "unknown",
        buildId: process.env.NEXT_PUBLIC_BUILD_ID ?? null,
        releaseChannel: process.env.NEXT_PUBLIC_RELEASE_CHANNEL ?? null,
        environment: process.env.NODE_ENV ?? null,
      },
      route: pathname,
      query: searchParams?.toString() ?? "",
      referrer: typeof document !== "undefined" ? document.referrer : null,
      locale: typeof navigator !== "undefined" ? navigator.language : null,
      timezone:
        typeof Intl !== "undefined"
          ? Intl.DateTimeFormat().resolvedOptions().timeZone
          : null,
      device:
        typeof navigator !== "undefined"
          ? {
              platform: navigator.platform,
              deviceMemory: (navigator as Navigator & { deviceMemory?: number }).deviceMemory ?? null,
              hardwareConcurrency: navigator.hardwareConcurrency ?? null,
            }
          : null,
      network:
        typeof navigator !== "undefined"
          ? {
              online: navigator.onLine,
              effectiveType:
                (navigator as Navigator & { connection?: { effectiveType?: string } }).connection
                  ?.effectiveType ?? null,
              downlink:
                (navigator as Navigator & { connection?: { downlink?: number } }).connection
                  ?.downlink ?? null,
              rtt:
                (navigator as Navigator & { connection?: { rtt?: number } }).connection?.rtt ??
                null,
            }
          : null,
      viewport:
        typeof window !== "undefined"
          ? { width: window.innerWidth, height: window.innerHeight }
          : null,
      featureFlags:
        typeof window !== "undefined"
          ? (window as Window & { __FEATURE_FLAGS__?: Record<string, unknown> }).__FEATURE_FLAGS__ ??
            (() => {
              try {
                const raw = window.localStorage.getItem("featureFlags");
                return raw ? (JSON.parse(raw) as Record<string, unknown>) : null;
              } catch {
                return null;
              }
            })()
          : null,
      tags:
        typeof window !== "undefined"
          ? (window as Window & { __CLIENT_LOG_TAGS__?: Record<string, unknown> })
              .__CLIENT_LOG_TAGS__ ??
            (() => {
              try {
                const raw = window.localStorage.getItem("clientLogTags");
                return raw ? (JSON.parse(raw) as Record<string, unknown>) : null;
              } catch {
                return null;
              }
            })()
          : null,
      user: session?.user
        ? {
            id: session.user.id ?? null,
            email: session.user.email ?? null,
            role: session.user.role ?? null,
          }
        : null,
    };
    setClientErrorBaseContext(context);
  }, [pathname, searchParams, session?.user, session?.user?.email, session?.user?.id, session?.user?.role]);

  return null;
}

"use client";

import { Button, Input, Select, SelectContent, SelectItem, SelectTrigger, SelectValue, useToast, Label, ListPanel, SectionHeader, SectionPanel, Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/shared/ui";
import { useCallback, useEffect, useMemo, useState } from "react";
import { useSearchParams } from "next/navigation";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";




import { RefreshCcw, Trash2, Download } from "lucide-react";
import type { SystemLogMetrics, SystemLogRecord, SystemLogLevel } from "@/shared/types/system-logs";




const levelOptions: Array<{ value: SystemLogLevel | "all"; label: string }> = [
  { value: "all", label: "All levels" },
  { value: "error", label: "Errors" },
  { value: "warn", label: "Warnings" },
  { value: "info", label: "Info" },
];

type MongoIndexInfo = {
  name?: string;
  key: Record<string, unknown>;
};

type MongoCollectionIndexStatus = {
  name: string;
  expected: MongoIndexInfo[];
  existing: MongoIndexInfo[];
  missing: MongoIndexInfo[];
  extra: MongoIndexInfo[];
  error?: string;
};

type MongoIndexDiagnostics = {
  generatedAt: string;
  collections: MongoCollectionIndexStatus[];
};

const formatTimestamp = (value: Date | string) => {
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.getTime())) return "—";
  return date.toLocaleString();
};

const formatDateParam = (value: string, endOfDay = false) => {
  if (!value) return null;
  const suffix = endOfDay ? "T23:59:59.999" : "T00:00:00.000";
  const date = new Date(`${value}${suffix}`);
  if (Number.isNaN(date.getTime())) return null;
  return date.toISOString();
};

export default function SystemLogsPage() {
  const { toast } = useToast();
  const searchParams = useSearchParams();
  const queryClient = useQueryClient();

  const [level, setLevel] = useState<SystemLogLevel | "all">(() => {
    const p = searchParams?.get("level");
    if (p && levelOptions.some((option) => option.value === p)) {
      return p as SystemLogLevel | "all";
    }
    return "all";
  });

  const [query, setQuery] = useState(() => searchParams?.get("query") ?? "");
  const [source, setSource] = useState(() => searchParams?.get("source") ?? "");

  const [fromDate, setFromDate] = useState(() => {
    const p = searchParams?.get("from");
    if (!p) return "";
    const date = new Date(p);
    return Number.isNaN(date.getTime()) ? "" : date.toISOString().slice(0, 10);
  });

  const [toDate, setToDate] = useState(() => {
    const p = searchParams?.get("to");
    if (!p) return "";
    const date = new Date(p);
    return Number.isNaN(date.getTime()) ? "" : date.toISOString().slice(0, 10);
  });

  const [page, setPage] = useState(1);
  const pageSize = 50;

  const buildLogParams = useCallback(() => {
    const params = new URLSearchParams();
    params.set("page", String(page));
    params.set("pageSize", String(pageSize));
    if (level !== "all") params.set("level", level);
    if (query.trim()) params.set("query", query.trim());
    if (source.trim()) params.set("source", source.trim());
    const from = formatDateParam(fromDate);
    const to = formatDateParam(toDate, true);
    if (from) params.set("from", from);
    if (to) params.set("to", to);
    return params;
  }, [level, page, pageSize, query, source, fromDate, toDate]);

  const buildMetricsParams = useCallback(() => {
    const params = new URLSearchParams();
    if (level !== "all") params.set("level", level);
    if (query.trim()) params.set("query", query.trim());
    if (source.trim()) params.set("source", source.trim());
    const from = formatDateParam(fromDate);
    const to = formatDateParam(toDate, true);
    if (from) params.set("from", from);
    if (to) params.set("to", to);
    return params;
  }, [level, query, source, fromDate, toDate]);

  const logsQuery = useQuery<{
    logs?: SystemLogRecord[];
    total?: number;
    page?: number;
    pageSize?: number;
  }>({
    queryKey: ["system-logs", page, pageSize, level, query, source, fromDate, toDate],
    queryFn: async () => {
      const params = buildLogParams();
      const res = await fetch(`/api/system/logs?${params.toString()}`);
      if (!res.ok) throw new Error("Failed to load system logs.");
      return (await res.json()) as {
        logs?: SystemLogRecord[];
        total?: number;
        page?: number;
        pageSize?: number;
      };
    },
  });

  const metricsQuery = useQuery<{ metrics?: SystemLogMetrics }>({
    queryKey: ["system-log-metrics", level, query, source, fromDate, toDate],
    queryFn: async () => {
      const params = buildMetricsParams();
      const res = await fetch(`/api/system/logs/metrics?${params.toString()}`);
      if (!res.ok) throw new Error("Failed to load system log metrics.");
      return (await res.json()) as { metrics?: SystemLogMetrics };
    },
  });

  const mongoDiagnosticsQuery = useQuery<MongoIndexDiagnostics>({
    queryKey: ["mongo-index-diagnostics"],
    queryFn: async () => {
      const res = await fetch("/api/system/diagnostics/mongo-indexes");
      if (!res.ok) throw new Error("Failed to load Mongo index diagnostics.");
      return (await res.json()) as MongoIndexDiagnostics;
    },
  });

  const rebuildIndexesMutation = useMutation({
    mutationFn: async () => {
      const res = await fetch("/api/system/diagnostics/mongo-indexes", {
        method: "POST",
      });
      if (!res.ok) throw new Error("Failed to rebuild Mongo indexes.");
      return (await res.json()) as MongoIndexDiagnostics & {
        created?: Array<{ collection: string; key: Record<string, unknown> }>;
      };
    },
    onSuccess: () => {
      void mongoDiagnosticsQuery.refetch();
    },
  });

  useEffect(() => {
    if (!logsQuery.error) return;
    toast(
      logsQuery.error instanceof Error
        ? logsQuery.error.message
        : "Failed to load system logs.",
      { variant: "error" }
    );
  }, [logsQuery.error, toast]);

  useEffect(() => {
    if (!metricsQuery.error) return;
    toast(
      metricsQuery.error instanceof Error
        ? metricsQuery.error.message
        : "Failed to load system log metrics.",
      { variant: "error" }
    );
  }, [metricsQuery.error, toast]);

  useEffect(() => {
    if (!mongoDiagnosticsQuery.error) return;
    toast(
      mongoDiagnosticsQuery.error instanceof Error
        ? mongoDiagnosticsQuery.error.message
        : "Failed to load Mongo diagnostics.",
      { variant: "error" }
    );
  }, [mongoDiagnosticsQuery.error, toast]);

  const logs = logsQuery.data?.logs ?? [];
  const total = logsQuery.data?.total ?? 0;
  const metrics = metricsQuery.data?.metrics ?? null;
  const diagnostics = mongoDiagnosticsQuery.data?.collections ?? [];
  const diagnosticsUpdatedAt = mongoDiagnosticsQuery.data?.generatedAt ?? null;
  const loading = logsQuery.isPending;
  const metricsLoading = metricsQuery.isPending;
  const diagnosticsLoading = mongoDiagnosticsQuery.isPending;

  const totalPages = useMemo(() => {
    return Math.max(1, Math.ceil(total / pageSize));
  }, [total, pageSize]);

  const clearLogsMutation = useMutation({
    mutationFn: async () => {
      const res = await fetch("/api/system/logs", { method: "DELETE" });
      if (!res.ok) throw new Error("Failed to clear logs.");
      return true;
    },
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: ["system-logs"] });
      void queryClient.invalidateQueries({ queryKey: ["system-log-metrics"] });
    },
  });


  const clearLogs = async () => {
    if (!window.confirm("Clear all system logs?")) return;
    try {
      await clearLogsMutation.mutateAsync();
      toast("System logs cleared.", { variant: "success" });
    } catch (error) {
      toast(error instanceof Error ? error.message : "Failed to clear logs.", {
        variant: "error",
      });
    }
  };

  const rebuildMongoIndexes = async () => {
    if (!window.confirm("Rebuild missing Mongo indexes for AI Paths runtime?")) return;
    try {
      const result = await rebuildIndexesMutation.mutateAsync();
      const createdCount = result?.created?.length ?? 0;
      toast(
        createdCount > 0
          ? `Rebuilt ${createdCount} index(es).`
          : "Mongo indexes already up to date.",
        { variant: "success" }
      );
    } catch (error) {
      toast(error instanceof Error ? error.message : "Failed to rebuild indexes.", {
        variant: "error",
      });
    }
  };

  const exportLogs = async () => {
    try {
      const payload = JSON.stringify(logs, null, 2);
      await navigator.clipboard.writeText(payload);
      toast("Logs copied to clipboard.", { variant: "success" });
    } catch (_error) {
      toast("Failed to copy logs.", { variant: "error" });
    }
  };

  const levelStyles: Record<string, string> = {
    error: "border-red-500/40 text-red-300 bg-red-500/10",
    warn: "border-yellow-500/40 text-yellow-300 bg-yellow-500/10",
    info: "border-blue-500/40 text-blue-300 bg-blue-500/10",
  };

  const getContextValue = (context: unknown, path: string) => {
    if (!context || typeof context !== "object") return null;
    return path.split(".").reduce<unknown>((acc, key) => {
      if (!acc || typeof acc !== "object") return null;
      return (acc as Record<string, unknown>)[key] ?? null;
    }, context);
  };

  const levels = metrics?.levels ?? { error: 0, warn: 0, info: 0 };

  return (
    <div className="container mx-auto py-10">
      <ListPanel
        header={
          <SectionHeader
            title="System Logs"
            description="Centralized error and warning events captured across the platform."
            actions={
              <>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => window.location.assign("/admin/settings/logging")}
                >
                  Client Logging Settings
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => {
                    void logsQuery.refetch();
                    void metricsQuery.refetch();
                  }}
                  disabled={loading || metricsLoading}
                >
                  <RefreshCcw className="mr-2 h-4 w-4" />
                  Refresh
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => void exportLogs()}
                  disabled={logs.length === 0}
                >
                  <Download className="mr-2 h-4 w-4" />
                  Copy JSON
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => void clearLogs()}
                  className="border-red-500/40 text-red-200 hover:bg-red-500/10"
                  disabled={logs.length === 0 || clearLogsMutation.isPending}
                >
                  <Trash2 className="mr-2 h-4 w-4" />
                  {clearLogsMutation.isPending ? "Clearing..." : "Clear Logs"}
                </Button>
              </>
            }
          />
        }
        alerts={
          <SectionPanel className="space-y-4">
            <div className="flex flex-wrap items-center justify-between gap-3">
              <div>
                <div className="text-lg font-semibold text-white">Diagnostics</div>
                <div className="text-xs text-gray-400">
                  Mongo index status for AI Paths runtime collections.
                </div>
              </div>
              <div className="flex items-center gap-2 text-xs text-gray-500">
                <span>
                  {diagnosticsUpdatedAt
                    ? `Updated ${formatTimestamp(diagnosticsUpdatedAt)}`
                    : "—"}
                </span>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => void mongoDiagnosticsQuery.refetch()}
                  disabled={diagnosticsLoading}
                >
                  Refresh
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => void rebuildMongoIndexes()}
                  disabled={rebuildIndexesMutation.isPending}
                  className="border-amber-500/40 text-amber-200 hover:bg-amber-500/10"
                >
                  {rebuildIndexesMutation.isPending ? "Rebuilding..." : "Rebuild missing indexes"}
                </Button>
              </div>
            </div>
            {diagnosticsLoading ? (
              <div className="text-sm text-gray-400">Loading diagnostics...</div>
            ) : diagnostics.length === 0 ? (
              <div className="text-sm text-gray-400">No diagnostics available.</div>
            ) : (
              <div className="rounded-md border border-border/70 bg-card/60">
                <Table>
                  <TableHeader>
                    <TableRow className="border-border/60">
                      <TableHead className="text-xs text-gray-400">Collection</TableHead>
                      <TableHead className="text-xs text-gray-400">Expected</TableHead>
                      <TableHead className="text-xs text-gray-400">Missing</TableHead>
                      <TableHead className="text-xs text-gray-400">Extra</TableHead>
                      <TableHead className="text-xs text-gray-400 text-right">Status</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {diagnostics.map((collection) => {
                      const missingCount = collection.missing.length;
                      const extraCount = collection.extra.length;
                      const statusLabel = collection.error
                        ? "Error"
                        : missingCount === 0
                          ? "OK"
                          : "Missing";
