import { useRouter } from "next/navigation";
import {
  createContext,
  useContext,
  useState,
  BaseSyntheticEvent,
  useRef,
  useEffect,
} from "react";
import { useQueryClient } from "@tanstack/react-query";
import {
  UseFormRegister,
  UseFormSetValue,
  UseFormGetValues,
  FieldErrors,
  FormProvider,
  useForm,
  Resolver,
} from "react-hook-form";

import type {
  CatalogRecord,
  ProductWithImages,
  PriceGroupWithDetails,
  ProductFormData,
  ProductDraft,
} from "@/features/products/types";
import type { ImageFileSelection } from "@/shared/types/files";
import type { ProductCategory, ProductTag, ProductParameter, ProductParameterValue } from "@/features/products/types";
import {
  ProductImageSlot,
} from "@/features/products/types/products-ui";
import {
  productCreateSchema,
  productUpdateSchema,
} from "@/features/products/validations";

import { useProductImages } from "@/features/products/hooks/useProductImages";
import { useProductMetadata } from "@/features/products/hooks/useProductMetadata";
import { delay } from "@/shared/utils";

interface ProductFormContextType {
  register: UseFormRegister<ProductFormData>;
  handleSubmit: (e?: BaseSyntheticEvent) => Promise<void>;
  errors: FieldErrors<ProductFormData>;
  setValue: UseFormSetValue<ProductFormData>;
  getValues: UseFormGetValues<ProductFormData>;
  imageSlots: (ProductImageSlot | null)[];
  imageLinks: string[];
  uploading: boolean;
  uploadError: string | null;
  uploadSuccess: boolean;
  showFileManager: boolean;
  setShowFileManager: (show: boolean) => void;
  handleSlotImageChange: (file: File | null, index: number) => void;
  handleSlotFileSelect: (file: ImageFileSelection | null, index: number) => void;
  handleSlotDisconnectImage: (index: number) => Promise<void>;
  handleMultiImageChange: (files: File[]) => void;
  handleMultiFileSelect: (files: ImageFileSelection[]) => void;
  swapImageSlots: (fromIndex: number, toIndex: number) => void;
  setImageLinkAt: (index: number, value: string) => void;
  setImagesReordering: (reordering: boolean) => void;
  catalogs: CatalogRecord[];
  catalogsLoading: boolean;
  catalogsError: string | null;
  selectedCatalogIds: string[];
  toggleCatalog: (catalogId: string) => void;
  categories: ProductCategory[];
  categoriesLoading: boolean;
  selectedCategoryIds: string[];
  toggleCategory: (categoryId: string) => void;
  tags: ProductTag[];
  tagsLoading: boolean;
  selectedTagIds: string[];
  toggleTag: (tagId: string) => void;
  parameters: ProductParameter[];
  parametersLoading: boolean;
  parameterValues: ProductParameterValue[];
  addParameterValue: () => void;
  updateParameterId: (index: number, parameterId: string) => void;
  updateParameterValue: (index: number, value: string) => void;
  removeParameterValue: (index: number) => void;
  filteredLanguages: Language[];
  filteredPriceGroups: PriceGroupWithDetails[];
  generationError: string | null;
  setGenerationError: (error: string | null) => void;
  product?: ProductWithImages | undefined;
}

export const ProductFormContext = createContext<ProductFormContextType | null>(
  null
);

export const useProductFormContext = () => {
  const context = useContext(ProductFormContext);
  if (!context) {
    throw new Error(
      "useProductFormContext must be used within a ProductFormProvider"
    );
  }
  return context;
};

// This context provides a centralized place for managing the state and logic of the product form.
// It handles form data, image uploads, and communication with the API.
export function ProductFormProvider({
  children,
  product,
  draft,
  onSuccess,
  onEditSave,
  requireSku,
  initialSku,
  initialCatalogId,
}: {
  children: React.ReactNode;
  product?: ProductWithImages | undefined;
  draft?: ProductDraft | null | undefined;
  onSuccess?: (() => void) | undefined;
  onEditSave?: ((saved: ProductWithImages) => void) | undefined;
  requireSku?: boolean | undefined;
  initialSku?: string | undefined;
  initialCatalogId?: string | undefined;
}) {
  const formSchema = product || requireSku ? productUpdateSchema : productCreateSchema;
  const methods = useForm<ProductFormData>({
    resolver: zodResolver(formSchema) as Resolver<ProductFormData>,
    defaultValues: {
      name_en: product?.name_en || draft?.name_en || "",
      name_pl: product?.name_pl || draft?.name_pl || "",
      name_de: product?.name_de || draft?.name_de || "",
      price: product?.price ?? draft?.price ?? 0,
      sku: product?.sku || initialSku || draft?.sku || "",
      defaultPriceGroupId:
        product?.defaultPriceGroupId ?? draft?.defaultPriceGroupId ?? undefined,
      baseProductId: product?.baseProductId ?? draft?.baseProductId ?? undefined,
      ean: product?.ean || draft?.ean || "",
      gtin: product?.gtin || draft?.gtin || "",
      asin: product?.asin || draft?.asin || "",
      description_en: product?.description_en || draft?.description_en || "",
      description_pl: product?.description_pl || draft?.description_pl || "",
      description_de: product?.description_de || draft?.description_de || "",
      supplierName: product?.supplierName || draft?.supplierName || "",
      supplierLink: product?.supplierLink || draft?.supplierLink || "",
      priceComment: product?.priceComment || draft?.priceComment || "",
      stock: product?.stock ?? draft?.stock ?? 0,
      sizeLength: product?.sizeLength ?? draft?.sizeLength ?? 0,
      sizeWidth: product?.sizeWidth ?? draft?.sizeWidth ?? 0,
      weight: product?.weight ?? draft?.weight ?? 0,
      length: product?.length ?? draft?.length ?? 0,
    },
  });
  const {
    register,
    formState: { errors },
    setValue,
    getValues,
  } = methods;
  const router = useRouter();
  const queryClient = useQueryClient();
  const [uploading, setUploading] = useState(false);
  const [uploadError, setUploadError] = useState<string | null>(null);
  const [uploadSuccess, setUploadSuccess] = useState(false);
  const successTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const [generationError, setGenerationError] = useState<string | null>(null);
  const { toast } = useToast();

  const {
    imageSlots,
    imageLinks,
    showFileManager,
    setShowFileManager,
    handleSlotImageChange,
    handleSlotFileSelect,
    handleSlotDisconnectImage,
    handleMultiImageChange,
    handleMultiFileSelect,
    swapImageSlots,
    setImageLinkAt,
    refreshFromProduct: refreshImages,
    setImagesReordering,
  } = useProductImages(product, draft?.imageLinks);

  const {
    catalogs,
    catalogsLoading,
    catalogsError,
    selectedCatalogIds,
    toggleCatalog,
    categories,
    categoriesLoading,
    selectedCategoryIds,
    toggleCategory,
    tags,
    tagsLoading,
    selectedTagIds,
    toggleTag,
    parameters,
    parametersLoading,
    filteredLanguages,
    filteredPriceGroups,
  } = useProductMetadata({
    product,
    initialCatalogId,
    initialCatalogIds: draft?.catalogIds,
    initialCategoryIds: draft?.categoryIds,
    initialTagIds: draft?.tagIds,
    setValue,
    getValues,
  });

  const normalizeParameterValues = (
    input?: ProductParameterValue[] | null
  ): ProductParameterValue[] => {
    if (!Array.isArray(input)) return [];
    return input.map((entry) => ({
      parameterId: typeof entry?.parameterId === "string" ? entry.parameterId : "",
      value: typeof entry?.value === "string" ? entry.value : "",
    }));
  };

  const [parameterValues, setParameterValues] = useState<ProductParameterValue[]>(
    () => normalizeParameterValues(product?.parameters ?? draft?.parameters ?? [])
  );

  useEffect(() => {
    setParameterValues(normalizeParameterValues(product?.parameters ?? draft?.parameters ?? []));
  }, [product?.id, draft?.id, product?.parameters, draft?.parameters]);

  useEffect(() => {
    return () => {
      if (successTimerRef.current) {
        clearTimeout(successTimerRef.current);
      }
    };
  }, []);

  const onSubmit = async (data: ProductFormData) => {
    const skuValue = typeof data.sku === "string" ? data.sku.trim() : "";
    const hasTempImages = imageSlots.some((slot) => {
      if (!slot) return false;
      if (slot.type === "file") return true;
      return slot.previewUrl.startsWith("/uploads/products/temp/");
    });

    if (!skuValue && hasTempImages) {
      const shouldContinue = window.confirm(
        "This product has images without an SKU. They will stay in the temporary folder until you set an SKU. Continue?"
      );
      if (!shouldContinue) {
        return;
      }
    }

    setUploading(true);
    setUploadError(null);
    setUploadSuccess(false);

    const formData = new FormData();
    Object.entries(data).forEach(([key, value]) => {
      if (value !== null && value !== undefined) {
        formData.append(key, typeof value === "object" ? JSON.stringify(value) : String(value));
      }
    });
    const normalizedLinks = imageLinks.map((link) => link.trim());
    formData.append("imageLinks", JSON.stringify(normalizedLinks));

    // Process image slots
    imageSlots.forEach(slot => {
      if (slot?.type === 'file') {
        formData.append("images", slot.data); // Append actual File object
      } else if (slot?.type === 'existing') {
        formData.append("imageFileIds", slot.data.id); // Append existing ImageFile ID
      }
    });
    selectedCatalogIds.forEach((catalogId) => {
      formData.append("catalogIds", catalogId);
    });
    selectedCategoryIds.forEach((categoryId) => {
      formData.append("categoryIds", categoryId);
    });
    selectedTagIds.forEach((tagId) => {
      formData.append("tagIds", tagId);
    });
    const normalizedParameters = parameterValues
      .map((entry) => ({
        parameterId: entry.parameterId?.trim(),
        value: typeof entry.value === "string" ? entry.value.trim() : "",
      }))
      .filter((entry) => entry.parameterId);
    formData.append("parameters", JSON.stringify(normalizedParameters));

    try {
      const response = await fetch(
        product ? `/api/products/${product.id}` : "/api/products",
        {
          method: product ? "PUT" : "POST",
          body: formData,
        }
      );

      if (!response.ok) {
        let errorData: { error?: string; errorId?: string } | null = null;
        try {
          errorData = (await response.json()) as {
            error?: string;
            errorId?: string;
          };
        } catch {
          errorData = null;
        }
        const message = errorData?.error || "Failed to save product";
        const errorIdSuffix = errorData?.errorId
          ? ` (Error ID: ${errorData.errorId})`
          : "";
        throw new Error(`${message}${errorIdSuffix}`);
      }

      const savedProduct = (await response.json()) as ProductWithImages;

      toast(product ? "Product updated." : "Product created.", {
        variant: "success",
      });

      // Small delay to ensure DB consistency before refetch
      await delay(500);

      // Invalidate both products list and count queries
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ["products"] }),
        queryClient.invalidateQueries({ queryKey: ["products-count"] }),
      ]);

      // Only close modal for Create mode, not Edit mode
      if (!product) {
        // For Create mode, close modal immediately without updating image state
        // This prevents the flickering caused by image slots re-rendering before modal closes
        onSuccess?.();
      } else {
        // For Edit mode, update image slots to reflect saved state
        refreshImages(savedProduct);
        setUploadSuccess(true);
        if (successTimerRef.current) {
          clearTimeout(successTimerRef.current);
        }
        successTimerRef.current = setTimeout(() => {
          setUploadSuccess(false);
        }, 3000);
        onEditSave?.(savedProduct);
        // Refresh to show updated data
        router.refresh();
      }
    } catch (error: unknown) {
      if (error instanceof Error) {
        setUploadError(error.message);
      } else {
        setUploadError("An unknown error occurred");
      }
    } finally {
      setUploading(false);
    }
  };

  return (
    <FormProvider {...methods}>
      <ProductFormContext.Provider
        value={{
          register,
          handleSubmit: methods.handleSubmit(onSubmit),
          errors,
          setValue,
          getValues,
          imageSlots,
          imageLinks,
          uploading,
          uploadError,
          uploadSuccess,
          showFileManager,
          setShowFileManager,
          handleSlotImageChange,
          handleSlotFileSelect,
          handleSlotDisconnectImage,
          handleMultiImageChange,
          handleMultiFileSelect,
          swapImageSlots,
          setImageLinkAt,
          setImagesReordering,
          catalogs,
          catalogsLoading,
          catalogsError,
          selectedCatalogIds,
          toggleCatalog,
          categories,
          categoriesLoading,
          selectedCategoryIds,
          toggleCategory,
          tags,
          tagsLoading,
          selectedTagIds,
          toggleTag,
          parameters,
          parametersLoading,
          parameterValues,
          addParameterValue: () =>
            setParameterValues((prev) => [...prev, { parameterId: "", value: "" }]),
          updateParameterId: (index, parameterId) =>
            setParameterValues((prev) => {
              const next = [...prev];
              if (!next[index]) return prev;
              next[index] = { ...next[index], parameterId };
              return next;
            }),
          updateParameterValue: (index, value) =>
            setParameterValues((prev) => {
              const next = [...prev];
              if (!next[index]) return prev;
              next[index] = { ...next[index], value };
              return next;
            }),
          removeParameterValue: (index) =>
            setParameterValues((prev) => prev.filter((_, i) => i !== index)),
          filteredLanguages,
          filteredPriceGroups,
          generationError,
          setGenerationError,
          product,
        }}
      >
        {children}
      </ProductFormContext.Provider>
    </FormProvider>
  );
}

"use client";

import { useState, useRef, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { logger } from "@/shared/utils/logger";
import type { Catalog } from "@/features/products/types";
import type { PriceGroupWithDetails } from "@/features/products/types";

type LanguageRecord = { id: string; code: string; name: string };
type LanguageOption = { value: "name_en" | "name_pl" | "name_de"; label: string };
type CurrencyRecord = { code?: string | null };

const supportedLanguageMap: Record<string, LanguageOption> = {
  EN: { value: "name_en", label: "English" },
  PL: { value: "name_pl", label: "Polish" },
  DE: { value: "name_de", label: "German" },
};

// Query keys for cache management
const catalogSyncQueryKeys = {
  catalogs: ["catalogs"] as const,
  priceGroups: ["price-groups"] as const,
  languages: ["languages"] as const,
  currencies: ["currencies"] as const,
};

// API fetch functions
async function fetchCatalogs(): Promise<Catalog[]> {
  const res = await fetch("/api/catalogs");
  if (!res.ok) {
    const payload = (await res.json()) as { error?: string };
    throw new Error(payload?.error || "Failed to load catalogs");
  }
  return res.json() as Promise<Catalog[]>;
}

async function fetchPriceGroups(): Promise<PriceGroupWithDetails[]> {
  const res = await fetch("/api/price-groups");
  if (!res.ok) {
    throw new Error("Failed to load price groups");
  }
  return res.json() as Promise<PriceGroupWithDetails[]>;
}

async function fetchLanguages(): Promise<LanguageRecord[]> {
  const res = await fetch("/api/languages");
  if (!res.ok) {
    throw new Error("Failed to load languages");
  }
  return res.json() as Promise<LanguageRecord[]>;
}

async function fetchCurrencies(): Promise<CurrencyRecord[]> {
  const res = await fetch("/api/currencies");
  if (!res.ok) {
    throw new Error("Failed to load currencies");
  }
  return res.json() as Promise<CurrencyRecord[]>;
}

export function useCatalogSync(catalogFilter: string) {
  const catalogFilterInitialized = useRef(false);

  // Parallel queries for all data sources
  const catalogsQuery = useQuery({
    queryKey: catalogSyncQueryKeys.catalogs,
    queryFn: fetchCatalogs,
    staleTime: 1000 * 60 * 5, // 5 minutes
  });

  const priceGroupsQuery = useQuery({
    queryKey: catalogSyncQueryKeys.priceGroups,
    queryFn: fetchPriceGroups,
    staleTime: 1000 * 60 * 5,
  });

  const languagesQuery = useQuery({
    queryKey: catalogSyncQueryKeys.languages,
    queryFn: fetchLanguages,
    staleTime: 1000 * 60 * 5,
  });

  const currenciesQuery = useQuery({
    queryKey: catalogSyncQueryKeys.currencies,
    queryFn: fetchCurrencies,
    staleTime: 1000 * 60 * 5,
  });

  // Log errors
  if (catalogsQuery.error) {
    logger.error("Failed to load catalogs:", catalogsQuery.error);
  }
  if (priceGroupsQuery.error) {
    logger.error("Failed to load price groups:", priceGroupsQuery.error);
  }
  if (languagesQuery.error) {
    logger.error("Failed to load languages:", languagesQuery.error);
  }
  if (currenciesQuery.error) {
    logger.error("Failed to load currencies:", currenciesQuery.error);
  }

  // Extract data with defaults
  const rawCatalogs = useMemo(() => catalogsQuery.data ?? [], [catalogsQuery.data]);
  const priceGroups = useMemo(() => priceGroupsQuery.data ?? [], [priceGroupsQuery.data]);
  const languages = useMemo(() => languagesQuery.data ?? [], [languagesQuery.data]);
  const currencyPriceGroups = priceGroups;

  // Compute allowed currency codes
  const allowedCurrencyCodes = useMemo(() => {
    const data = currenciesQuery.data ?? [];
    return data
      .map((entry) => entry.code?.trim().toUpperCase())
      .filter((code): code is string => Boolean(code));
  }, [currenciesQuery.data]);

  // Memoize catalog transformation to prevent new references
  const catalogs = useMemo(() =>
    rawCatalogs.map((catalog) => ({
      ...catalog,
      priceGroupIds: catalog.priceGroupIds ?? [],
      defaultPriceGroupId: catalog.defaultPriceGroupId ?? null,
    })),
    [rawCatalogs]
  );

  // Memoize currency options to prevent unnecessary re-renders
  const { codes, fallbackCode } = useMemo(() => {
    if (currencyPriceGroups.length === 0) return { codes: [] as string[], fallbackCode: "" };

    const isCatalogScoped = catalogFilter !== "all" && catalogFilter !== "unassigned";
    const catalog = isCatalogScoped ? catalogs.find((entry) => entry.id === catalogFilter) : undefined;
    const catalogPriceGroupIds = catalog?.priceGroupIds ?? [];
    const allowedGroupIds = catalogPriceGroupIds.length > 0 ? new Set(catalogPriceGroupIds) : null;

    const candidateGroups = allowedGroupIds
      ? currencyPriceGroups.filter((group) => allowedGroupIds.has(group.id))
      : currencyPriceGroups;

    let codes = Array.from(
      new Set(
        candidateGroups
          .map((group) => group.currency?.code)
          .filter((code): code is NonNullable<typeof code> => Boolean(code))
      )
    ).map((code) => code.trim().toUpperCase());

    const allowedSet = new Set(allowedCurrencyCodes.map((code) => code.trim().toUpperCase()));
    if (allowedSet.size > 0) {
      codes = codes.filter((code) => allowedSet.has(code));
    } else {
      // Basic safety filter if no allowed list available.
      codes = codes.filter((code) => /^[A-Z]{3,5}$/.test(code));
    }

    const defaultGroupId = catalog?.defaultPriceGroupId ?? null;
    const defaultGroup = defaultGroupId
      ? candidateGroups.find((group) => group.id === defaultGroupId)
      : candidateGroups.find((group) => group.isDefault);

    const fallbackCode = defaultGroup?.currency?.code || codes[0] || "";

    return { codes, fallbackCode };
  }, [catalogFilter, catalogs, currencyPriceGroups, allowedCurrencyCodes]);

  // Sync Currency Options based on Catalog
  const currencyOptions = codes;

  // Derived state for currencyCode to avoid set-state-in-effect
  // If the current user selection is valid for the current catalog, keep it.
  // Otherwise, fallback to the catalog's default.
  // We use a piece of state to track the user's *explicit* selection if any.
  // Note: We use 'currencyCode' state here to track the *effective* code if possible,
  // but to match the "derived" pattern we need to know if the state value is "stale".
  // Actually, the simplest way is to just let the user set a preference, and validate it on read.
  const [userCurrencyCode, setUserCurrencyCode] = useState<string | null>(null);

  const currencyCode = userCurrencyCode && codes.includes(userCurrencyCode)
    ? userCurrencyCode
    : fallbackCode;

  const setCurrencyCode = (action: string | ((prev: string) => string)) => {
    // Wrap the setter to handle functional updates correctly with the derived value
    if (typeof action === "function") {
      setUserCurrencyCode((_prev) => {
        // We use the *derived* currencyCode as the base for the update
        const newVal = action(currencyCode);
        return newVal;
      });
    } else {
      setUserCurrencyCode(action);
    }
  };

  const { languageOptions, fallbackNameLocale } = useMemo(() => {
    const options: LanguageOption[] = [];
    const isCatalogScoped = catalogFilter !== "all" && catalogFilter !== "unassigned";
    const catalog = isCatalogScoped ? catalogs.find((entry) => entry.id === catalogFilter) : undefined;
    const allowedIds = catalog?.languageIds ?? [];

    const scopedLanguages =
      allowedIds.length > 0
        ? languages.filter((lang) => allowedIds.includes(lang.id))
        : languages;

    const seen = new Set<string>();
    scopedLanguages.forEach((lang) => {
      const key = lang.code?.trim().toUpperCase();
      const option = supportedLanguageMap[key];
      if (!option || seen.has(option.value)) return;
      seen.add(option.value);
      options.push(option);
    });

    if (options.length === 0) {
      options.push(supportedLanguageMap.EN!);
      options.push(supportedLanguageMap.PL!);
      options.push(supportedLanguageMap.DE!);
    }

    const defaultLanguageId = catalog?.defaultLanguageId ?? null;
    const defaultLang = defaultLanguageId
      ? languages.find((lang) => lang.id === defaultLanguageId)
      : null;
    const defaultOption = defaultLang
      ? supportedLanguageMap[defaultLang.code?.trim().toUpperCase() || ""]
      : undefined;
    const fallbackNameLocale = defaultOption?.value ?? options[0]?.value;

    return { languageOptions: options, fallbackNameLocale };
  }, [catalogFilter, catalogs, languages]);

  return {
    catalogs,
    catalogsLoading: catalogsQuery.isLoading,
    catalogsError: catalogsQuery.error ? catalogsQuery.error.message : null,
    currencyCode,
    setCurrencyCode,
    currencyOptions,
    priceGroups,
    catalogFilterInitialized,
    languageOptions,
    fallbackNameLocale,
  };
}

