"use client";

import { useState, useEffect, useMemo, useRef } from "react";
import { PriceGroupWithDetails } from "@/features/products/types";
import { useProductsWithCount } from "@/features/products/hooks/useProductsQuery";

interface UseProductDataProps {
  refreshTrigger: number;
  initialCatalogFilter?: string;
  initialPageSize?: number;
  preferencesLoaded?: boolean;
  currencyCode?: string;
  priceGroups?: PriceGroupWithDetails[];
  searchLanguage?: string; // "name_en" | "name_pl" | "name_de" - limits search to specific language
}

/**
 * Converts a price filter value from the display currency to the base currency.
 * This allows filtering to work correctly when viewing prices in a dependent currency.
 */
function convertPriceFilterToBase(
  filterValue: number | undefined,
  currencyCode: string | undefined,
  priceGroups: PriceGroupWithDetails[] | undefined
): number | undefined {
  if (filterValue === undefined || !currencyCode || !priceGroups?.length) {
    return filterValue;
  }

  // Find the price group for the selected currency
  const targetGroup = priceGroups.find(
    (g) => g.currency?.code === currencyCode || g.currencyCode === currencyCode
  );

  if (!targetGroup) {
    return filterValue;
  }

  // If it's a dependent price group, convert back to base currency
  if (targetGroup.type === "dependent" && targetGroup.sourceGroupId) {
    const multiplier = targetGroup.priceMultiplier || 1;
    const addToPrice = targetGroup.addToPrice || 0;

    // Reverse the formula: displayPrice = basePrice * multiplier + addToPrice
    // So: basePrice = (displayPrice - addToPrice) / multiplier
    return Math.round((filterValue - addToPrice) / multiplier);
  }

  // If it's a standard/base currency, no conversion needed
  return filterValue;
}

export function useProductData({
  refreshTrigger,
  initialCatalogFilter = "all",
  initialPageSize = 24,
  preferencesLoaded = true,
  currencyCode,
  priceGroups,
  searchLanguage,
}: UseProductDataProps) {
  // Filter state
  const [search, setSearch] = useState<string>("");
  const [debouncedSearch, setDebouncedSearch] = useState<string>("");
  const [sku, setSku] = useState<string>("");
  const [debouncedSku, setDebouncedSku] = useState<string>("");
  const [minPrice, setMinPrice] = useState<number | undefined>(undefined);
  const [maxPrice, setMaxPrice] = useState<number | undefined>(undefined);
  const [startDate, setStartDate] = useState<string>("");
  const [endDate, setEndDate] = useState<string>("");
  const [catalogFilter, setCatalogFilter] = useState(initialCatalogFilter);

  // Pagination state
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(initialPageSize);

  // Track whether initial sync from preferences has completed
  const [initialSyncComplete, setInitialSyncComplete] = useState(false);

  // Sync catalogFilter and pageSize when preferences load
  // We do this during render to avoid useEffect state sync warnings
  if (preferencesLoaded && !initialSyncComplete) {
    setInitialSyncComplete(true);
    if (catalogFilter !== initialCatalogFilter) {
      setCatalogFilter(initialCatalogFilter);
    }
    if (pageSize !== initialPageSize) {
      setPageSize(initialPageSize);
    }
  }

  // Debounce search
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSearch(search);
    }, 300);
    return () => clearTimeout(timer);
  }, [search]);

  // Debounce SKU
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSku(sku);
    }, 300);
    return () => clearTimeout(timer);
  }, [sku]);

  // Reset page when filters change
  useEffect(() => {
    const t = setTimeout(() => setPage(1), 0);
    return () => clearTimeout(t);
  }, [debouncedSearch, debouncedSku, minPrice, maxPrice, startDate, endDate, catalogFilter]);

  const convertedMinPrice = useMemo(
    () => convertPriceFilterToBase(minPrice, currencyCode, priceGroups),
    [minPrice, currencyCode, priceGroups]
  );

  const convertedMaxPrice = useMemo(
    () => convertPriceFilterToBase(maxPrice, currencyCode, priceGroups),
    [maxPrice, currencyCode, priceGroups]
  );

  const filters = useMemo(
    () => ({
      search: debouncedSearch,
      sku: debouncedSku,
      minPrice: convertedMinPrice,
      maxPrice: convertedMaxPrice,
      startDate,
      endDate,
      page,
      pageSize,
      catalogId: catalogFilter === "all" ? undefined : catalogFilter,
      searchLanguage,
    }),
    [
      debouncedSearch,
      debouncedSku,
      convertedMinPrice,
      convertedMaxPrice,
      startDate,
      endDate,
      page,
      pageSize,
      catalogFilter,
      searchLanguage,
    ]
  );

  const {
    products: data,
    total,
    isLoading,
    isFetching,
    error,
    refetch,
  } = useProductsWithCount(filters, {
    enabled: preferencesLoaded && initialSyncComplete,
  });

  const lastRefreshTrigger = useRef(refreshTrigger);
  useEffect(() => {
    if (refreshTrigger > lastRefreshTrigger.current) {
      lastRefreshTrigger.current = refreshTrigger;
      void refetch();
    }
  }, [refreshTrigger, refetch]);

  const loadError = useMemo(() => {
    if (!error) return null;
    return error instanceof Error ? error.message : "Failed to load products";
  }, [error]);

  const totalPages = useMemo(() => {
    return Math.max(1, Math.ceil(total / pageSize));
  }, [total, pageSize]);

  return {
    data,
    total,
    totalPages,
    page,
    setPage,
    pageSize,
    setPageSize,
    search,
    setSearch,
    sku,
    setSku,
    minPrice,
    setMinPrice,
    maxPrice,
    setMaxPrice,
    startDate,
    setStartDate,
    endDate,
    setEndDate,
    catalogFilter,
    setCatalogFilter,
    loadError,
    isLoading,
    isFetching,
  };
}

"use client";

import { useState, useMemo, useCallback } from "react";
import { useProductsWithCount } from "@/features/products/hooks/useProductsQuery";

interface UseProductDataWithQueryProps {
  initialCatalogFilter?: string;
  initialPageSize?: number;
  preferencesLoaded?: boolean;
}

export function useProductDataWithQuery({
  initialCatalogFilter = "all",
  initialPageSize = 24,
  preferencesLoaded = true,
}: UseProductDataWithQueryProps = {}) {
  // Filter state
  const [search, setSearch] = useState<string>("");
  const [debouncedSearch, setDebouncedSearch] = useState<string>("");
  const [sku, setSku] = useState<string>("");
  const [debouncedSku, setDebouncedSku] = useState<string>("");
  const [minPrice, setMinPrice] = useState<number | undefined>(undefined);
  const [maxPrice, setMaxPrice] = useState<number | undefined>(undefined);
  const [startDate, setStartDate] = useState<string>("");
  const [endDate, setEndDate] = useState<string>("");
  const [catalogFilter, setCatalogFilter] = useState(initialCatalogFilter);

  // Pagination state
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(initialPageSize);

  // Debounce search
  useState(() => {
    const timer = setTimeout(() => {
      setDebouncedSearch(search);
      setPage(1);
    }, 300);
    return () => clearTimeout(timer);
  });

  // Debounce SKU
  useState(() => {
    const timer = setTimeout(() => {
      setDebouncedSku(sku);
      setPage(1);
    }, 300);
    return () => clearTimeout(timer);
  });

  const filters = useMemo(
    () => ({
      search: debouncedSearch,
      sku: debouncedSku,
      minPrice,
      maxPrice,
      startDate,
      endDate,
      page,
      pageSize,
      catalogId: catalogFilter === "all" ? undefined : catalogFilter,
    }),
    [debouncedSearch, debouncedSku, minPrice, maxPrice, startDate, endDate, page, pageSize, catalogFilter]
  );

  const { products, total, isLoading, isFetching, error, refetch } = useProductsWithCount(filters, {
    enabled: preferencesLoaded,
  });

  const totalPages = useMemo(() => {
    return Math.max(1, Math.ceil(total / pageSize));
  }, [total, pageSize]);

  const resetFilters = useCallback(() => {
    setSearch("");
    setDebouncedSearch("");
    setSku("");
    setDebouncedSku("");
    setMinPrice(undefined);
    setMaxPrice(undefined);
    setStartDate("");
    setEndDate("");
    setPage(1);
  }, []);

  return {
    data: products,
    total,
    totalPages,
    page,
    setPage,
    pageSize,
    setPageSize,
    search,
    setSearch,
    sku,
    setSku,
    minPrice,
    setMinPrice,
    maxPrice,
    setMaxPrice,
    startDate,
    setStartDate,
    endDate,
    setEndDate,
    catalogFilter,
    setCatalogFilter,
    isLoading,
    isFetching,
    error: error ? (error instanceof Error ? error.message : "Failed to load products") : null,
    refetch,
    resetFilters,
  };
}

import { useState, useCallback, useRef, useEffect } from "react";
import type { ProductWithImages } from "@/features/products/types";
import type { ImageFileSelection } from "@/shared/types/files";
import type { ProductImageSlot } from "@/features/products/types/products-ui";

const TOTAL_IMAGE_SLOTS = 15;

const normalizeImageLinks = (links?: string[] | null): string[] => {
  const next: string[] = new Array<string>(TOTAL_IMAGE_SLOTS).fill("");
  if (Array.isArray(links)) {
    links.slice(0, TOTAL_IMAGE_SLOTS).forEach((link, index) => {
      next[index] = typeof link === "string" ? link : "";
    });
  }
  return next;
};

const buildImageSlotsFromProduct = (product?: ProductWithImages): (ProductImageSlot | null)[] => {
  const slots: (ProductImageSlot | null)[] = Array.from(
    { length: TOTAL_IMAGE_SLOTS },
    () => null
  );
  if (!product?.images?.length) return slots;
  product.images.slice(0, TOTAL_IMAGE_SLOTS).forEach((pImg, index) => {
    if (pImg.imageFile) {
      slots[index] = {
        type: "existing",
        data: pImg.imageFile as ImageFileSelection,
        previewUrl: pImg.imageFile.filepath,
        slotId: pImg.imageFile.id,
      };
    }
  });
  return slots;
};

const createSlotId = () =>
  typeof crypto !== "undefined" && "randomUUID" in crypto
    ? crypto.randomUUID()
    : `${Date.now()}-${Math.random().toString(16).slice(2)}`;

export function useProductImages(
  product?: ProductWithImages,
  initialImageLinks?: string[] | null
) {
  const [imageSlots, setImageSlots] = useState<(ProductImageSlot | null)[]>(
    () => buildImageSlotsFromProduct(product)
  );
  const [imageLinks, setImageLinks] = useState<string[]>(
    () => normalizeImageLinks(product?.imageLinks ?? initialImageLinks)
  );
  const [showFileManager, setShowFileManager] = useState(false);
  const objectUrlsRef = useRef<string[]>([]);
  const isReorderingRef = useRef(false);
  const pendingRefreshRef = useRef<ProductWithImages | null>(null);

  // Effect to clean up object URLs when component unmounts or imageSlots change
  useEffect(() => {
    const currentObjectUrls = imageSlots.map(slot =>
      slot?.type === 'file' ? slot.previewUrl : null
    ).filter(Boolean) as string[];

    // Revoke old object URLs that are no longer in use
    const oldObjectUrls = objectUrlsRef.current.filter(url => !currentObjectUrls.includes(url));
    oldObjectUrls.forEach(url => URL.revokeObjectURL(url));

    // Update ref with current object URLs
    objectUrlsRef.current = currentObjectUrls;

    return () => {
      // Clean up all object URLs on unmount
      objectUrlsRef.current.forEach(url => URL.revokeObjectURL(url));
      objectUrlsRef.current = [];
    };
  }, [imageSlots]);

  const handleSlotImageChange = useCallback((file: File | null, index: number) => {
    setImageSlots((prevSlots) => {
      const newSlots = [...prevSlots];
      if (file) {
        // Revoke existing object URL if replacing an image
        const existingSlot = newSlots[index];
        if (existingSlot?.type === "file") {
          URL.revokeObjectURL(existingSlot.previewUrl);
        }
        newSlots[index] = {
          type: "file",
          data: file,
          previewUrl: URL.createObjectURL(file),
          slotId: createSlotId(),
        };
      } else {
        // Revoke object URL if clearing the slot
        const existingSlot = newSlots[index];
        if (existingSlot?.type === "file") {
          URL.revokeObjectURL(existingSlot.previewUrl);
        }
        newSlots[index] = null;
      }
      return newSlots;
    });
  }, []);

  const handleSlotFileSelect = useCallback((file: ImageFileSelection | null, index: number) => {
    setImageSlots((prevSlots) => {
      const newSlots = [...prevSlots];
      if (file) {
         // Revoke object URL if replacing a file upload with an existing file
         const existingSlot = newSlots[index];
         if (existingSlot?.type === "file") {
          URL.revokeObjectURL(existingSlot.previewUrl);
        }
        newSlots[index] = {
          type: "existing",
          data: file,
          previewUrl: file.filepath,
          slotId: file.id,
        };
      } else {
        // Revoke object URL if clearing the slot
        const existingSlot = newSlots[index];
        if (existingSlot?.type === "file") {
          URL.revokeObjectURL(existingSlot.previewUrl);
        }
        newSlots[index] = null;
      }
      return newSlots;
    });
    setShowFileManager(false);
  }, []);

  const handleSlotDisconnectImage = useCallback(async (index: number) => {
    const slotToClear = imageSlots[index];
    if (!slotToClear) return;

    setImageSlots(prevSlots => {
      const newSlots = [...prevSlots];
      newSlots[index] = null;
      return newSlots;
    });

    if (slotToClear.type === 'existing' && product?.id) {
      try {
        const res = await fetch(`/api/products/${product.id}/images/${slotToClear.data.id}`, {
          method: "DELETE",
        });

        if (!res.ok) {
          const payload = (await res.json()) as { error?: string; errorId?: string };
          console.error("Failed to disconnect image from product:", {
            error: payload?.error,
            errorId: payload?.errorId,
            productId: product.id,
            imageFileId: slotToClear.data.id,
          });
        }
      } catch (error) {
        console.error("Failed to disconnect image from product:", error);
      }
    } else if (slotToClear.type === 'file') {
      URL.revokeObjectURL(slotToClear.previewUrl);
    }
  }, [imageSlots, product]);

  const setImageLinkAt = useCallback((index: number, value: string) => {
    setImageLinks((prev) => {
      const next = [...prev];
      if (index < 0 || index >= next.length) return prev;
      next[index] = value;
      return next;
    });
  }, []);

  const handleMultiImageChange = useCallback((files: File[]) => {
    setImageSlots((prevSlots) => {
      const newSlots = [...prevSlots];
      let fileIndex = 0;
      for (let i = 0; i < TOTAL_IMAGE_SLOTS && fileIndex < files.length; i++) {
        if (newSlots[i] === null) {
          const file = files[fileIndex];
          if (file) {
            newSlots[i] = {
              type: "file",
              data: file,
              previewUrl: URL.createObjectURL(file),
              slotId: createSlotId(),
            };
          }
          fileIndex++;
        }
      }
      return newSlots;
    });
  }, []);

  const handleMultiFileSelect = useCallback((files: ImageFileSelection[]) => {
    setImageSlots((prevSlots) => {
      const newSlots = [...prevSlots];
      let fileIndex = 0;
      for (let i = 0; i < TOTAL_IMAGE_SLOTS && fileIndex < files.length; i++) {
        if (newSlots[i] === null) {
          const file = files[fileIndex];
          if (file) {
            newSlots[i] = {
              type: "existing",
              data: file,
              previewUrl: file.filepath,
              slotId: file.id,
            };
          }
          fileIndex++;
        }
      }
      return newSlots;
    });
    setShowFileManager(false);
  }, []);

  const swapImageSlots = useCallback((fromIndex: number, toIndex: number) => {
    if (fromIndex === toIndex) return;
    if (fromIndex < 0 || fromIndex >= TOTAL_IMAGE_SLOTS) return;
    if (toIndex < 0 || toIndex >= TOTAL_IMAGE_SLOTS) return;

    setImageSlots((prevSlots) => {
      const newSlots = [...prevSlots];
      const temp = newSlots[fromIndex];
      newSlots[fromIndex] = newSlots[toIndex]!;
      newSlots[toIndex] = temp!;
      return newSlots;
    });

    setImageLinks((prevLinks) => {
      const newLinks = [...prevLinks];
      const temp = newLinks[fromIndex];
      newLinks[fromIndex] = newLinks[toIndex]!;
      newLinks[toIndex] = temp!;
      return newLinks;
    });
  }, []);

  const applyRefresh = useCallback((savedProduct: ProductWithImages) => {
    setImageSlots((prevSlots) => {
      // Instead of replacing all slots, update only what changed
      // This prevents flickering by keeping existing references when possible
      const newSlots: (ProductImageSlot | null)[] = [...prevSlots];

      // Update slots with saved images
      savedProduct.images
        .slice(0, TOTAL_IMAGE_SLOTS)
        .forEach((pImg, index) => {
          if (pImg.imageFile) {
            const existingSlot = newSlots[index];
            // Only update if the image ID changed or slot was empty
            if (!existingSlot || existingSlot.type !== "existing" || existingSlot.slotId !== pImg.imageFile.id) {
              newSlots[index] = {
                type: "existing",
                data: pImg.imageFile,
                previewUrl: pImg.imageFile.filepath,
                slotId: pImg.imageFile.id,
              };
            }
          }
        });

      // Clear slots beyond saved images count
      for (let i = savedProduct.images.length; i < TOTAL_IMAGE_SLOTS; i++) {
        if (newSlots[i]?.type === "file") {
          // Keep temporary file uploads that haven't been saved yet
          continue;
        }
        newSlots[i] = null;
      }

      return newSlots;
    });
    setImageLinks(normalizeImageLinks(savedProduct.imageLinks));
  }, []);

  const setImagesReordering = useCallback((value: boolean) => {
    isReorderingRef.current = value;
    if (!value && pendingRefreshRef.current) {
      const pending = pendingRefreshRef.current;
      pendingRefreshRef.current = null;
      applyRefresh(pending);
    }
  }, [applyRefresh]);

  // Function to refresh state from product (e.g. after save)
  const refreshFromProduct = useCallback((savedProduct: ProductWithImages) => {
    if (isReorderingRef.current) {
      pendingRefreshRef.current = savedProduct;
      if (process.env.NODE_ENV !== "production") {
        console.info("[product-images] Refresh deferred during reorder");
      }
      return;
    }
    applyRefresh(savedProduct);
  }, [applyRefresh]);

  return {
    imageSlots,
    imageLinks,
    showFileManager,
    setShowFileManager,
    handleSlotImageChange,
    handleSlotFileSelect,
    handleSlotDisconnectImage,
    handleMultiImageChange,
    handleMultiFileSelect,
    swapImageSlots,
    setImageLinkAt,
    refreshFromProduct,
    setImagesReordering,
  };
}

"use client";

import { useState, useEffect, useMemo } from "react";
import type {
  ProductWithImages,
  ProductFormData,
} from "@/features/products/types";
import { UseFormSetValue, UseFormGetValues } from "react-hook-form";
import { 
  useCatalogs, 
  useLanguages, 
  usePriceGroups, 
  useMultiCategories, 
  useMultiTags, 
  useMultiParameters 
} from "./useMetadata";

interface UseProductMetadataProps {
  product?: ProductWithImages | undefined;
  initialCatalogId?: string | undefined;
  initialCatalogIds?: string[] | undefined;
  initialCategoryIds?: string[] | undefined;
  initialTagIds?: string[] | undefined;
  setValue: UseFormSetValue<ProductFormData>;
  getValues: UseFormGetValues<ProductFormData>;
}

export function useProductMetadata({
  product,
  initialCatalogId: _initialCatalogId,
  initialCatalogIds,
  initialCategoryIds,
  initialTagIds,
  setValue,
  getValues,
}: UseProductMetadataProps) {
  const { data: catalogs = [], isLoading: catalogsLoading, error: catalogsError } = useCatalogs();
  const { data: languages = [] } = useLanguages();
  const { data: priceGroups = [] } = usePriceGroups();

  const [selectedCatalogIds, setSelectedCatalogIds] = useState<string[]>(
    () =>
      product?.catalogs?.map((entry) => entry.catalogId) ??
      initialCatalogIds ??
      []
  );

  const categoryQueries = useMultiCategories(selectedCatalogIds);
  const tagQueries = useMultiTags(selectedCatalogIds);
  const parameterQueries = useMultiParameters(selectedCatalogIds);

  const categories = useMemo(() => categoryQueries.flatMap(q => q.data ?? []), [categoryQueries]);
  const categoriesLoading = useMemo(() => categoryQueries.some(q => q.isLoading), [categoryQueries]);

  const tags = useMemo(() => tagQueries.flatMap(q => q.data ?? []), [tagQueries]);
  const tagsLoading = useMemo(() => tagQueries.some(q => q.isLoading), [tagQueries]);

  const parameters = useMemo(() => parameterQueries.flatMap(q => q.data ?? []), [parameterQueries]);
  const parametersLoading = useMemo(() => parameterQueries.some(q => q.isLoading), [parameterQueries]);

  const [selectedCategoryIds, setSelectedCategoryIds] = useState<string[]>(
    () =>
      product?.categories?.map((entry: { categoryId: string }) => entry.categoryId) ??
      initialCategoryIds ??
      []
  );

  const [selectedTagIds, setSelectedTagIds] = useState<string[]>(
    () =>
      product?.tags?.map((entry: { tagId: string }) => entry.tagId) ??
      initialTagIds ??
      []
  );

  // Auto-select default catalog for new products when none is chosen
  useEffect(() => {
    if (product) return;
    if (selectedCatalogIds.length > 0) return;
    if (catalogs.length === 0) return;
    const defaultCatalog = catalogs.find((catalog) => catalog.isDefault);
    const targetId = defaultCatalog?.id ?? catalogs[0]!.id;
    // Use setTimeout to avoid synchronous setState warning in effect
    const timer = setTimeout(() => {
      setSelectedCatalogIds([targetId]);
    }, 0);
    return () => clearTimeout(timer);
  }, [product, selectedCatalogIds.length, catalogs]);

  // Auto-set defaultPriceGroupId when catalog is selected for new products
  useEffect(() => {
    if (product) return; // Only for new products
    if (selectedCatalogIds.length === 0) return;

    // Get the first selected catalog's default price group
    const firstCatalog = catalogs.find((c) => selectedCatalogIds.includes(c.id));
    if (firstCatalog?.defaultPriceGroupId) {
      const currentDefaultPriceGroupId = getValues("defaultPriceGroupId");
      // Only set if not already set
      if (!currentDefaultPriceGroupId) {
        setValue("defaultPriceGroupId", firstCatalog.defaultPriceGroupId);
      }
    }
  }, [product, selectedCatalogIds, catalogs, getValues, setValue]);

  const filteredLanguages = useMemo(() => {
    if (selectedCatalogIds.length === 0) return languages;
    if (catalogsLoading || catalogs.length === 0) return [];

    const selectedCatalogs = catalogs.filter((catalog) => selectedCatalogIds.includes(catalog.id));
    if (selectedCatalogs.length === 0) {
      return languages;
    }

    const allowedLanguageIds = new Set(
      selectedCatalogs.flatMap((catalog) => catalog.languageIds ?? [])
    );

    if (allowedLanguageIds.size === 0) {
      return languages;
    }

    const filtered = languages.filter((language) => allowedLanguageIds.has(language.id));
    return filtered.length > 0 ? filtered : languages;
  }, [languages, catalogs, selectedCatalogIds, catalogsLoading]);

  const filteredPriceGroups = useMemo(() => {
    if (selectedCatalogIds.length === 0) return priceGroups;
    const allowedGroupIds = new Set<string>();
    const orderedGroups: (typeof priceGroups)[number][] = []; 

    // Only include price groups that are explicitly assigned to selected catalogs
    selectedCatalogIds.forEach((catalogId) => {
      const catalog = catalogs.find((c) => c.id === catalogId);
      if (catalog?.priceGroupIds) {
        catalog.priceGroupIds.forEach((pgId) => {
          if (!allowedGroupIds.has(pgId)) {
            const pg = priceGroups.find((p) => p.id === pgId);
            if (pg) {
              orderedGroups.push(pg);
              allowedGroupIds.add(pgId);
            }
          }
        });
      }
    });

    return orderedGroups.length > 0 ? orderedGroups : priceGroups;
  }, [priceGroups, catalogs, selectedCatalogIds]);

  const toggleCatalog = (catalogId: string) => {
    setSelectedCatalogIds((prev) =>
      prev.includes(catalogId)
        ? prev.filter((id) => id !== catalogId)
        : [...prev, catalogId]
    );
  };

  const toggleCategory = (categoryId: string) => {
    setSelectedCategoryIds((prev) =>
      prev.includes(categoryId)
        ? prev.filter((id) => id !== categoryId)
        : [...prev, categoryId]
    );
  };

  const toggleTag = (tagId: string) => {
    setSelectedTagIds((prev) =>
      prev.includes(tagId)
        ? prev.filter((id) => id !== tagId)
        : [...prev, tagId]
    );
  };

  return {
    catalogs,
    catalogsLoading,
    catalogsError: catalogsError ? (catalogsError).message : null,
    selectedCatalogIds,
    toggleCatalog,
    categories,
    categoriesLoading,
    selectedCategoryIds,
    toggleCategory,
    tags,
    tagsLoading,
    selectedTagIds,
    toggleTag,
    parameters,
    parametersLoading,
    filteredLanguages,
    filteredPriceGroups,
  };
}

"use client";

import { useToast } from "@/shared/ui";
import { useState } from "react";

import type { ProductWithImages } from "@/features/products/types";
import type { ProductDraft } from "@/features/products/types/drafts";

export function useProductOperations(setRefreshTrigger: React.Dispatch<React.SetStateAction<number>>) {
  const { toast } = useToast();

  // UI State
  const [isCreateOpen, setIsCreateOpen] = useState(false);
  const [initialSku, setInitialSku] = useState<string>("");
  const [editingProduct, setEditingProduct] = useState<ProductWithImages | null>(null);
  const [lastEditedId, setLastEditedId] = useState<string | null>(null);
  const [actionError, setActionError] = useState<string | null>(null);

  const handleOpenCreateModal = async () => {
    const skuInput = window.prompt("Enter a new unique SKU:");
    if (skuInput === null) return;
    const sku = skuInput.trim().toUpperCase();
    const skuPattern = /^[A-Z0-9]+$/;
    if (!sku) {
      setActionError("SKU is required.");
      return;
    }
    if (!skuPattern.test(sku)) {
      setActionError("SKU must use uppercase letters and numbers only.");
      return;
    }
    try {
      const res = await fetch(`/api/products?sku=${encodeURIComponent(sku)}`);
      if (!res.ok) {
        const payload = (await res.json()) as { error?: string };
        setActionError(payload?.error || "Failed to validate SKU");
        return;
      }
      const products = (await res.json()) as ProductWithImages[];
      if (products.some((p) => p.sku === sku)) {
        setActionError("SKU already exists.");
        return;
      }
    } catch (error) {
      console.error("Failed to validate SKU:", error);
      setActionError("Failed to validate SKU. Please try again.");
      return;
    }
    setInitialSku(sku);
    setIsCreateOpen(true);
  };

  const handleOpenCreateFromDraft = (draft: ProductDraft) => {
    const draftSku = typeof draft.sku === "string" ? draft.sku.trim().toUpperCase() : "";
    setInitialSku(draftSku);
    setIsCreateOpen(true);
  };

  const handleCreateSuccess = () => {
    setIsCreateOpen(false);
    setInitialSku("");
    setRefreshTrigger((prev) => prev + 1);
    toast("Product created successfully.", { variant: "success" });
  };

  const handleEditSuccess = () => {
    if (editingProduct) {
      setLastEditedId(editingProduct.id);
    }
    setEditingProduct(null);
    setRefreshTrigger((prev) => prev + 1);
    toast("Product updated successfully.", { variant: "success" });
  };

  const handleEditSave = (savedProduct: ProductWithImages) => {
    setLastEditedId(savedProduct.id);
    setRefreshTrigger((prev) => prev + 1);
  };

  return {
    isCreateOpen,
    setIsCreateOpen,
    initialSku,
    setInitialSku,
    editingProduct,
    setEditingProduct,
    lastEditedId,
    actionError,
    setActionError,
    handleOpenCreateModal,
    handleOpenCreateFromDraft,
    handleCreateSuccess,
    handleEditSuccess,
    handleEditSave,
  };
}

"use client";

import { useMutation, useQueryClient } from "@tanstack/react-query";
import type { ProductWithImages } from "@/features/products/types";
import type { DeleteResponse } from "@/shared/types/api";
import { delay } from "@/shared/utils";

interface UpdateProductPayload {
  id: string;
  data: Partial<ProductWithImages>;
}

export function useCreateProduct() {
  const queryClient = useQueryClient();

  return useMutation({
    onSuccess: async () => {
      // Small delay to ensure DB consistency before refetch
      await delay(500);
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ["products"] }),
        queryClient.invalidateQueries({ queryKey: ["products-count"] }),
      ]);
    },
  });
}

export function useUpdateProduct() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ id, data }: UpdateProductPayload) => {
      const response = await fetch(`/api/products/${id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      });
      if (!response.ok) throw new Error("Failed to update product");
      return (await response.json()) as ProductWithImages;
    },
    onSuccess: async () => {
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ["products"] }),
        queryClient.invalidateQueries({ queryKey: ["products-count"] }),
      ]);
    },
  });
}

export function useDeleteProduct() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (id: string) => {
      const response = await fetch(`/api/products/${id}`, {
        method: "DELETE",
      });
      if (!response.ok) throw new Error("Failed to delete product");
      return (await response.json()) as DeleteResponse;
    },
    onSuccess: async () => {
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ["products"] }),
        queryClient.invalidateQueries({ queryKey: ["products-count"] }),
      ]);
    },
  });
}

"use client";

import { useQuery, useQueries, useQueryClient } from "@tanstack/react-query";
import { getProducts, countProducts } from "@/features/products/api";
import { useCallback } from "react";

interface UseProductsFilters {
  search?: string | undefined;
  sku?: string | undefined;
  minPrice?: number | undefined;
  maxPrice?: number | undefined;
  startDate?: string | undefined;
  endDate?: string | undefined;
  page?: number | undefined;
  pageSize?: number | undefined;
  catalogId?: string | undefined;
  searchLanguage?: string | undefined;
}

interface UseProductsOptions {
  enabled?: boolean;
}

export function useProducts(
  filters: UseProductsFilters,
  options: UseProductsOptions = {}
) {
  const { enabled = true } = options;

  return useQuery({
    queryKey: ["products", filters],
    queryFn: () => getProducts(filters),
    enabled,
  });
}

export function useProductsCount(
  filters: UseProductsFilters,
  options: UseProductsOptions = {}
) {
  const { enabled = true } = options;

  return useQuery({
    queryKey: ["products-count", filters],
    queryFn: () => countProducts(filters),
    enabled,
  });
}

export function useProductsWithCount(
  filters: UseProductsFilters,
  options: UseProductsOptions = {}
) {
  const { enabled = true } = options;
  const queryClient = useQueryClient();

  const results = useQueries({
    queries: [
      {
        queryKey: ["products", filters],
        queryFn: () => getProducts(filters),
        enabled,
      },
      {
        queryKey: ["products-count", filters],
        queryFn: () => countProducts(filters),
        enabled,
      },
    ],
  });

  const [productsQuery, countQuery] = results;

  const refetch = useCallback(async () => {
    await Promise.all([
      queryClient.refetchQueries({ queryKey: ["products"] }),
      queryClient.refetchQueries({ queryKey: ["products-count"] }),
    ]);
  }, [queryClient]);

  return {
    products: productsQuery.data ?? [],
    total: countQuery.data ?? 0,
    isLoading: productsQuery.isPending || countQuery.isPending,
    isFetching: productsQuery.isFetching || countQuery.isFetching,
    error: productsQuery.error || countQuery.error,
    refetch,
  };
}

"use client";

import { useCallback } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import type { ProductListPreferences } from "@/features/products/types/products-ui";

const DEFAULT_PREFERENCES: ProductListPreferences = {
  nameLocale: "name_en",
  catalogFilter: "all",
  currencyCode: "PLN",
  pageSize: 12,
};

type PreferencesApiResponse = {
  productListNameLocale?: string;
  productListCatalogFilter?: string;
  productListCurrencyCode?: string | null;
  productListPageSize?: number;
};

const userPreferencesQueryKey = ["user-preferences", "product-list"] as const;

async function fetchUserPreferences(): Promise<ProductListPreferences> {
  const res = await fetch("/api/user/preferences");
  if (!res.ok) {
    throw new Error("Failed to load preferences");
  }
  const data = (await res.json()) as PreferencesApiResponse;
  return {
    nameLocale: (data.productListNameLocale || "name_en") as "name_en" | "name_pl" | "name_de",
    catalogFilter: data.productListCatalogFilter || "all",
    currencyCode: data.productListCurrencyCode ?? "PLN",
    pageSize: data.productListPageSize || 12,
  };
}

async function updateUserPreference(key: keyof ProductListPreferences, value: unknown): Promise<void> {
  const apiKey = `productList${key.charAt(0).toUpperCase()}${key.slice(1)}`;
  const res = await fetch("/api/user/preferences", {
    method: "PATCH",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ [apiKey]: value }),
  });
  if (!res.ok) {
    throw new Error(`Failed to update preference: ${key}`);
  }
}

function getLocalStorageFallback(): Partial<ProductListPreferences> {
  if (typeof window === "undefined") return {};

  const storedLocale = window.localStorage.getItem("productListNameLocale");
  const storedCatalogFilter = window.localStorage.getItem("productListCatalogFilter");
  const storedCurrencyCode = window.localStorage.getItem("productListCurrencyCode");
  const storedPageSize = window.localStorage.getItem("productListPageSize");

  return {
    ...(storedLocale === "name_en" || storedLocale === "name_pl" || storedLocale === "name_de"
      ? { nameLocale: storedLocale }
      : {}),
    ...(storedCatalogFilter ? { catalogFilter: storedCatalogFilter } : {}),
    ...(storedCurrencyCode ? { currencyCode: storedCurrencyCode } : {}),
    ...(storedPageSize && !Number.isNaN(Number(storedPageSize))
      ? { pageSize: Number(storedPageSize) }
      : {}),
  };
}

function updateLocalStorage(key: keyof ProductListPreferences, value: unknown): void {
  if (typeof window === "undefined") return;

  const storageKey = `productList${key.charAt(0).toUpperCase()}${key.slice(1)}`;
  window.localStorage.setItem(storageKey, String(value));
}

export function useUserPreferences() {
  const queryClient = useQueryClient();

  const preferencesQuery = useQuery({
    queryKey: userPreferencesQueryKey,
    queryFn: async () => {
      try {
        return await fetchUserPreferences();
      } catch (error) {
        console.error("Failed to load user preferences:", error);
        // Fall back to localStorage if database fails
        const fallback = getLocalStorageFallback();
        return { ...DEFAULT_PREFERENCES, ...fallback };
      }
    },
    staleTime: 1000 * 60 * 5, // 5 minutes
  });

  const updatePreferenceMutation = useMutation({
    mutationFn: ({ key, value }: { key: keyof ProductListPreferences; value: unknown }) =>
      updateUserPreference(key, value),
    onMutate: async ({ key, value }) => {
      // Cancel outgoing refetches
      await queryClient.cancelQueries({ queryKey: userPreferencesQueryKey });

      // Snapshot previous value
      const previousPreferences = queryClient.getQueryData<ProductListPreferences>(userPreferencesQueryKey);

      // Optimistically update
      queryClient.setQueryData<ProductListPreferences>(userPreferencesQueryKey, (old) => ({
        ...DEFAULT_PREFERENCES,
        ...old,
        [key]: value,
      }));

      // Also update localStorage as fallback
      updateLocalStorage(key, value);

      return { previousPreferences };
    },
    onError: (error, { key }) => {
      console.warn(`Preference update failed for ${key}.`, error);
      // Keep the optimistic update - don't rollback so UI stays responsive
    },
    onSettled: () => {
      // Optionally refetch to ensure consistency
      void queryClient.invalidateQueries({ queryKey: userPreferencesQueryKey });
    },
  });

  const preferences = preferencesQuery.data ?? DEFAULT_PREFERENCES;

  const setNameLocale = useCallback((locale: "name_en" | "name_pl" | "name_de") => {
    updatePreferenceMutation.mutate({ key: "nameLocale", value: locale });
  }, [updatePreferenceMutation]);

  const setCatalogFilter = useCallback((filter: string) => {
    updatePreferenceMutation.mutate({ key: "catalogFilter", value: filter });
  }, [updatePreferenceMutation]);

  const setCurrencyCode = useCallback((code: string | null) => {
    updatePreferenceMutation.mutate({ key: "currencyCode", value: code });
  }, [updatePreferenceMutation]);

  const setPageSize = useCallback((size: number) => {
    updatePreferenceMutation.mutate({ key: "pageSize", value: size });
  }, [updatePreferenceMutation]);

  return {
    preferences,
    loading: preferencesQuery.isLoading,
    error: preferencesQuery.error ? preferencesQuery.error.message : null,
    setNameLocale,
    setCatalogFilter,
    setCurrencyCode,
    setPageSize,
  };
}

"use client";
import { ProfilerOnRenderCallback, useCallback, useEffect, useMemo, useState } from "react";

import dynamic from "next/dynamic";
