"use client";

import { Button, Input, Label } from "@/shared/ui";
import { Upload, Loader2, Plus, X } from "lucide-react";
import { useState, useRef, useCallback } from "react";
import { validate3DFile, SUPPORTED_3D_FORMATS } from "../utils/validateAsset3d";
import { uploadAsset3DFile } from "../api";
import type { Asset3DRecord } from "../types";
import { cn } from "@/shared/utils";

export interface Asset3DUploaderProps {
  onUpload: (asset: Asset3DRecord) => void;
  onCancel?: () => void;
  existingCategories?: string[];
  existingTags?: string[];
  className?: string;
}

export function Asset3DUploader({
  onUpload,
  onCancel,
  existingCategories = [],
  existingTags = [],
  className,
}: Asset3DUploaderProps) {
  const [file, setFile] = useState<File | null>(null);
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [category, setCategory] = useState("");
  const [tags, setTags] = useState<string[]>([]);
  const [newTag, setNewTag] = useState("");
  const [isPublic, setIsPublic] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isDragOver, setIsDragOver] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileSelect = useCallback((selectedFile: File) => {
    const validation = validate3DFile(selectedFile);
    if (!validation.valid) {
      setError(validation.error ?? "Invalid file");
      return;
    }
    setFile(selectedFile);
    setError(null);
    // Auto-fill name from filename
    if (!name) {
      const cleanName = selectedFile.name
        .replace(/\.[^/.]+$/, "")
        .replace(/[-_]/g, " ")
        .replace(/\s+/g, " ")
        .trim();
      setName(cleanName);
    }
  }, [name]);

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault();
      setIsDragOver(false);
      const droppedFile = e.dataTransfer.files[0];
      if (droppedFile) handleFileSelect(droppedFile);
    },
    [handleFileSelect]
  );

  const handleAddTag = () => {
    const trimmed = newTag.trim().toLowerCase();
    if (trimmed && !tags.includes(trimmed)) {
      setTags([...tags, trimmed]);
      setNewTag("");
    }
  };

  const handleRemoveTag = (tag: string) => {
    setTags(tags.filter((t) => t !== tag));
  };

  const handleUpload = async () => {
    if (!file) return;

    setIsUploading(true);
    setError(null);

    try {
      const uploaded = await uploadAsset3DFile(file, {
        ...(name.trim() && { name: name.trim() }),
        ...(description.trim() && { description: description.trim() }),
        ...(category.trim() && { category: category.trim() }),
        ...(tags.length > 0 && { tags }),
        isPublic,
      });
      onUpload(uploaded);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Upload failed");
    } finally {
      setIsUploading(false);
    }
  };

  const formatFileSize = (bytes: number) => {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / 1024 / 1024).toFixed(2)} MB`;
  };

  return (
    <div className={className}>
      {/* File Drop Zone */}
      {!file ? (
        <div
          className={cn(
            "relative flex h-32 cursor-pointer items-center justify-center rounded-lg border-2 border-dashed transition-colors",
            isDragOver
              ? "border-blue-500 bg-blue-500/10"
              : "border-gray-600 bg-gray-800/50 hover:border-blue-500 hover:bg-gray-800"
          )}
          onDragOver={(e) => {
            e.preventDefault();
            setIsDragOver(true);
          }}
          onDragLeave={(e) => {
            e.preventDefault();
            setIsDragOver(false);
          }}
          onDrop={handleDrop}
          onClick={() => fileInputRef.current?.click()}
        >
          <div className="flex flex-col items-center gap-2">
            <Upload className="h-8 w-8 text-gray-500" />
            <span className="text-sm text-gray-400">
              Drop .glb or .gltf file here
            </span>
            <span className="text-xs text-gray-500">or click to browse</span>
          </div>
          <input
            ref={fileInputRef}
            type="file"
            accept=".glb,.gltf"
            className="hidden"
            onChange={(e) => {
              const selectedFile = e.target.files?.[0];
              if (selectedFile) handleFileSelect(selectedFile);
              e.target.value = "";
            }}
          />
        </div>
      ) : (
        <div className="space-y-4">
          {/* Selected File */}
          <div className="flex items-center justify-between p-3 bg-gray-800 rounded-lg border border-gray-700">
            <div className="flex items-center gap-3">
              <div className="h-10 w-10 bg-blue-500/20 rounded flex items-center justify-center">
                <Upload className="h-5 w-5 text-blue-400" />
              </div>
              <div>
                <p className="text-sm font-medium text-white">{file.name}</p>
                <p className="text-xs text-gray-400">{formatFileSize(file.size)}</p>
              </div>
            </div>
            <Button
              variant="ghost"
              size="icon"
              onClick={() => setFile(null)}
              disabled={isUploading}
            >
              <X className="h-4 w-4" />
            </Button>
          </div>

          {/* Name */}
          <div>
            <Label htmlFor="upload-name" className="text-sm text-gray-300">
              Name
            </Label>
            <Input
              id="upload-name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Enter asset name..."
              className="mt-1 bg-gray-800 border-gray-700"
              disabled={isUploading}
            />
          </div>

          {/* Description */}
          <div>
            <Label htmlFor="upload-description" className="text-sm text-gray-300">
              Description
            </Label>
            <textarea
              id="upload-description"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Enter description..."
              rows={2}
              className="mt-1 w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-md text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-blue-500 resize-none text-sm"
              disabled={isUploading}
            />
          </div>

          {/* Category */}
          <div>
            <Label htmlFor="upload-category" className="text-sm text-gray-300">
              Category
            </Label>
            <Input
              id="upload-category"
              value={category}
              onChange={(e) => setCategory(e.target.value)}
              placeholder="Enter category..."
              list="upload-categories-list"
              className="mt-1 bg-gray-800 border-gray-700"
              disabled={isUploading}
            />
            <datalist id="upload-categories-list">
              {existingCategories.map((cat) => (
                <option key={cat} value={cat} />
              ))}
            </datalist>
          </div>

          {/* Tags */}
          <div>
            <Label className="text-sm text-gray-300">Tags</Label>
            <div className="mt-1 flex gap-2">
              <Input
                value={newTag}
                onChange={(e) => setNewTag(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter") {
                    e.preventDefault();
                    handleAddTag();
                  }
                }}
                placeholder="Add tag..."
                list="upload-tags-list"
                className="bg-gray-800 border-gray-700 flex-1"
                disabled={isUploading}
              />
              <datalist id="upload-tags-list">
                {existingTags
                  .filter((t) => !tags.includes(t))
                  .map((tag) => (
                    <option key={tag} value={tag} />
                  ))}
              </datalist>
              <Button
                type="button"
                variant="secondary"
                size="icon"
                onClick={handleAddTag}
                disabled={isUploading}
              >
                <Plus className="h-4 w-4" />
              </Button>
            </div>
            {tags.length > 0 && (
              <div className="flex flex-wrap gap-1 mt-2">
                {tags.map((tag) => (
                  <span
                    key={tag}
                    className="inline-flex items-center gap-1 px-2 py-1 bg-gray-700 text-gray-300 rounded text-xs"
                  >
                    {tag}
                    <button
                      type="button"
                      onClick={() => handleRemoveTag(tag)}
                      className="text-gray-500 hover:text-red-400"
                      disabled={isUploading}
                    >
                      <X className="h-3 w-3" />
                    </button>
                  </span>
                ))}
              </div>
            )}
          </div>

          {/* Visibility */}
          <label className="flex items-center gap-3 cursor-pointer">
            <input
              type="checkbox"
              checked={isPublic}
              onChange={(e) => setIsPublic(e.target.checked)}
              className="rounded border-gray-600 bg-gray-800 text-blue-500 focus:ring-blue-500"
              disabled={isUploading}
            />
            <span className="text-sm text-gray-300">Make publicly visible</span>
          </label>
        </div>
      )}

      {/* Error */}
      {error && (
        <p className="mt-2 text-sm text-red-400">{error}</p>
      )}

      {/* Format Info */}
      <p className="mt-2 text-xs text-gray-500">
        Supported formats: {Object.keys(SUPPORTED_3D_FORMATS).join(", ")}. Max 100MB.
      </p>

      {/* Actions */}
      {file && (
        <div className="flex justify-end gap-2 mt-4">
          {onCancel && (
            <Button variant="ghost" onClick={onCancel} disabled={isUploading}>
              Cancel
            </Button>
          )}
          <Button onClick={() => void handleUpload()} disabled={isUploading}>
            {isUploading ? (
              <>
                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                Uploading...
              </>
            ) : (
              <>
                <Upload className="h-4 w-4 mr-2" />
                Upload Asset
              </>
            )}
          </Button>
        </div>
      )}
    </div>
  );
}

